import React, { useState, useEffect, useCallback, useMemo } from 'react';
import { v4 as uuidv4 } from 'uuid';
import { 
  Download, Upload, FileJson, Palette, PanelLeft, Edit3, Columns, Eye, X, FileText, Save
} from 'lucide-react';
import { Sidebar } from './components/Sidebar';
import { Editor } from './components/Editor';
import { FileNode, NodeType, AppTheme } from './types';
import { initialNodes } from './initialData';

const themes: Record<string, AppTheme> = {
  dark: { name: 'Dark', bgMain: '#030712', bgSidebar: '#111827', textMain: '#f3f4f6', textMuted: '#9ca3af', border: '#1f2937', accent: '#3b82f6', hover: 'rgba(255, 255, 255, 0.05)' },
  light: { name: 'Light', bgMain: '#ffffff', bgSidebar: '#f3f4f6', textMain: '#111827', textMuted: '#6b7280', border: '#e5e7eb', accent: '#3b82f6', hover: 'rgba(0, 0, 0, 0.05)' },
  navy: { name: 'Navy', bgMain: '#0a192f', bgSidebar: '#112240', textMain: '#ccd6f6', textMuted: '#8892b0', border: '#233554', accent: '#64ffda', hover: 'rgba(100, 255, 218, 0.1)' },
  dracula: { name: 'Dracula', bgMain: '#282a36', bgSidebar: '#21222c', textMain: '#f8f8f2', textMuted: '#6272a4', border: '#44475a', accent: '#ff79c6', hover: 'rgba(255, 255, 255, 0.1)' }
};

export default function App() {
  const [nodes, setNodes] = useState<FileNode[]>(() => {
    const saved = localStorage.getItem('mathsci-fs');
    return saved ? JSON.parse(saved) : initialNodes;
  });
  const [activeFileId, setActiveFileId] = useState<string | null>('file-intro');
  const [expandedFolders, setExpandedFolders] = useState<Set<string>>(new Set(['folder-welcome', 'folder-docs']));
  const [showSettings, setShowSettings] = useState(false);
  const [isSidebarOpen, setIsSidebarOpen] = useState(true);
  const [editorView, setEditorView] = useState<'split' | 'editor' | 'preview'>('split');
  const [currentTheme, setCurrentTheme] = useState<AppTheme>(() => {
    const saved = localStorage.getItem('mathsci-theme');
    return saved ? JSON.parse(saved) : themes.dark;
  });

  useEffect(() => {
    const root = document.documentElement;
    root.style.setProperty('--bg-main', currentTheme.bgMain);
    root.style.setProperty('--bg-sidebar', currentTheme.bgSidebar);
    root.style.setProperty('--bg-toolbar', currentTheme.bgSidebar);
    root.style.setProperty('--text-main', currentTheme.textMain);
    root.style.setProperty('--text-muted', currentTheme.textMuted);
    root.style.setProperty('--border-color', currentTheme.border);
    root.style.setProperty('--accent-color', currentTheme.accent);
    root.style.setProperty('--hover-bg', currentTheme.hover);
    localStorage.setItem('mathsci-theme', JSON.stringify(currentTheme));
  }, [currentTheme]);

  useEffect(() => {
    // Throttled persistence for 1000+ files
    const handler = setTimeout(() => {
      localStorage.setItem('mathsci-fs', JSON.stringify(nodes));
    }, 1000);
    return () => clearTimeout(handler);
  }, [nodes]);

  const deleteRecursive = useCallback((targetId: string, currentNodes: FileNode[]): string[] => {
    const idsToDelete: string[] = [targetId];
    const queue = [targetId];
    while (queue.length > 0) {
      const parentId = queue.shift();
      const children = currentNodes.filter(n => n.parentId === parentId);
      children.forEach(child => {
        idsToDelete.push(child.id);
        queue.push(child.id);
      });
    }
    return idsToDelete;
  }, []);

  const handleExportWorkspace = (format: 'json' | 'md') => {
    let content = '';
    let mimeType = '';
    let fileName = '';

    if (format === 'json') {
      content = JSON.stringify({ version: 1, nodes }, null, 2);
      mimeType = 'application/json';
      fileName = `workspace_backup_${new Date().toISOString().split('T')[0]}.json`;
    } else {
      // Optimized Bundled Markdown Export for 1000+ files
      const nodeMap = new Map<string | null, FileNode[]>();
      nodes.forEach(n => {
        const pId = n.parentId;
        if (!nodeMap.has(pId)) nodeMap.set(pId, []);
        nodeMap.get(pId)!.push(n);
      });

      const buildMarkdown = (parentId: string | null, depth: number): string => {
        let md = '';
        const items = nodeMap.get(parentId) || [];
        // Folders first, then alphabetically
        items.sort((a, b) => {
          if (a.type !== b.type) return a.type === NodeType.FOLDER ? -1 : 1;
          return a.name.localeCompare(b.name);
        });

        items.forEach(item => {
          const indent = '#'.repeat(Math.min(depth + 1, 6));
          if (item.type === NodeType.FOLDER) {
            md += `${indent} Folder: ${item.name}\n\n`;
            md += buildMarkdown(item.id, depth + 1);
          } else {
            md += `${indent} File: ${item.name}\n\n${item.content}\n\n---\n\n`;
          }
        });
        return md;
      };

      content = `# Workspace Export - ${new Date().toLocaleString()}\n\n${buildMarkdown(null, 0)}`;
      mimeType = 'text/markdown';
      fileName = `workspace_bundle_${nodes.length}_files.md`;
    }

    const blob = new Blob([content], { type: mimeType });
    const url = URL.createObjectURL(blob);
    const link = document.createElement('a');
    link.href = url;
    link.download = fileName;
    link.click();
    URL.revokeObjectURL(url);
  };

  const handleImportWorkspace = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;
    const reader = new FileReader();
    reader.onload = (event) => {
      try {
        const data = JSON.parse(event.target?.result as string);
        if (data.nodes && Array.isArray(data.nodes)) {
          setNodes(data.nodes);
          if (data.nodes.length > 0) {
            const firstFile = data.nodes.find((n: FileNode) => n.type === NodeType.FILE);
            setActiveFileId(firstFile ? firstFile.id : data.nodes[0].id);
          }
        }
      } catch (err) {
        alert("Failed to parse import file. Ensure it is a valid Workspace JSON.");
      }
    };
    reader.readAsText(file);
  };

  const activeFile = useMemo(() => nodes.find(n => n.id === activeFileId), [nodes, activeFileId]);

  return (
    <div className="app-container" style={{ background: 'var(--bg-main)' }}>
      <div className="sidebar-wrapper" style={{ width: isSidebarOpen ? '280px' : '0' }}>
         <Sidebar 
            nodes={nodes}
            activeFileId={activeFileId}
            expandedFolders={expandedFolders}
            onFileSelect={setActiveFileId}
            onToggleFolder={(id) => setExpandedFolders(prev => {
                const next = new Set(prev);
                if (next.has(id)) next.delete(id); else next.add(id);
                return next;
            })}
            onAddFile={(parentId) => {
                const id = uuidv4();
                const newNode: FileNode = { id, parentId, name: 'New File.md', type: NodeType.FILE, content: '', createdAt: Date.now() };
                setNodes(prev => [...prev, newNode]);
                setActiveFileId(id);
                if (parentId) setExpandedFolders(prev => new Set(prev).add(parentId));
            }}
            onAddFolder={(parentId) => {
                const id = uuidv4();
                setNodes(prev => [...prev, { id, parentId, name: 'New Folder', type: NodeType.FOLDER, content: '', createdAt: Date.now() }]);
                if (parentId) setExpandedFolders(prev => new Set(prev).add(parentId));
            }}
            onDeleteNode={(id) => {
                const idsToRemove = deleteRecursive(id, nodes);
                setNodes(prev => prev.filter(n => !idsToRemove.includes(n.id)));
                if (activeFileId && idsToRemove.includes(activeFileId)) setActiveFileId(null);
            }}
            onRenameNode={(id, name) => setNodes(prev => prev.map(n => n.id === id ? { ...n, name } : n))}
            onMoveNode={(id, parentId) => setNodes(prev => prev.map(n => n.id === id ? { ...n, parentId } : n))}
         />
      </div>

      <div className="main-content" style={{ flex: 1, display: 'flex', flexDirection: 'column', overflow: 'hidden' }}>
        <div className="toolbar">
            <div style={{ display: 'flex', alignItems: 'center', gap: '0.75rem' }}>
                <button onClick={() => setIsSidebarOpen(!isSidebarOpen)} className="btn-icon" title="Toggle Sidebar"><PanelLeft size={18} /></button>
                <h1 className="app-title" style={{ fontSize: '1rem' }}>MathSci <span style={{ opacity: 0.4, fontWeight: 'normal', fontSize: '0.75rem' }}>v2.0</span></h1>
            </div>
            <div style={{ display: 'flex', alignItems: 'center', gap: '0.5rem' }}>
                <button onClick={() => handleExportWorkspace('md')} className="btn" title="Bundle all files into one Markdown"><FileText size={14} /> Export Bundle</button>
                <button onClick={() => handleExportWorkspace('json')} className="btn" title="Backup Workspace JSON"><Download size={14} /> Backup</button>
                <label className="btn" style={{ cursor: 'pointer' }}>
                  <Upload size={14} /> Restore
                  <input type="file" onChange={handleImportWorkspace} style={{ display: 'none' }} accept=".json" />
                </label>
                <div className="divider"></div>
                <button onClick={() => setShowSettings(true)} className="btn"><Palette size={14} /> Theme</button>
                <div style={{ display: 'flex', background: 'var(--bg-main)', border: '1px solid var(--border-color)', borderRadius: '6px', padding: '2px', gap: '2px' }}>
                   <button onClick={() => setEditorView('editor')} className="btn-icon" style={{ color: editorView === 'editor' ? 'var(--accent-color)' : 'var(--text-muted)' }}><Edit3 size={16} /></button>
                   <button onClick={() => setEditorView('split')} className="btn-icon" style={{ color: editorView === 'split' ? 'var(--accent-color)' : 'var(--text-muted)' }}><Columns size={16} /></button>
                   <button onClick={() => setEditorView('preview')} className="btn-icon" style={{ color: editorView === 'preview' ? 'var(--accent-color)' : 'var(--text-muted)' }}><Eye size={16} /></button>
                </div>
            </div>
        </div>

        <div style={{ flex: 1, overflow: 'hidden' }}>
            {activeFile ? (
                <Editor 
                  content={activeFile.content} 
                  fileName={activeFile.name}
                  allNodes={nodes}
                  viewMode={editorView}
                  onChange={(content) => setNodes(prev => prev.map(n => n.id === activeFileId ? { ...n, content } : n))} 
                />
            ) : (
              <div style={{ height: '100%', display: 'flex', alignItems: 'center', justifyContent: 'center', color: 'var(--text-muted)', flexDirection: 'column', gap: '1.5rem', textAlign: 'center' }}>
                  <div style={{ position: 'relative' }}>
                    <FileText size={64} style={{ opacity: 0.1 }} />
                    <Plus size={24} style={{ position: 'absolute', bottom: -5, right: -5, opacity: 0.3 }} />
                  </div>
                  <div>
                    <p style={{ fontSize: '1.1rem', marginBottom: '0.5rem' }}>Workspace ready</p>
                    <p style={{ fontSize: '0.85rem', opacity: 0.6 }}>{nodes.length} items in file system. Select a file to edit.</p>
                  </div>
                  <button onClick={() => {
                     const id = uuidv4();
                     setNodes(prev => [...prev, { id, parentId: null, name: 'Untitled.md', type: NodeType.FILE, content: '', createdAt: Date.now() }]);
                     setActiveFileId(id);
                  }} className="btn btn-primary" style={{ padding: '0.5rem 1.5rem' }}>Create New File</button>
              </div>
            )}
        </div>
      </div>

      {showSettings && (
          <div className="modal-overlay" onClick={() => setShowSettings(false)}>
              <div className="modal" onClick={e => e.stopPropagation()} style={{ maxWidth: '420px', background: '#0a0f1d', color: '#f8fafc', border: '1px solid #1e293b', padding: '1.5rem' }}>
                  <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: '2rem' }}>
                      <div style={{ display: 'flex', alignItems: 'center', gap: '0.75rem' }}>
                        <Palette size={20} color="#3b82f6" />
                        <span style={{ fontSize: '1.125rem', fontWeight: 600 }}>Theme Settings</span>
                      </div>
                      <button onClick={() => setShowSettings(false)} className="btn-icon"><X size={20}/></button>
                  </div>
                  <div style={{ marginBottom: '2rem' }}>
                    <label style={{ fontSize: '0.85rem', color: '#94a3b8', marginBottom: '1rem', display: 'block' }}>Select Look & Feel</label>
                    <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: '0.75rem' }}>
                        {Object.entries(themes).map(([k, t]) => (
                            <button key={k} onClick={() => setCurrentTheme(t)} style={{ padding: '0.75rem', borderRadius: '8px', background: t.bgMain, color: t.textMain, border: `1px solid ${currentTheme.name === t.name ? 'var(--accent-color)' : '#1e293b'}`, cursor: 'pointer', display: 'flex', alignItems: 'center', gap: '0.5rem', fontSize: '0.9rem', transition: 'all 0.2s' }}>
                                <div style={{ width: 12, height: 12, borderRadius: '50%', background: t.accent }} />
                                {t.name}
                            </button>
                        ))}
                    </div>
                  </div>
                  <button onClick={() => setShowSettings(false)} className="btn-primary" style={{ width: '100%', padding: '0.75rem', borderRadius: '8px', border: 'none', fontWeight: 600, cursor: 'pointer' }}>Apply Changes</button>
              </div>
          </div>
      )}
    </div>
  );
}

import React, { useState, useRef, useMemo, useCallback, useEffect } from 'react';
import ReactMarkdown from 'react-markdown';
import remarkGfm from 'remark-gfm';
import remarkMath from 'remark-math';
import rehypeRaw from 'rehype-raw';
import rehypeHighlight from 'rehype-highlight';
import { MermaidDiagram } from './engines/MermaidDiagram';
import { SmilesDiagram } from './engines/SmilesDiagram';
import { InteractivePlot } from './engines/InteractivePlot';
import { PhysicsSimulation } from './engines/PhysicsSimulation';
import { EditorToolbar } from './editor/EditorToolbar';
import { FileNode } from '../types';

interface EditorProps {
  content: string;
  fileName: string;
  allNodes: FileNode[];
  onChange: (content: string) => void;
  readOnly?: boolean;
  viewMode?: 'split' | 'editor' | 'preview';
}

const safeJsonParse = (str: string) => {
  try {
    return JSON.parse(str);
  } catch (e) {
    try {
      const cleaned = str
        .replace(/\\n/g, "\\n")
        .replace(/\\'/g, "\\'")
        .replace(/\\"/g, '\\"')
        .replace(/\\&/g, "\\&")
        .replace(/\\r/g, "\\r")
        .replace(/\\t/g, "\\t")
        .replace(/\\b/g, "\\b")
        .replace(/\\f/g, "\\f");
      return JSON.parse(cleaned);
    } catch (e2) {
      throw e2;
    }
  }
};

export const Editor: React.FC<EditorProps> = ({ content, fileName, allNodes, onChange, readOnly = false, viewMode = 'split' }) => {
  const textareaRef = useRef<HTMLTextAreaElement>(null);
  const contentRef = useRef(content);
  const [localContent, setLocalContent] = useState(content);

  const ideRegistry = useRef<Record<string, string>>({});
  const persistTimer = useRef<number | null>(null);

  useEffect(() => {
    if (content !== contentRef.current) {
      contentRef.current = content;
      setLocalContent(content);
      ideRegistry.current = {};
    }
  }, [content, fileName]);

  const persistToMarkdown = useCallback(() => {
    const currentDoc = contentRef.current;
    const registry = ideRegistry.current;

    const newDoc = currentDoc.replace(/```ide\s*([\s\S]*?)\s*```/g, (match, inner) => {
      try {
        const parsed = safeJsonParse(inner.trim());
        const id = parsed.internal_block_id;
        if (id && registry[id]) {
          return `\`\`\`ide\n${registry[id]}\n\`\`\``;
        }
        return match;
      } catch (e) {
        return match;
      }
    });

    if (newDoc !== currentDoc) {
      contentRef.current = newDoc;
      setLocalContent(newDoc);
      onChange(newDoc);
    }
  }, [onChange]);

  const handleTextareaChange = (val: string) => {
    setLocalContent(val);
    contentRef.current = val;
    if (persistTimer.current) window.clearTimeout(persistTimer.current);
    persistTimer.current = window.setTimeout(persistToMarkdown, 1000);
  };

  const insertFormat = (prefix: string, suffix: string = '', block: boolean = false) => {
    if (!textareaRef.current) return;
    const { selectionStart: start, selectionEnd: end, value } = textareaRef.current;
    const selectedText = value.substring(start, end);
    let insertion = prefix + selectedText + suffix;
    if (block && value[start - 1] !== '\n' && start !== 0) insertion = '\n' + insertion;
    const newVal = value.substring(0, start) + insertion + value.substring(end);
    handleTextareaChange(newVal);
  };

  const handleIDEUpdate = useCallback((targetId: string, newConfigStr: string) => {
    ideRegistry.current[targetId] = newConfigStr;
    const currentDoc = contentRef.current;
    const updatedDoc = currentDoc.replace(/```ide\s*([\s\S]*?)\s*```/g, (match, inner) => {
      try {
        const parsed = safeJsonParse(inner.trim());
        if (parsed.internal_block_id === targetId) {
          return `\`\`\`ide\n${newConfigStr}\n\`\`\``;
        }
        return match;
      } catch (e) {
        return match;
      }
    });

    if (updatedDoc !== currentDoc) {
      contentRef.current = updatedDoc;
      setLocalContent(updatedDoc);
      if (persistTimer.current) window.clearTimeout(persistTimer.current);
      persistTimer.current = window.setTimeout(() => {
        onChange(updatedDoc);
      }, 500);
    }
  }, [onChange]);

  const markdownComponents = useMemo(() => ({
    code({node, inline, className, children, ...props}: any) {
        const match = /language-([\w-]+)/.exec(className || '');
        const rawCodeContent = String(children).replace(/\n$/, '');
        if (!inline && match?.[1] === 'ide') {
          try { 
            const parsed = safeJsonParse(rawCodeContent.trim());
            const blockId = parsed.internal_block_id;
            if (!blockId) return <pre>{rawCodeContent}</pre>;
            const configToUse = ideRegistry.current[blockId] || rawCodeContent;

            // Fix: CodeEditorEngine is not defined, using a placeholder for now
            return (
              <div style={{ border: '1px solid var(--border-color)', padding: '1rem', background: 'var(--bg-sidebar)', borderRadius: '8px' }}>
                <p style={{ color: 'var(--accent-color)', margin: '0 0 0.5rem 0', fontWeight: 'bold' }}>IDE Block: {blockId}</p>
                <pre style={{ margin: 0, fontSize: '11px', overflow: 'auto' }}>{configToUse}</pre>
                <p style={{ fontSize: '10px', marginTop: '8px', opacity: 0.6 }}>Interactive editor component not found.</p>
              </div>
            );
          } catch(e: any) { 
            return (
              <div style={{ border: '1px solid #dc2626', padding: '1rem', background: '#fef2f2', borderRadius: '8px' }}>
                <p style={{ color: '#dc2626', margin: '0 0 0.5rem 0', fontWeight: 'bold' }}>JSON Syntax Error in IDE Block</p>
                <pre style={{ margin: 0, fontSize: '11px', overflow: 'auto' }}>{e.message}</pre>
              </div>
            );
          }
        }
        if (!inline) {
          switch (match?.[1]) {
            case 'mermaid': return <MermaidDiagram chart={rawCodeContent} />;
            case 'smiles': return <SmilesDiagram smiles={rawCodeContent} />;
            case 'plot': return <InteractivePlot configStr={rawCodeContent} />;
            case 'physics': return <PhysicsSimulation configStr={rawCodeContent} />;
          }
        }
        return <code className={className} {...props}>{children}</code>;
    },
    div: ({node, className, ...props}: any) => className?.includes('math-display') ? <div dangerouslySetInnerHTML={{__html: window.katex?.renderToString(props['data-math'], {displayMode:true, throwOnError:false}) || ''}} {...props}/> : <div className={className} {...props}/>,
    span: ({node, className, ...props}: any) => className?.includes('math-inline') ? <span dangerouslySetInnerHTML={{__html: window.katex?.renderToString(props['data-math'], {displayMode:false, throwOnError:false}) || ''}} {...props}/> : <span className={className} {...props}/>
  }), [handleIDEUpdate, allNodes]);

  return (
    <div className="editor-container bg-[var(--bg-main)] text-[var(--text-main)]">
      <div className="editor-header bg-[var(--bg-toolbar)] border-[var(--border-color)]">
        {(viewMode !== 'preview' && !readOnly) && <EditorToolbar insertFormat={insertFormat} readOnly={readOnly} />}
      </div>
      <div className="split-container">
        {(viewMode === 'split' || viewMode === 'editor') && (
            <div className={`pane ${viewMode === 'split' ? 'half border-r' : 'full'}`}>
                <textarea 
                  ref={textareaRef} 
                  className="textarea" 
                  value={localContent} 
                  onChange={e => handleTextareaChange(e.target.value)} 
                  onBlur={persistToMarkdown}
                  placeholder="# Start typing..." 
                  spellCheck={false} 
                  disabled={readOnly} 
                />
            </div>
        )}
        {(viewMode === 'split' || viewMode === 'preview') && (
            <div id="markdown-preview" className={`pane ${viewMode === 'split' ? 'half' : 'full'} preview-area no-scrollbar`}>
                <div className="markdown-body">
                    <ReactMarkdown 
                        key={fileName} 
                        remarkPlugins={[remarkGfm, remarkMath]} 
                        rehypePlugins={[rehypeRaw, rehypeHighlight]}
                        components={markdownComponents}
                    >
                      {localContent}
                    </ReactMarkdown>
                </div>
            </div>
        )}
      </div>
    </div>
  );
};

import React, { useState, useEffect, useCallback, useMemo } from 'react';
import { v4 as uuidv4 } from 'uuid';
import { 
  Download, Upload, FileJson, Palette, PanelLeft, Edit3, Columns, Eye, X, FileText, Save, Plus
} from 'lucide-react';
import { Sidebar } from './components/Sidebar';
import { Editor } from './components/Editor';
import { FileNode, NodeType, AppTheme } from './types';
import { initialNodes } from './initialData';

const themes: Record<string, AppTheme> = {
  dark: { name: 'Dark', bgMain: '#030712', bgSidebar: '#111827', textMain: '#f3f4f6', textMuted: '#9ca3af', border: '#1f2937', accent: '#3b82f6', hover: 'rgba(255, 255, 255, 0.05)' },
  light: { name: 'Light', bgMain: '#ffffff', bgSidebar: '#f3f4f6', textMain: '#111827', textMuted: '#6b7280', border: '#e5e7eb', accent: '#3b82f6', hover: 'rgba(0, 0, 0, 0.05)' },
  navy: { name: 'Navy', bgMain: '#0a192f', bgSidebar: '#112240', textMain: '#ccd6f6', textMuted: '#8892b0', border: '#233554', accent: '#64ffda', hover: 'rgba(100, 255, 218, 0.1)' },
  dracula: { name: 'Dracula', bgMain: '#282a36', bgSidebar: '#21222c', textMain: '#f8f8f2', textMuted: '#6272a4', border: '#44475a', accent: '#ff79c6', hover: 'rgba(255, 255, 255, 0.1)' }
};

export default function App() {
  const [nodes, setNodes] = useState<FileNode[]>(() => {
    const saved = localStorage.getItem('mathsci-fs');
    return saved ? JSON.parse(saved) : initialNodes;
  });
  const [activeFileId, setActiveFileId] = useState<string | null>('file-intro');
  const [expandedFolders, setExpandedFolders] = useState<Set<string>>(new Set(['folder-welcome', 'folder-docs']));
  const [showSettings, setShowSettings] = useState(false);
  const [isSidebarOpen, setIsSidebarOpen] = useState(true);
  const [editorView, setEditorView] = useState<'split' | 'editor' | 'preview'>('split');
  const [currentTheme, setCurrentTheme] = useState<AppTheme>(() => {
    const saved = localStorage.getItem('mathsci-theme');
    return saved ? JSON.parse(saved) : themes.dark;
  });

  useEffect(() => {
    const root = document.documentElement;
    root.style.setProperty('--bg-main', currentTheme.bgMain);
    root.style.setProperty('--bg-sidebar', currentTheme.bgSidebar);
    root.style.setProperty('--bg-toolbar', currentTheme.bgSidebar);
    root.style.setProperty('--text-main', currentTheme.textMain);
    root.style.setProperty('--text-muted', currentTheme.textMuted);
    root.style.setProperty('--border-color', currentTheme.border);
    root.style.setProperty('--accent-color', currentTheme.accent);
    root.style.setProperty('--hover-bg', currentTheme.hover);
    localStorage.setItem('mathsci-theme', JSON.stringify(currentTheme));
  }, [currentTheme]);

  useEffect(() => {
    // Throttled persistence for 1000+ files
    const handler = setTimeout(() => {
      localStorage.setItem('mathsci-fs', JSON.stringify(nodes));
    }, 1000);
    return () => clearTimeout(handler);
  }, [nodes]);

  const deleteRecursive = useCallback((targetId: string, currentNodes: FileNode[]): string[] => {
    const idsToDelete: string[] = [targetId];
    const queue = [targetId];
    while (queue.length > 0) {
      const parentId = queue.shift();
      const children = currentNodes.filter(n => n.parentId === parentId);
      children.forEach(child => {
        idsToDelete.push(child.id);
        queue.push(child.id);
      });
    }
    return idsToDelete;
  }, []);

  const handleExportWorkspace = (format: 'json' | 'md') => {
    let content = '';
    let mimeType = '';
    let fileName = '';

    if (format === 'json') {
      content = JSON.stringify({ version: 1, nodes }, null, 2);
      mimeType = 'application/json';
      fileName = `workspace_backup_${new Date().toISOString().split('T')[0]}.json`;
    } else {
      // Optimized Bundled Markdown Export for 1000+ files
      const nodeMap = new Map<string | null, FileNode[]>();
      nodes.forEach(n => {
        const pId = n.parentId;
        if (!nodeMap.has(pId)) nodeMap.set(pId, []);
        nodeMap.get(pId)!.push(n);
      });

      const buildMarkdown = (parentId: string | null, depth: number): string => {
        let md = '';
        const items = nodeMap.get(parentId) || [];
        // Folders first, then alphabetically
        items.sort((a, b) => {
          if (a.type !== b.type) return a.type === NodeType.FOLDER ? -1 : 1;
          return a.name.localeCompare(b.name);
        });

        items.forEach(item => {
          const indent = '#'.repeat(Math.min(depth + 1, 6));
          if (item.type === NodeType.FOLDER) {
            md += `${indent} Folder: ${item.name}\n\n`;
            md += buildMarkdown(item.id, depth + 1);
          } else {
            md += `${indent} File: ${item.name}\n\n${item.content}\n\n---\n\n`;
          }
        });
        return md;
      };

      content = `# Workspace Export - ${new Date().toLocaleString()}\n\n${buildMarkdown(null, 0)}`;
      mimeType = 'text/markdown';
      fileName = `workspace_bundle_${nodes.length}_files.md`;
    }

    const blob = new Blob([content], { type: mimeType });
    const url = URL.createObjectURL(blob);
    const link = document.createElement('a');
    link.href = url;
    link.download = fileName;
    link.click();
    URL.revokeObjectURL(url);
  };

  const handleImportWorkspace = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;
    const reader = new FileReader();
    reader.onload = (event) => {
      try {
        const data = JSON.parse(event.target?.result as string);
        if (data.nodes && Array.isArray(data.nodes)) {
          setNodes(data.nodes);
          if (data.nodes.length > 0) {
            const firstFile = data.nodes.find((n: FileNode) => n.type === NodeType.FILE);
            setActiveFileId(firstFile ? firstFile.id : data.nodes[0].id);
          }
        }
      } catch (err) {
        alert("Failed to parse import file. Ensure it is a valid Workspace JSON.");
      }
    };
    reader.readAsText(file);
  };

  const activeFile = useMemo(() => nodes.find(n => n.id === activeFileId), [nodes, activeFileId]);

  return (
    <div className="app-container" style={{ background: 'var(--bg-main)' }}>
      <div className="sidebar-wrapper" style={{ width: isSidebarOpen ? '280px' : '0' }}>
         <Sidebar 
            nodes={nodes}
            activeFileId={activeFileId}
            expandedFolders={expandedFolders}
            onFileSelect={setActiveFileId}
            onToggleFolder={(id) => setExpandedFolders(prev => {
                const next = new Set(prev);
                if (next.has(id)) next.delete(id); else next.add(id);
                return next;
            })}
            onAddFile={(parentId) => {
                const id = uuidv4();
                const newNode: FileNode = { id, parentId, name: 'New File.md', type: NodeType.FILE, content: '', createdAt: Date.now() };
                setNodes(prev => [...prev, newNode]);
                setActiveFileId(id);
                if (parentId) setExpandedFolders(prev => new Set(prev).add(parentId));
            }}
            onAddFolder={(parentId) => {
                const id = uuidv4();
                setNodes(prev => [...prev, { id, parentId, name: 'New Folder', type: NodeType.FOLDER, content: '', createdAt: Date.now() }]);
                if (parentId) setExpandedFolders(prev => new Set(prev).add(parentId));
            }}
            onDeleteNode={(id) => {
                const idsToRemove = deleteRecursive(id, nodes);
                setNodes(prev => prev.filter(n => !idsToRemove.includes(n.id)));
                if (activeFileId && idsToRemove.includes(activeFileId)) setActiveFileId(null);
            }}
            onRenameNode={(id, name) => setNodes(prev => prev.map(n => n.id === id ? { ...n, name } : n))}
            onMoveNode={(id, parentId) => setNodes(prev => prev.map(n => n.id === id ? { ...n, parentId } : n))}
         />
      </div>

      <div className="main-content" style={{ flex: 1, display: 'flex', flexDirection: 'column', overflow: 'hidden' }}>
        <div className="toolbar">
            <div style={{ display: 'flex', alignItems: 'center', gap: '0.75rem' }}>
                <button onClick={() => setIsSidebarOpen(!isSidebarOpen)} className="btn-icon" title="Toggle Sidebar"><PanelLeft size={18} /></button>
                <h1 className="app-title" style={{ fontSize: '1rem' }}>MathSci <span style={{ opacity: 0.4, fontWeight: 'normal', fontSize: '0.75rem' }}>v2.0</span></h1>
            </div>
            <div style={{ display: 'flex', alignItems: 'center', gap: '0.5rem' }}>
                <button onClick={() => handleExportWorkspace('md')} className="btn" title="Bundle all files into one Markdown"><FileText size={14} /> Export Bundle</button>
                <button onClick={() => handleExportWorkspace('json')} className="btn" title="Backup Workspace JSON"><Download size={14} /> Backup</button>
                <label className="btn" style={{ cursor: 'pointer' }}>
                  <Upload size={14} /> Restore
                  <input type="file" onChange={handleImportWorkspace} style={{ display: 'none' }} accept=".json" />
                </label>
                <div className="divider"></div>
                <button onClick={() => setShowSettings(true)} className="btn"><Palette size={14} /> Theme</button>
                <div style={{ display: 'flex', background: 'var(--bg-main)', border: '1px solid var(--border-color)', borderRadius: '6px', padding: '2px', gap: '2px' }}>
                   <button onClick={() => setEditorView('editor')} className="btn-icon" style={{ color: editorView === 'editor' ? 'var(--accent-color)' : 'var(--text-muted)' }}><Edit3 size={16} /></button>
                   <button onClick={() => setEditorView('split')} className="btn-icon" style={{ color: editorView === 'split' ? 'var(--accent-color)' : 'var(--text-muted)' }}><Columns size={16} /></button>
                   <button onClick={() => setEditorView('preview')} className="btn-icon" style={{ color: editorView === 'preview' ? 'var(--accent-color)' : 'var(--text-muted)' }}><Eye size={16} /></button>
                </div>
            </div>
        </div>

        <div style={{ flex: 1, overflow: 'hidden' }}>
            {activeFile ? (
                <Editor 
                  content={activeFile.content} 
                  fileName={activeFile.name}
                  allNodes={nodes}
                  viewMode={editorView}
                  onChange={(content) => setNodes(prev => prev.map(n => n.id === activeFileId ? { ...n, content } : n))} 
                />
            ) : (
              <div style={{ height: '100%', display: 'flex', alignItems: 'center', justifyContent: 'center', color: 'var(--text-muted)', flexDirection: 'column', gap: '1.5rem', textAlign: 'center' }}>
                  <div style={{ position: 'relative' }}>
                    <FileText size={64} style={{ opacity: 0.1 }} />
                    {/* Fixed: Plus icon now correctly uses the imported Plus from lucide-react */}
                    <Plus size={24} style={{ position: 'absolute', bottom: -5, right: -5, opacity: 0.3 }} />
                  </div>
                  <div>
                    <p style={{ fontSize: '1.1rem', marginBottom: '0.5rem' }}>Workspace ready</p>
                    <p style={{ fontSize: '0.85rem', opacity: 0.6 }}>{nodes.length} items in file system. Select a file to edit.</p>
                  </div>
                  <button onClick={() => {
                     const id = uuidv4();
                     setNodes(prev => [...prev, { id, parentId: null, name: 'Untitled.md', type: NodeType.FILE, content: '', createdAt: Date.now() }]);
                     setActiveFileId(id);
                  }} className="btn btn-primary" style={{ padding: '0.5rem 1.5rem' }}>Create New File</button>
              </div>
            )}
        </div>
      </div>

      {showSettings && (
          <div className="modal-overlay" onClick={() => setShowSettings(false)}>
              <div className="modal" onClick={e => e.stopPropagation()} style={{ maxWidth: '420px', background: '#0a0f1d', color: '#f8fafc', border: '1px solid #1e293b', padding: '1.5rem' }}>
                  <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: '2rem' }}>
                      <div style={{ display: 'flex', alignItems: 'center', gap: '0.75rem' }}>
                        <Palette size={20} color="#3b82f6" />
                        <span style={{ fontSize: '1.125rem', fontWeight: 600 }}>Theme Settings</span>
                      </div>
                      <button onClick={() => setShowSettings(false)} className="btn-icon"><X size={20}/></button>
                  </div>
                  <div style={{ marginBottom: '2rem' }}>
                    <label style={{ fontSize: '0.85rem', color: '#94a3b8', marginBottom: '1rem', display: 'block' }}>Select Look & Feel</label>
                    <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: '0.75rem' }}>
                        {Object.entries(themes).map(([k, t]) => (
                            <button key={k} onClick={() => setCurrentTheme(t)} style={{ padding: '0.75rem', borderRadius: '8px', background: t.bgMain, color: t.textMain, border: `1px solid ${currentTheme.name === t.name ? 'var(--accent-color)' : '#1e293b'}`, cursor: 'pointer', display: 'flex', alignItems: 'center', gap: '0.5rem', fontSize: '0.9rem', transition: 'all 0.2s' }}>
                                <div style={{ width: 12, height: 12, borderRadius: '50%', background: t.accent }} />
                                {t.name}
                            </button>
                        ))}
                    </div>
                  </div>
                  <button onClick={() => setShowSettings(false)} className="btn-primary" style={{ width: '100%', padding: '0.75rem', borderRadius: '8px', border: 'none', fontWeight: 600, cursor: 'pointer' }}>Apply Changes</button>
              </div>
          </div>
      )}
    </div>
  );
}

import React, { useState, useRef, useMemo, useCallback, useEffect } from 'react';
import ReactMarkdown from 'react-markdown';
import remarkGfm from 'remark-gfm';
import remarkMath from 'remark-math';
import rehypeKatex from 'rehype-katex';
import rehypeRaw from 'rehype-raw';
import rehypeHighlight from 'rehype-highlight';
import { MermaidDiagram } from './engines/MermaidDiagram';
import { SmilesDiagram } from './engines/SmilesDiagram';
import { InteractivePlot } from './engines/InteractivePlot';
import { PhysicsSimulation } from './engines/PhysicsSimulation';
import { EditorToolbar } from './editor/EditorToolbar';
import { FileNode } from '../types';

interface EditorProps {
  content: string;
  fileName: string;
  allNodes: FileNode[];
  onChange: (content: string) => void;
  readOnly?: boolean;
  viewMode?: 'split' | 'editor' | 'preview';
}

const safeJsonParse = (str: string) => {
  try {
    return JSON.parse(str);
  } catch (e) {
    try {
      const cleaned = str
        .replace(/\\n/g, "\\n")
        .replace(/\\'/g, "\\'")
        .replace(/\\"/g, '\\"')
        .replace(/\\&/g, "\\&")
        .replace(/\\r/g, "\\r")
        .replace(/\\t/g, "\\t")
        .replace(/\\b/g, "\\b")
        .replace(/\\f/g, "\\f");
      return JSON.parse(cleaned);
    } catch (e2) {
      throw e2;
    }
  }
};

export const Editor: React.FC<EditorProps> = ({ content, fileName, allNodes, onChange, readOnly = false, viewMode = 'split' }) => {
  const textareaRef = useRef<HTMLTextAreaElement>(null);
  const contentRef = useRef(content);
  const [localContent, setLocalContent] = useState(content);

  const ideRegistry = useRef<Record<string, string>>({});
  const persistTimer = useRef<number | null>(null);

  useEffect(() => {
    if (content !== contentRef.current) {
      contentRef.current = content;
      setLocalContent(content);
      ideRegistry.current = {};
    }
  }, [content, fileName]);

  const persistToMarkdown = useCallback(() => {
    const currentDoc = contentRef.current;
    const registry = ideRegistry.current;

    const newDoc = currentDoc.replace(/```ide\s*([\s\S]*?)\s*```/g, (match, inner) => {
      try {
        const parsed = safeJsonParse(inner.trim());
        const id = parsed.internal_block_id;
        if (id && registry[id]) {
          return `\`\`\`ide\n${registry[id]}\n\`\`\``;
        }
        return match;
      } catch (e) {
        return match;
      }
    });

    if (newDoc !== currentDoc) {
      contentRef.current = newDoc;
      setLocalContent(newDoc);
      onChange(newDoc);
    }
  }, [onChange]);

  const handleTextareaChange = (val: string) => {
    setLocalContent(val);
    contentRef.current = val;
    if (persistTimer.current) window.clearTimeout(persistTimer.current);
    persistTimer.current = window.setTimeout(persistToMarkdown, 1000);
  };

  const insertFormat = (prefix: string, suffix: string = '', block: boolean = false) => {
    if (!textareaRef.current) return;
    const { selectionStart: start, selectionEnd: end, value } = textareaRef.current;
    const selectedText = value.substring(start, end);
    let insertion = prefix + selectedText + suffix;
    if (block && value[start - 1] !== '\n' && start !== 0) insertion = '\n' + insertion;
    const newVal = value.substring(0, start) + insertion + value.substring(end);
    handleTextareaChange(newVal);
  };

  const markdownComponents = useMemo(() => ({
    code({node, inline, className, children, ...props}: any) {
        const match = /language-([\w-]+)/.exec(className || '');
        const rawCodeContent = String(children).replace(/\n$/, '');
        if (!inline && match?.[1] === 'ide') {
          try { 
            const parsed = safeJsonParse(rawCodeContent.trim());
            const blockId = parsed.internal_block_id;
            if (!blockId) return <pre>{rawCodeContent}</pre>;
            const configToUse = ideRegistry.current[blockId] || rawCodeContent;

            return (
              <div style={{ border: '1px solid var(--border-color)', padding: '1rem', background: 'var(--bg-sidebar)', borderRadius: '8px' }}>
                <p style={{ color: 'var(--accent-color)', margin: '0 0 0.5rem 0', fontWeight: 'bold' }}>IDE Block: {blockId}</p>
                <pre style={{ margin: 0, fontSize: '11px', overflow: 'auto' }}>{configToUse}</pre>
                <p style={{ fontSize: '10px', marginTop: '8px', opacity: 0.6 }}>Interactive editor component not found.</p>
              </div>
            );
          } catch(e: any) { 
            return (
              <div style={{ border: '1px solid #dc2626', padding: '1rem', background: '#fef2f2', borderRadius: '8px' }}>
                <p style={{ color: '#dc2626', margin: '0 0 0.5rem 0', fontWeight: 'bold' }}>JSON Syntax Error in IDE Block</p>
                <pre style={{ margin: 0, fontSize: '11px', overflow: 'auto' }}>{e.message}</pre>
              </div>
            );
          }
        }
        if (!inline) {
          switch (match?.[1]) {
            case 'mermaid': return <MermaidDiagram chart={rawCodeContent} />;
            case 'smiles': return <SmilesDiagram smiles={rawCodeContent} />;
            case 'plot': return <InteractivePlot configStr={rawCodeContent} />;
            case 'physics': return <PhysicsSimulation configStr={rawCodeContent} />;
          }
        }
        return <code className={className} {...props}>{children}</code>;
    }
    // We removed custom div/span rendering for math because rehype-katex handles it better
  }), [allNodes]);

  return (
    <div className="editor-container bg-[var(--bg-main)] text-[var(--text-main)]">
      <div className="editor-header bg-[var(--bg-toolbar)] border-[var(--border-color)]">
        {(viewMode !== 'preview' && !readOnly) && <EditorToolbar insertFormat={insertFormat} readOnly={readOnly} />}
      </div>
      <div className="split-container">
        {(viewMode === 'split' || viewMode === 'editor') && (
            <div className={`pane ${viewMode === 'split' ? 'half border-r' : 'full'}`}>
                <textarea 
                  ref={textareaRef} 
                  className="textarea" 
                  value={localContent} 
                  onChange={e => handleTextareaChange(e.target.value)} 
                  onBlur={persistToMarkdown}
                  placeholder="# Start typing..." 
                  spellCheck={false} 
                  disabled={readOnly} 
                />
            </div>
        )}
        {(viewMode === 'split' || viewMode === 'preview') && (
            <div id="markdown-preview" className={`pane ${viewMode === 'split' ? 'half' : 'full'} preview-area no-scrollbar`}>
                <div className="markdown-body">
                    <ReactMarkdown 
                        key={fileName} 
                        remarkPlugins={[remarkGfm, remarkMath]} 
                        rehypePlugins={[
                          rehypeRaw, 
                          [rehypeKatex, { trust: true, strict: false }], 
                          rehypeHighlight
                        ]}
                        components={markdownComponents}
                    >
                      {localContent}
                    </ReactMarkdown>
                </div>
            </div>
        )}
      </div>
    </div>
  );
};

import React, { useState, useEffect, useRef } from 'react';
import Editor from '@monaco-editor/react';
import { 
  Play, Maximize2, Minimize2, FileCode, Globe, Palette, 
  ExternalLink, RefreshCcw, Layout
} from 'lucide-react';

interface CodeEditorEngineProps {
  config: {
    js?: string;
    html?: string;
    css?: string;
    internal_block_id: string;
  };
  onUpdate: (newConfig: string) => void;
}

type Tab = 'js' | 'html' | 'css' | 'result';

export const CodeEditorEngine: React.FC<CodeEditorEngineProps> = ({ config, onUpdate }) => {
  const [activeTab, setActiveTab] = useState<Tab>('js');
  const [isFullscreen, setIsFullscreen] = useState(false);
  const [showPreview, setShowPreview] = useState(true);

  // Local state for the code to avoid unnecessary parent re-renders while typing
  const [jsCode, setJsCode] = useState(config.js || '');
  const [htmlCode, setHtmlCode] = useState(config.html || '');
  const [cssCode, setCssCode] = useState(config.css || '');

  const iframeRef = useRef<HTMLIFrameElement>(null);

  // Sync with prop changes (when switching files)
  useEffect(() => {
    setJsCode(config.js || '');
    setHtmlCode(config.html || '');
    setCssCode(config.css || '');
  }, [config.internal_block_id]);

  const runCode = () => {
    if (!iframeRef.current) return;

    const combinedHtml = `
      <!DOCTYPE html>
      <html>
        <head>
          <meta charset="utf-8">
          <style>${cssCode}</style>
        </head>
        <body>
          ${htmlCode}
          <script>
            (function() {
              const originalLog = console.log;
              console.log = function(...args) {
                originalLog.apply(console, args);
                window.parent.postMessage({ type: 'console', payload: args.join(' ') }, '*');
              };
              try {
                ${jsCode}
              } catch (err) {
                console.error(err);
              }
            })();
          </script>
        </body>
      </html>
    `;

    const blob = new Blob([combinedHtml], { type: 'text/html' });
    const url = URL.createObjectURL(blob);
    iframeRef.current.src = url;

    // Persist changes to parent
    const updatedConfig = JSON.stringify({
      js: jsCode,
      html: htmlCode,
      css: cssCode,
      internal_block_id: config.internal_block_id
    }, null, 2);
    onUpdate(updatedConfig);
  };

  useEffect(() => {
    if (activeTab === 'result' || showPreview) {
      const timer = setTimeout(runCode, 500);
      return () => clearTimeout(timer);
    }
  }, [activeTab, showPreview]);

  const TabButton = ({ id, label, icon: Icon }: { id: Tab, label: string, icon: any }) => (
    <button
      onClick={() => setActiveTab(id)}
      style={{
        padding: '0.4rem 0.75rem',
        fontSize: '0.75rem',
        fontWeight: 600,
        display: 'flex',
        alignItems: 'center',
        gap: '0.4rem',
        border: 'none',
        background: activeTab === id ? 'var(--bg-main)' : 'transparent',
        color: activeTab === id ? 'var(--accent-color)' : 'var(--text-muted)',
        borderBottom: activeTab === id ? '2px solid var(--accent-color)' : '2px solid transparent',
        cursor: 'pointer',
        transition: 'all 0.2s'
      }}
    >
      <Icon size={14} />
      {label}
    </button>
  );

  const containerStyle: React.CSSProperties = isFullscreen ? {
    position: 'fixed',
    top: 0,
    left: 0,
    width: '100vw',
    height: '100vh',
    zIndex: 9999,
    backgroundColor: 'var(--bg-main)',
    display: 'flex',
    flexDirection: 'column'
  } : {
    width: '100%',
    height: '500px',
    border: '1px solid var(--border-color)',
    borderRadius: '8px',
    overflow: 'hidden',
    display: 'flex',
    flexDirection: 'column',
    margin: '1rem 0',
    backgroundColor: 'var(--bg-sidebar)'
  };

  return (
    <div style={containerStyle}>
      {/* Header Toolbar */}
      <div style={{ 
        height: '40px', 
        backgroundColor: '#1f2937', 
        display: 'flex', 
        alignItems: 'center', 
        justifyContent: 'space-between',
        padding: '0 0.5rem',
        borderBottom: '1px solid var(--border-color)'
      }}>
        <div style={{ display: 'flex', gap: '2px', height: '100%', alignItems: 'flex-end' }}>
          <TabButton id="js" label="JS" icon={FileCode} />
          <TabButton id="html" label="HTML" icon={Globe} />
          <TabButton id="css" label="CSS" icon={Palette} />
          <TabButton id="result" label="Result" icon={Layout} />
        </div>

        <div style={{ display: 'flex', alignItems: 'center', gap: '0.5rem' }}>
          <button 
            onClick={runCode}
            style={{
              padding: '0.3rem 0.8rem',
              borderRadius: '4px',
              backgroundColor: '#374151',
              color: '#fff',
              border: 'none',
              fontSize: '0.7rem',
              fontWeight: 'bold',
              display: 'flex',
              alignItems: 'center',
              gap: '0.4rem',
              cursor: 'pointer'
            }}
          >
            <Play size={12} fill="white" /> RUN
          </button>
          <button 
            onClick={() => setIsFullscreen(!isFullscreen)}
            style={{ background: 'transparent', border: 'none', color: '#9ca3af', cursor: 'pointer' }}
          >
            {isFullscreen ? <Minimize2 size={16} /> : <Maximize2 size={16} />}
          </button>
        </div>
      </div>

      {/* Editor/Result Area */}
      <div style={{ flex: 1, display: 'flex', overflow: 'hidden' }}>
        {/* Monaco Editor Pane */}
        {activeTab !== 'result' && (
          <div style={{ flex: 1, height: '100%' }}>
            <Editor
              height="100%"
              theme="vs-dark"
              language={activeTab === 'js' ? 'javascript' : activeTab === 'html' ? 'html' : 'css'}
              value={activeTab === 'js' ? jsCode : activeTab === 'html' ? htmlCode : cssCode}
              onChange={(val) => {
                if (activeTab === 'js') setJsCode(val || '');
                if (activeTab === 'html') setHtmlCode(val || '');
                if (activeTab === 'css') setCssCode(val || '');
              }}
              options={{
                minimap: { enabled: false },
                fontSize: 13,
                scrollBeyondLastLine: false,
                automaticLayout: true,
                padding: { top: 10 }
              }}
            />
          </div>
        )}

        {/* Result/Preview Pane */}
        {(activeTab === 'result' || (showPreview && activeTab !== 'result')) && (
          <div style={{ 
            flex: activeTab === 'result' ? 1 : 0.8, 
            height: '100%', 
            backgroundColor: '#fff',
            borderLeft: '1px solid var(--border-color)',
            display: 'flex',
            flexDirection: 'column'
          }}>
            <iframe
              ref={iframeRef}
              title="Preview"
              style={{ width: '100%', height: '100%', border: 'none' }}
              sandbox="allow-scripts"
            />
          </div>
        )}
      </div>
    </div>
  );
};

import React, { useState, useRef, useMemo, useCallback, useEffect } from 'react';
import ReactMarkdown from 'react-markdown';
import remarkGfm from 'remark-gfm';
import remarkMath from 'remark-math';
import rehypeKatex from 'rehype-katex';
import rehypeRaw from 'rehype-raw';
import rehypeHighlight from 'rehype-highlight';
import { MermaidDiagram } from './engines/MermaidDiagram';
import { SmilesDiagram } from './engines/SmilesDiagram';
import { InteractivePlot } from './engines/InteractivePlot';
import { PhysicsSimulation } from './engines/PhysicsSimulation';
import { CodeEditorEngine } from './engines/CodeEditorEngine';
import { EditorToolbar } from './editor/EditorToolbar';
import { FileNode } from '../types';

interface EditorProps {
  content: string;
  fileName: string;
  allNodes: FileNode[];
  onChange: (content: string) => void;
  readOnly?: boolean;
  viewMode?: 'split' | 'editor' | 'preview';
}

const safeJsonParse = (str: string) => {
  try {
    return JSON.parse(str);
  } catch (e) {
    try {
      const cleaned = str
        .replace(/\\n/g, "\\n")
        .replace(/\\'/g, "\\'")
        .replace(/\\"/g, '\\"')
        .replace(/\\&/g, "\\&")
        .replace(/\\r/g, "\\r")
        .replace(/\\t/g, "\\t")
        .replace(/\\b/g, "\\b")
        .replace(/\\f/g, "\\f");
      return JSON.parse(cleaned);
    } catch (e2) {
      throw e2;
    }
  }
};

export const Editor: React.FC<EditorProps> = ({ content, fileName, allNodes, onChange, readOnly = false, viewMode = 'split' }) => {
  const textareaRef = useRef<HTMLTextAreaElement>(null);
  const contentRef = useRef(content);
  const [localContent, setLocalContent] = useState(content);

  // Registry to keep track of live updates from IDE blocks
  const ideRegistry = useRef<Record<string, string>>({});
  const persistTimer = useRef<number | null>(null);

  useEffect(() => {
    if (content !== contentRef.current) {
      contentRef.current = content;
      setLocalContent(content);
      // Clear registry when switching files to ensure fresh parse
      ideRegistry.current = {};
    }
  }, [content, fileName]);

  const persistToMarkdown = useCallback(() => {
    const currentDoc = contentRef.current;
    const registry = ideRegistry.current;

    // Find all IDE blocks and update them from our registry
    const newDoc = currentDoc.replace(/```ide\s*([\s\S]*?)\s*```/g, (match, inner) => {
      try {
        const parsed = safeJsonParse(inner.trim());
        const id = parsed.internal_block_id;
        if (id && registry[id]) {
          return `\`\`\`ide\n${registry[id]}\n\`\`\``;
        }
        return match;
      } catch (e) {
        return match;
      }
    });

    if (newDoc !== currentDoc) {
      contentRef.current = newDoc;
      setLocalContent(newDoc);
      onChange(newDoc);
    }
  }, [onChange]);

  const handleTextareaChange = (val: string) => {
    setLocalContent(val);
    contentRef.current = val;
    if (persistTimer.current) window.clearTimeout(persistTimer.current);
    persistTimer.current = window.setTimeout(persistToMarkdown, 1000);
  };

  const insertFormat = (prefix: string, suffix: string = '', block: boolean = false) => {
    if (!textareaRef.current) return;
    const { selectionStart: start, selectionEnd: end, value } = textareaRef.current;
    const selectedText = value.substring(start, end);
    let insertion = prefix + selectedText + suffix;
    if (block && value[start - 1] !== '\n' && start !== 0) insertion = '\n' + insertion;
    const newVal = value.substring(0, start) + insertion + value.substring(end);
    handleTextareaChange(newVal);
  };

  const handleIDEUpdate = useCallback((targetId: string, newConfigStr: string) => {
    ideRegistry.current[targetId] = newConfigStr;
    // We don't trigger onChange immediately for performance, 
    // we wait for a throttle or manual blur
    const currentDoc = contentRef.current;
    const updatedDoc = currentDoc.replace(/```ide\s*([\s\S]*?)\s*```/g, (match, inner) => {
      try {
        const parsed = safeJsonParse(inner.trim());
        if (parsed.internal_block_id === targetId) {
          return `\`\`\`ide\n${newConfigStr}\n\`\`\``;
        }
        return match;
      } catch (e) {
        return match;
      }
    });

    if (updatedDoc !== currentDoc) {
      contentRef.current = updatedDoc;
      setLocalContent(updatedDoc);
      if (persistTimer.current) window.clearTimeout(persistTimer.current);
      persistTimer.current = window.setTimeout(() => {
        onChange(updatedDoc);
      }, 500);
    }
  }, [onChange]);

  const markdownComponents = useMemo(() => ({
    code({node, inline, className, children, ...props}: any) {
        const match = /language-([\w-]+)/.exec(className || '');
        const rawCodeContent = String(children).replace(/\n$/, '');
        if (!inline && match?.[1] === 'ide') {
          try { 
            const parsed = safeJsonParse(rawCodeContent.trim());
            const blockId = parsed.internal_block_id;
            if (!blockId) return <pre>{rawCodeContent}</pre>;

            return (
              <CodeEditorEngine 
                key={blockId}
                config={parsed}
                onUpdate={(newStr) => handleIDEUpdate(blockId, newStr)}
              />
            );
          } catch(e: any) { 
            return <pre style={{color: 'red'}}>IDE Syntax Error: {e.message}</pre>;
          }
        }
        if (!inline) {
          switch (match?.[1]) {
            case 'mermaid': return <MermaidDiagram chart={rawCodeContent} />;
            case 'smiles': return <SmilesDiagram smiles={rawCodeContent} />;
            case 'plot': return <InteractivePlot configStr={rawCodeContent} />;
            case 'physics': return <PhysicsSimulation configStr={rawCodeContent} />;
          }
        }
        return <code className={className} {...props}>{children}</code>;
    }
  }), [handleIDEUpdate, allNodes]);

  return (
    <div className="editor-container bg-[var(--bg-main)] text-[var(--text-main)]">
      <div className="editor-header bg-[var(--bg-toolbar)] border-[var(--border-color)]">
        {(viewMode !== 'preview' && !readOnly) && <EditorToolbar insertFormat={insertFormat} readOnly={readOnly} />}
      </div>
      <div className="split-container">
        {(viewMode === 'split' || viewMode === 'editor') && (
            <div className={`pane ${viewMode === 'split' ? 'half border-r' : 'full'}`}>
                <textarea 
                  ref={textareaRef} 
                  className="textarea" 
                  value={localContent} 
                  onChange={e => handleTextareaChange(e.target.value)} 
                  onBlur={persistToMarkdown}
                  placeholder="# Start typing..." 
                  spellCheck={false} 
                  disabled={readOnly} 
                />
            </div>
        )}
        {(viewMode === 'split' || viewMode === 'preview') && (
            <div id="markdown-preview" className={`pane ${viewMode === 'split' ? 'half' : 'full'} preview-area no-scrollbar`}>
                <div className="markdown-body">
                    <ReactMarkdown 
                        key={fileName} 
                        remarkPlugins={[remarkGfm, remarkMath]} 
                        rehypePlugins={[
                          rehypeRaw, 
                          [rehypeKatex, { trust: true, strict: false }], 
                          rehypeHighlight
                        ]}
                        components={markdownComponents}
                    >
                      {localContent}
                    </ReactMarkdown>
                </div>
            </div>
        )}
      </div>
    </div>
  );
};

'use client';
import React, { useRef, useState } from 'react';
import { 
  Bold, Italic, Strikethrough, 
  Heading1, Heading2, Heading3, 
  List, ListOrdered, CheckSquare, 
  Quote, Code, Link, Image, Table, Minus,
  Sigma, Workflow, Hexagon, Activity, Atom, 
  Terminal, Upload, FileImage, Globe, Copy, Check, X,
  Layout, Cpu
} from 'lucide-react';
import { 
  PLOT_TEMPLATE, PHYSICS_TEMPLATE, REACTION_TEMPLATE, getIdeTemplate 
} from './templates';
import { compressImageToTarget } from '../../utils/imageUtils';

type TabName = 'Write' | 'Insert' | 'Math/Sci';

export const EditorToolbar = ({ insertFormat, readOnly }: { insertFormat: (p: string, s?: string, b?: boolean) => void, readOnly?: boolean }) => {
  const [activeTab, setActiveTab] = useState<TabName>('Write');
  const [uploadStatus, setUploadStatus] = useState<{name: string, syntax: string, size?: number} | null>(null);
  const [copied, setCopied] = useState(false);
  const fileInputRef = useRef<HTMLInputElement>(null);

  if (readOnly) return null;

  const handleImageUpload = async (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;

    try {
      const compressed = await compressImageToTarget(file, 10 * 1024);
      if (!compressed) {
        alert('Could not compress image. Try a different image.');
        if (fileInputRef.current) fileInputRef.current.value = '';
        return;
      }
      const { dataUrl, size } = compressed;
      const syntax = `<img src="${dataUrl}" alt="${file.name}" />`;
      insertFormat(`\n${syntax}\n`, '', true);
      setUploadStatus({ name: file.name, syntax, size });
    } catch (err) {
      console.error(err);
      alert('Failed to upload image.');
    } finally {
      if (fileInputRef.current) fileInputRef.current.value = '';
    }
  };

  const copyToClipboard = () => {
    if (uploadStatus) {
      navigator.clipboard.writeText(uploadStatus.syntax);
      setCopied(true);
      setTimeout(() => setCopied(false), 2000);
    }
  };

  const ToolbarButton = ({ icon: Icon, title, action, color }: { icon: any, title: string, action: () => void, color?: string }) => (
    <button 
      onClick={action} 
      className="btn-icon" 
      title={title} 
      style={{ color: color, padding: '0.4rem', borderRadius: '4px' }}
    >
      <Icon size={16} />
    </button>
  );

  const Group = ({ children, label }: { children: React.ReactNode, label?: string }) => (
    <div style={{ display: 'flex', alignItems: 'center', gap: '2px', padding: '0 8px', borderRight: '1px solid var(--border-color)', position: 'relative' }}>
      {children}
      {label && <span style={{ position: 'absolute', bottom: '-4px', left: 0, right: 0, textAlign: 'center', fontSize: '6px', color: 'var(--text-muted)', textTransform: 'uppercase', opacity: 0.6 }}>{label}</span>}
    </div>
  );

  return (
    <div className="editor-toolbar" style={{ borderBottom: '1px solid var(--border-color)', background: 'var(--bg-toolbar)', position: 'relative' }}>
       <div className="flex px-4 py-2 gap-2" style={{ background: 'var(--bg-main)' }}>
          {['Write', 'Insert', 'Math/Sci'].map((tab) => (
             <button
               key={tab}
               onClick={() => setActiveTab(tab as TabName)}
               style={{
                 padding: '0.2rem 0.75rem',
                 fontSize: '0.7rem',
                 fontWeight: 600,
                 borderRadius: '20px',
                 border: '1px solid var(--border-color)',
                 background: activeTab === tab ? 'var(--text-main)' : 'transparent',
                 color: activeTab === tab ? 'var(--bg-main)' : 'var(--text-main)',
                 cursor: 'pointer'
               }}
             >
               {tab}
             </button>
          ))}
       </div>

       <div className="px-2 pb-2 flex items-center overflow-x-auto h-12 no-scrollbar">
          {activeTab === 'Write' && (
            <>
              <Group label="Text">
                <ToolbarButton icon={Bold} title="Bold" action={() => insertFormat('**', '**')} />
                <ToolbarButton icon={Italic} title="Italic" action={() => insertFormat('*', '*')} />
                <ToolbarButton icon={Strikethrough} title="Strike" action={() => insertFormat('~~', '~~')} />
              </Group>
              <Group label="Header">
                <ToolbarButton icon={Heading1} title="H1" action={() => insertFormat('# ', '', true)} />
                <ToolbarButton icon={Heading2} title="H2" action={() => insertFormat('## ', '', true)} />
              </Group>
              <Group label="List">
                <ToolbarButton icon={List} title="Unordered" action={() => insertFormat('- ', '', true)} />
                <ToolbarButton icon={CheckSquare} title="Tasks" action={() => insertFormat('- [ ] ', '', true)} />
              </Group>
            </>
          )}

          {activeTab === 'Insert' && (
            <>
              <Group label="Media">
                <ToolbarButton icon={Link} title="Web Link" action={() => insertFormat('[text](', ')') } />
                <ToolbarButton icon={Globe} title="Image URL" action={() => insertFormat('![alt](', ')') } />
                <ToolbarButton icon={Upload} title="Upload File" action={() => fileInputRef.current?.click()} color="var(--accent-color)" />
                <input type="file" ref={fileInputRef} onChange={handleImageUpload} accept="image/*" style={{ display: 'none' }} />
              </Group>
              <Group label="Code">
                <ToolbarButton icon={Code} title="Inline" action={() => insertFormat('`', '`')} />
                <ToolbarButton icon={Terminal} title="Block" action={() => insertFormat('```\n', '\n```', true)} />
                <ToolbarButton icon={Cpu} title="Interactive IDE" action={() => insertFormat(getIdeTemplate(), '', true)} color="var(--accent-color)" />
              </Group>
              <Group label="Diagram">
                <ToolbarButton icon={Workflow} title="Mermaid" action={() => insertFormat('```mermaid\n', '\n```', true)} color="#c084fc" />
                <ToolbarButton icon={Activity} title="Plotly" action={() => insertFormat(PLOT_TEMPLATE, '', true)} color="#c084fc" />
              </Group>
            </>
          )}

          {activeTab === 'Math/Sci' && (
            <>
              <Group label="LaTeX">
                <ToolbarButton icon={Sigma} title="Math" action={() => insertFormat('$$\n', '\n$$', true)} color="#60a5fa" />
              </Group>
              <Group label="Chemistry">
                <ToolbarButton icon={Hexagon} title="SMILES" action={() => insertFormat('```smiles\n', '\n```', true)} color="#60a5fa" />
                <ToolbarButton icon={Activity} title="Reaction" action={() => insertFormat(REACTION_TEMPLATE, '', true)} color="#60a5fa" />
              </Group>
              <Group label="Physics">
                <ToolbarButton icon={Atom} title="Physics" action={() => insertFormat(PHYSICS_TEMPLATE, '', true)} color="#f87171" />
              </Group>
            </>
          )}
       </div>

       {uploadStatus && (
         <div style={{ position: 'absolute', top: '100%', left: 0, right: 0, zIndex: 100, background: 'var(--bg-sidebar)', borderBottom: '1px solid var(--border-color)', padding: '0.5rem 1rem', display: 'flex', alignItems: 'center', justifyContent: 'space-between', fontSize: '0.75rem', boxShadow: '0 4px 6px -1px rgba(0, 0, 0, 0.1)' }}>
            <div style={{ display: 'flex', alignItems: 'center', gap: '0.5rem', flex: 1, overflow: 'hidden' }}>
                <FileImage size={14} color="var(--accent-color)" />
                <span style={{ color: 'var(--text-muted)' }}>Uploaded:</span>
                <code style={{ background: 'var(--hover-bg)', padding: '2px 4px', borderRadius: '4px', whiteSpace: 'nowrap', overflow: 'hidden', textOverflow: 'ellipsis' }}>{uploadStatus.syntax}</code>
                {uploadStatus.size !== undefined && <span style={{ marginLeft: '0.5rem', color: 'var(--text-muted)', fontFamily: 'monospace' }}>({(uploadStatus.size / 1024).toFixed(1)} KB)</span>}
            </div>
            <div style={{ display: 'flex', gap: '0.5rem', marginLeft: '1rem' }}>
                <button onClick={copyToClipboard} className="btn" style={{ padding: '0.2rem 0.5rem' }}>
                    {copied ? <Check size={12} color="#4ade80" /> : <Copy size={12} />}
                    {copied ? 'Copied' : 'Copy'}
                </button>
                <button onClick={() => setUploadStatus(null)} className="btn-icon" style={{ padding: '2px' }}><X size={14}/></button>
            </div>
         </div>
       )}
    </div>
  );
};

import React, { useState, useEffect, useRef } from 'react';
import Editor from '@monaco-editor/react';
import { 
  Play, Maximize2, Minimize2, FileCode, Globe, Palette, 
  ExternalLink, RefreshCcw, Layout
} from 'lucide-react';

interface CodeEditorEngineProps {
  config: {
    js?: string;
    html?: string;
    css?: string;
    internal_block_id: string;
  };
  onUpdate: (newConfig: string) => void;
}

type Tab = 'js' | 'html' | 'css' | 'result';

export const CodeEditorEngine: React.FC<CodeEditorEngineProps> = ({ config, onUpdate }) => {
  const [activeTab, setActiveTab] = useState<Tab>('js');
  const [isFullscreen, setIsFullscreen] = useState(false);
  const [showPreview, setShowPreview] = useState(true);

  // Local state for the code to avoid unnecessary parent re-renders while typing
  const [jsCode, setJsCode] = useState(config.js || '');
  const [htmlCode, setHtmlCode] = useState(config.html || '');
  const [cssCode, setCssCode] = useState(config.css || '');

  const iframeRef = useRef<HTMLIFrameElement>(null);

  // Sync with prop changes (when switching files)
  useEffect(() => {
    setJsCode(config.js || '');
    setHtmlCode(config.html || '');
    setCssCode(config.css || '');
  }, [config.internal_block_id]);

  const runCode = () => {
    if (!iframeRef.current) return;

    const combinedHtml = `
      <!DOCTYPE html>
      <html>
        <head>
          <meta charset="utf-8">
          <style>${cssCode}</style>
        </head>
        <body>
          ${htmlCode}
          <script>
            (function() {
              const originalLog = console.log;
              console.log = function(...args) {
                originalLog.apply(console, args);
                window.parent.postMessage({ type: 'console', payload: args.join(' ') }, '*');
              };
              try {
                ${jsCode}
              } catch (err) {
                console.error(err);
              }
            })();
          </script>
        </body>
      </html>
    `;

    const blob = new Blob([combinedHtml], { type: 'text/html' });
    const url = URL.createObjectURL(blob);
    iframeRef.current.src = url;

    // Persist changes to parent
    const updatedConfig = JSON.stringify({
      js: jsCode,
      html: htmlCode,
      css: cssCode,
      internal_block_id: config.internal_block_id
    }, null, 2);
    onUpdate(updatedConfig);
  };

  useEffect(() => {
    if (activeTab === 'result' || showPreview) {
      const timer = setTimeout(runCode, 500);
      return () => clearTimeout(timer);
    }
  }, [activeTab, showPreview]);

  const TabButton = ({ id, label, icon: Icon }: { id: Tab, label: string, icon: any }) => (
    <button
      onClick={() => setActiveTab(id)}
      style={{
        padding: '0.4rem 0.75rem',
        fontSize: '0.75rem',
        fontWeight: 600,
        display: 'flex',
        alignItems: 'center',
        gap: '0.4rem',
        border: 'none',
        background: activeTab === id ? 'var(--bg-main)' : 'transparent',
        color: activeTab === id ? 'var(--accent-color)' : 'var(--text-muted)',
        borderBottom: activeTab === id ? '2px solid var(--accent-color)' : '2px solid transparent',
        cursor: 'pointer',
        transition: 'all 0.2s'
      }}
    >
      <Icon size={14} />
      {label}
    </button>
  );

  const containerStyle: React.CSSProperties = isFullscreen ? {
    position: 'fixed',
    top: 0,
    left: 0,
    width: '100vw',
    height: '100vh',
    zIndex: 9999,
    backgroundColor: 'var(--bg-main)',
    display: 'flex',
    flexDirection: 'column'
  } : {
    width: '100%',
    height: '500px',
    border: '1px solid var(--border-color)',
    borderRadius: '8px',
    overflow: 'hidden',
    display: 'flex',
    flexDirection: 'column',
    margin: '1rem 0',
    backgroundColor: 'var(--bg-sidebar)'
  };

  return (
    <div style={containerStyle}>
      {/* Header Toolbar */}
      <div style={{ 
        height: '40px', 
        backgroundColor: '#1f2937', 
        display: 'flex', 
        alignItems: 'center', 
        justifyContent: 'space-between',
        padding: '0 0.5rem',
        borderBottom: '1px solid var(--border-color)'
      }}>
        <div style={{ display: 'flex', gap: '2px', height: '100%', alignItems: 'flex-end' }}>
          <TabButton id="js" label="JS" icon={FileCode} />
          <TabButton id="html" label="HTML" icon={Globe} />
          <TabButton id="css" label="CSS" icon={Palette} />
          <TabButton id="result" label="Result" icon={Layout} />
        </div>

        <div style={{ display: 'flex', alignItems: 'center', gap: '0.5rem' }}>
          <button 
            onClick={runCode}
            style={{
              padding: '0.3rem 0.8rem',
              borderRadius: '4px',
              backgroundColor: '#374151',
              color: '#fff',
              border: 'none',
              fontSize: '0.7rem',
              fontWeight: 'bold',
              display: 'flex',
              alignItems: 'center',
              gap: '0.4rem',
              cursor: 'pointer'
            }}
          >
            <Play size={12} fill="white" /> RUN
          </button>
          <button 
            onClick={() => setIsFullscreen(!isFullscreen)}
            style={{ background: 'transparent', border: 'none', color: '#9ca3af', cursor: 'pointer' }}
          >
            {isFullscreen ? <Minimize2 size={16} /> : <Maximize2 size={16} />}
          </button>
        </div>
      </div>

      {/* Editor/Result Area */}
      <div style={{ flex: 1, display: 'flex', overflow: 'hidden' }}>
        {/* Monaco Editor Pane */}
        {/* Fix: Simplified conditional check to prevent TypeScript error about non-overlapping types */}
        {activeTab !== 'result' && (
          <div style={{ flex: 1, height: '100%' }}>
            <Editor
              height="100%"
              theme="vs-dark"
              language={activeTab === 'js' ? 'javascript' : activeTab === 'html' ? 'html' : 'css'}
              value={activeTab === 'js' ? jsCode : (activeTab === 'html' ? htmlCode : (activeTab === 'css' ? cssCode : ''))}
              onChange={(val) => {
                if (activeTab === 'js') setJsCode(val || '');
                else if (activeTab === 'html') setHtmlCode(val || '');
                else if (activeTab === 'css') setCssCode(val || '');
              }}
              options={{
                minimap: { enabled: false },
                fontSize: 13,
                scrollBeyondLastLine: false,
                automaticLayout: true,
                padding: { top: 10 }
              }}
            />
          </div>
        )}

        {/* Result/Preview Pane */}
        {(activeTab === 'result' || (showPreview && activeTab !== 'result')) && (
          <div style={{ 
            flex: activeTab === 'result' ? 1 : 0.8, 
            height: '100%', 
            backgroundColor: '#fff',
            borderLeft: '1px solid var(--border-color)',
            display: 'flex',
            flexDirection: 'column'
          }}>
            <iframe
              ref={iframeRef}
              title="Preview"
              style={{ width: '100%', height: '100%', border: 'none' }}
              sandbox="allow-scripts"
            />
          </div>
        )}
      </div>
    </div>
  );
};

import React, { useState, useRef, useMemo, useCallback, useEffect } from 'react';
import ReactMarkdown from 'react-markdown';
import remarkGfm from 'remark-gfm';
import remarkMath from 'remark-math';
import rehypeKatex from 'rehype-katex';
import rehypeRaw from 'rehype-raw';
import rehypeHighlight from 'rehype-highlight';
import { MermaidDiagram } from './engines/MermaidDiagram';
import { SmilesDiagram } from './engines/SmilesDiagram';
import { InteractivePlot } from './engines/InteractivePlot';
import { PhysicsSimulation } from './engines/PhysicsSimulation';
import { CodeEditorEngine } from './engines/CodeEditorEngine';
import { EditorToolbar } from './editor/EditorToolbar';
import { FileNode } from '../types';

interface EditorProps {
  content: string;
  fileName: string;
  allNodes: FileNode[];
  onChange: (content: string) => void;
  readOnly?: boolean;
  viewMode?: 'split' | 'editor' | 'preview';
}

const safeJsonParse = (str: string) => {
  try {
    return JSON.parse(str);
  } catch (e) {
    try {
      const cleaned = str
        .replace(/\\n/g, "\\n")
        .replace(/\\'/g, "\\'")
        .replace(/\\"/g, '\\"')
        .replace(/\\&/g, "\\&")
        .replace(/\\r/g, "\\r")
        .replace(/\\t/g, "\\t")
        .replace(/\\b/g, "\\b")
        .replace(/\\f/g, "\\f");
      return JSON.parse(cleaned);
    } catch (e2) {
      throw e2;
    }
  }
};

export const Editor: React.FC<EditorProps> = ({ content, fileName, allNodes, onChange, readOnly = false, viewMode = 'split' }) => {
  const textareaRef = useRef<HTMLTextAreaElement>(null);
  const contentRef = useRef(content);
  const [localContent, setLocalContent] = useState(content);

  // Registry to keep track of live updates from IDE blocks
  const ideRegistry = useRef<Record<string, string>>({});
  const persistTimer = useRef<number | null>(null);

  useEffect(() => {
    if (content !== contentRef.current) {
      contentRef.current = content;
      setLocalContent(content);
      // Clear registry when switching files to ensure fresh parse
      ideRegistry.current = {};
    }
  }, [content, fileName]);

  const persistToMarkdown = useCallback(() => {
    const currentDoc = contentRef.current;
    const registry = ideRegistry.current;

    // Find all IDE blocks and update them from our registry
    const newDoc = currentDoc.replace(/```ide\s*([\s\S]*?)\s*```/g, (match, inner) => {
      try {
        const parsed = safeJsonParse(inner.trim());
        const id = parsed.internal_block_id;
        if (id && registry[id]) {
          return `\`\`\`ide\n${registry[id]}\n\`\`\``;
        }
        return match;
      } catch (e) {
        return match;
      }
    });

    if (newDoc !== currentDoc) {
      contentRef.current = newDoc;
      setLocalContent(newDoc);
      onChange(newDoc);
    }
  }, [onChange]);

  const handleTextareaChange = (val: string) => {
    setLocalContent(val);
    contentRef.current = val;
    if (persistTimer.current) window.clearTimeout(persistTimer.current);
    persistTimer.current = window.setTimeout(persistToMarkdown, 1000);
  };

  const insertFormat = (prefix: string, suffix: string = '', block: boolean = false) => {
    if (!textareaRef.current) return;
    const { selectionStart: start, selectionEnd: end, value } = textareaRef.current;
    const selectedText = value.substring(start, end);
    let insertion = prefix + selectedText + suffix;
    if (block && value[start - 1] !== '\n' && start !== 0) insertion = '\n' + insertion;
    const newVal = value.substring(0, start) + insertion + value.substring(end);
    handleTextareaChange(newVal);
  };

  const handleIDEUpdate = useCallback((targetId: string, newConfigStr: string) => {
    ideRegistry.current[targetId] = newConfigStr;
    const currentDoc = contentRef.current;
    const updatedDoc = currentDoc.replace(/```ide\s*([\s\S]*?)\s*```/g, (match, inner) => {
      try {
        const parsed = safeJsonParse(inner.trim());
        if (parsed.internal_block_id === targetId) {
          return `\`\`\`ide\n${newConfigStr}\n\`\`\``;
        }
        return match;
      } catch (e) {
        return match;
      }
    });

    if (updatedDoc !== currentDoc) {
      contentRef.current = updatedDoc;
      setLocalContent(updatedDoc);
      if (persistTimer.current) window.clearTimeout(persistTimer.current);
      persistTimer.current = window.setTimeout(() => {
        onChange(updatedDoc);
      }, 500);
    }
  }, [onChange]);

  const markdownComponents = useMemo(() => ({
    code({node, inline, className, children, ...props}: any) {
        const match = /language-([\w-]+)/.exec(className || '');
        const rawCodeContent = String(children).replace(/\n$/, '');
        if (!inline && match?.[1] === 'ide') {
          try { 
            const parsed = safeJsonParse(rawCodeContent.trim());
            const blockId = parsed.internal_block_id;
            if (!blockId) return <pre>{rawCodeContent}</pre>;

            return (
              <CodeEditorEngine 
                key={blockId}
                config={parsed}
                onUpdate={(newStr) => handleIDEUpdate(blockId, newStr)}
              />
            );
          } catch(e: any) { 
            return <pre style={{color: 'red'}}>IDE Syntax Error: {e.message}</pre>;
          }
        }
        if (!inline) {
          switch (match?.[1]) {
            case 'mermaid': return <MermaidDiagram chart={rawCodeContent} />;
            case 'smiles': return <SmilesDiagram smiles={rawCodeContent} />;
            case 'plot': return <InteractivePlot configStr={rawCodeContent} />;
            case 'physics': return <PhysicsSimulation configStr={rawCodeContent} />;
          }
        }
        return <code className={className} {...props}>{children}</code>;
    }
  }), [handleIDEUpdate, allNodes]);

  return (
    <div className="editor-container bg-[var(--bg-main)] text-[var(--text-main)]">
      <div className="editor-header bg-[var(--bg-toolbar)] border-[var(--border-color)]">
        {(viewMode !== 'preview' && !readOnly) && <EditorToolbar insertFormat={insertFormat} readOnly={readOnly} />}
      </div>
      <div className="split-container">
        {(viewMode === 'split' || viewMode === 'editor') && (
            <div className={`pane ${viewMode === 'split' ? 'half border-r' : 'full'}`}>
                <textarea 
                  ref={textareaRef} 
                  className="textarea" 
                  value={localContent} 
                  onChange={e => handleTextareaChange(e.target.value)} 
                  onBlur={persistToMarkdown}
                  placeholder="# Start typing..." 
                  spellCheck={false} 
                  disabled={readOnly} 
                />
            </div>
        )}
        {(viewMode === 'split' || viewMode === 'preview') && (
            <div id="markdown-preview" className={`pane ${viewMode === 'split' ? 'half' : 'full'} preview-area no-scrollbar`}>
                <div className="markdown-body">
                    <ReactMarkdown 
                        key={fileName} 
                        remarkPlugins={[remarkGfm, remarkMath]} 
                        rehypePlugins={[
                          rehypeRaw, 
                          [rehypeKatex, { 
                            trust: true, 
                            strict: false,
                            macros: { "\\ce": "\\text{#1}" } // Placeholder if needed, but mhchem script handles the heavy lifting
                          }], 
                          rehypeHighlight
                        ]}
                        components={markdownComponents}
                    >
                      {localContent}
                    </ReactMarkdown>
                </div>
            </div>
        )}
      </div>
    </div>
  );
};

import React, { useState, useEffect, useRef } from 'react';
import Editor from '@monaco-editor/react';
import { 
  Play, Maximize2, Minimize2, FileCode, Globe, Palette, 
  ExternalLink, RefreshCcw, Layout
} from 'lucide-react';

interface CodeEditorEngineProps {
  config: {
    js?: string;
    html?: string;
    css?: string;
    internal_block_id: string;
  };
  onUpdate: (newConfig: string) => void;
}

type Tab = 'js' | 'html' | 'css' | 'result';

export const CodeEditorEngine: React.FC<CodeEditorEngineProps> = ({ config, onUpdate }) => {
  const [activeTab, setActiveTab] = useState<Tab>('js');
  const [isFullscreen, setIsFullscreen] = useState(false);
  const [showPreview, setShowPreview] = useState(true);

  // Local state for the code to avoid unnecessary parent re-renders while typing
  const [jsCode, setJsCode] = useState(config.js || '');
  const [htmlCode, setHtmlCode] = useState(config.html || '');
  const [cssCode, setCssCode] = useState(config.css || '');

  const iframeRef = useRef<HTMLIFrameElement>(null);

  // Sync with prop changes (when switching files)
  useEffect(() => {
    setJsCode(config.js || '');
    setHtmlCode(config.html || '');
    setCssCode(config.css || '');
  }, [config.internal_block_id]);

  const runCode = () => {
    if (!iframeRef.current) return;

    const combinedHtml = `
      <!DOCTYPE html>
      <html>
        <head>
          <meta charset="utf-8">
          <style>${cssCode}</style>
        </head>
        <body>
          ${htmlCode}
          <script>
            (function() {
              const originalLog = console.log;
              console.log = function(...args) {
                originalLog.apply(console, args);
                window.parent.postMessage({ type: 'console', payload: args.join(' ') }, '*');
              };
              try {
                ${jsCode}
              } catch (err) {
                console.error(err);
              }
            })();
          </script>
        </body>
      </html>
    `;

    const blob = new Blob([combinedHtml], { type: 'text/html' });
    const url = URL.createObjectURL(blob);
    iframeRef.current.src = url;

    // Persist changes to parent
    const updatedConfig = JSON.stringify({
      js: jsCode,
      html: htmlCode,
      css: cssCode,
      internal_block_id: config.internal_block_id
    }, null, 2);
    onUpdate(updatedConfig);
  };

  useEffect(() => {
    if (activeTab === 'result' || showPreview) {
      const timer = setTimeout(runCode, 500);
      return () => clearTimeout(timer);
    }
  }, [activeTab, showPreview]);

  const TabButton = ({ id, label, icon: Icon }: { id: Tab, label: string, icon: any }) => (
    <button
      onClick={() => setActiveTab(id)}
      style={{
        padding: '0.4rem 0.75rem',
        fontSize: '0.75rem',
        fontWeight: 600,
        display: 'flex',
        alignItems: 'center',
        gap: '0.4rem',
        border: 'none',
        background: activeTab === id ? 'var(--bg-main)' : 'transparent',
        color: activeTab === id ? 'var(--accent-color)' : 'var(--text-muted)',
        borderBottom: activeTab === id ? '2px solid var(--accent-color)' : '2px solid transparent',
        cursor: 'pointer',
        transition: 'all 0.2s'
      }}
    >
      <Icon size={14} />
      {label}
    </button>
  );

  const containerStyle: React.CSSProperties = isFullscreen ? {
    position: 'fixed',
    top: 0,
    left: 0,
    width: '100vw',
    height: '100vh',
    zIndex: 9999,
    backgroundColor: 'var(--bg-main)',
    display: 'flex',
    flexDirection: 'column'
  } : {
    width: '100%',
    height: '500px',
    border: '1px solid var(--border-color)',
    borderRadius: '8px',
    overflow: 'hidden',
    display: 'flex',
    flexDirection: 'column',
    margin: '1rem 0',
    backgroundColor: 'var(--bg-sidebar)'
  };

  /**
   * Helper to get the current code based on activeTab.
   * Only called when activeTab is 'js' | 'html' | 'css'
   */
  const getCurrentCode = () => {
    if (activeTab === 'js') return jsCode;
    if (activeTab === 'html') return htmlCode;
    if (activeTab === 'css') return cssCode;
    return '';
  };

  return (
    <div style={containerStyle}>
      {/* Header Toolbar */}
      <div style={{ 
        height: '40px', 
        backgroundColor: '#1f2937', 
        display: 'flex', 
        alignItems: 'center', 
        justifyContent: 'space-between',
        padding: '0 0.5rem',
        borderBottom: '1px solid var(--border-color)'
      }}>
        <div style={{ display: 'flex', gap: '2px', height: '100%', alignItems: 'flex-end' }}>
          <TabButton id="js" label="JS" icon={FileCode} />
          <TabButton id="html" label="HTML" icon={Globe} />
          <TabButton id="css" label="CSS" icon={Palette} />
          <TabButton id="result" label="Result" icon={Layout} />
        </div>

        <div style={{ display: 'flex', alignItems: 'center', gap: '0.5rem' }}>
          <button 
            onClick={runCode}
            style={{
              padding: '0.3rem 0.8rem',
              borderRadius: '4px',
              backgroundColor: '#374151',
              color: '#fff',
              border: 'none',
              fontSize: '0.7rem',
              fontWeight: 'bold',
              display: 'flex',
              alignItems: 'center',
              gap: '0.4rem',
              cursor: 'pointer'
            }}
          >
            <Play size={12} fill="white" /> RUN
          </button>
          <button 
            onClick={() => setIsFullscreen(!isFullscreen)}
            style={{ background: 'transparent', border: 'none', color: '#9ca3af', cursor: 'pointer' }}
          >
            {isFullscreen ? <Minimize2 size={16} /> : <Maximize2 size={16} />}
          </button>
        </div>
      </div>

      {/* Editor/Result Area */}
      <div style={{ flex: 1, display: 'flex', overflow: 'hidden' }}>
        {/* Monaco Editor Pane - Rendered for js, html, and css tabs */}
        {/* Fix: Check explicitly for the code tabs to satisfy TypeScript type guards */}
        {(activeTab === 'js' || activeTab === 'html' || activeTab === 'css') && (
          <div style={{ flex: 1, height: '100%' }}>
            <Editor
              height="100%"
              theme="vs-dark"
              language={activeTab === 'js' ? 'javascript' : activeTab}
              value={getCurrentCode()}
              onChange={(val) => {
                if (activeTab === 'js') setJsCode(val || '');
                else if (activeTab === 'html') setHtmlCode(val || '');
                else if (activeTab === 'css') setCssCode(val || '');
              }}
              options={{
                minimap: { enabled: false },
                fontSize: 13,
                scrollBeyondLastLine: false,
                automaticLayout: true,
                padding: { top: 10 }
              }}
            />
          </div>
        )}

        {/* Result/Preview Pane */}
        {(activeTab === 'result' || (showPreview && activeTab !== 'result')) && (
          <div style={{ 
            flex: activeTab === 'result' ? 1 : 0.8, 
            height: '100%', 
            backgroundColor: '#fff',
            borderLeft: '1px solid var(--border-color)',
            display: 'flex',
            flexDirection: 'column'
          }}>
            <iframe
              ref={iframeRef}
              title="Preview"
              style={{ width: '100%', height: '100%', border: 'none' }}
              sandbox="allow-scripts"
            />
          </div>
        )}
      </div>
    </div>
  );
};

