            case 'physics': return <PhysicsSimulation configStr={codeContent} />;
          }
        }
        return <code className={className} {...props}>{children}</code>;
    },
    'model-viewer': ({node, ...props}: any) => React.createElement('model-viewer', props),
  }), [handleIDEUpdate]);

  const insertFormat = (prefix: string, suffix: string = '', blockMode: boolean = false) => {
    if (!textareaRef.current || readOnly) return;
    const { selectionStart: start, selectionEnd: end, value: text } = textareaRef.current;
    const selected = text.substring(start, end);
    let newText = '', newCursor = 0;
    if (blockMode) {
        const hasNewline = text.substring(0, start).endsWith('\n') || start === 0;
        newText = `${text.substring(0, start)}${hasNewline ? '' : '\n'}${prefix}${selected}${suffix}${text.substring(end)}`;
        newCursor = start + prefix.length + (hasNewline ? 0 : 1) + selected.length;
    } else {
        newText = `${text.substring(0, start)}${prefix}${selected}${suffix}${text.substring(end)}`;
        newCursor = start + prefix.length + selected.length;
    }
    onChange(newText);
    setTimeout(() => { textareaRef.current?.focus(); textareaRef.current?.setSelectionRange(newCursor, newCursor); }, 0);
  };

  const handleKeyDown = (e: React.KeyboardEvent<HTMLTextAreaElement>) => {
    if (e.key === 'Tab') {
      e.preventDefault();
      const { selectionStart: start, selectionEnd: end, value } = e.currentTarget;
      onChange(value.substring(0, start) + '  ' + value.substring(end));
      setTimeout(() => { if(textareaRef.current) textareaRef.current.selectionStart = textareaRef.current.selectionEnd = start + 2; }, 0);
    }
  };

  return (
    <div className="editor-container bg-[var(--bg-main)] text-[var(--text-main)]">
      <div className="editor-header bg-[var(--bg-toolbar)] border-[var(--border-color)]">
        {(viewMode !== 'preview' && !readOnly) && <EditorToolbar insertFormat={insertFormat} readOnly={readOnly} />}
      </div>

      <div className="split-container">
        {(viewMode === 'split' || viewMode === 'editor') && (
            <div className={`pane ${viewMode === 'split' ? 'half border-r' : 'full'}`}>
                <textarea 
                  ref={textareaRef} 
                  className="textarea" 
                  value={content} 
                  onChange={e => onChange(e.target.value)} 
                  onKeyDown={handleKeyDown}
                  onScroll={handleEditorScroll}
                  placeholder="# Start typing..." 
                  spellCheck={false} 
                  disabled={readOnly} 
                />
            </div>
        )}
        {(viewMode === 'split' || viewMode === 'preview') && (
            <div 
              ref={previewRef}
              onScroll={handlePreviewScroll}
              id="markdown-preview" 
              className={`pane ${viewMode === 'split' ? 'half' : 'full'} preview-area no-scrollbar`}
            >
                <div className="markdown-body">
                    <ReactMarkdown 
                        remarkPlugins={[remarkGfm, remarkMath]} 
                        rehypePlugins={[
                          rehypeRaw, 
                          rehypeHighlight,
                          [rehypeKatex, { trust: true, strict: false }]
                        ]}
                        components={markdownComponents}
                    >
                      {content}
                    </ReactMarkdown>
                </div>
            </div>
        )}
      </div>
    </div>
  );
};

import React, { useState, useEffect, useCallback, useMemo } from 'react';
import { v4 as uuidv4 } from 'uuid';
import { 
  Download, Upload, FileJson, Palette, PanelLeft, Edit3, Columns, Eye, X, FileText, Save, Plus
} from 'lucide-react';
import { Sidebar } from './components/Sidebar';
import { Editor } from './components/Editor';
import { FileNode, NodeType, AppTheme } from './types';
import { initialNodes } from './initialData';

const themes: Record<string, AppTheme> = {
  dark: { name: 'Dark', bgMain: '#030712', bgSidebar: '#111827', textMain: '#f3f4f6', textMuted: '#9ca3af', border: '#1f2937', accent: '#3b82f6', hover: 'rgba(255, 255, 255, 0.05)' },
  light: { name: 'Light', bgMain: '#ffffff', bgSidebar: '#f3f4f6', textMain: '#111827', textMuted: '#6b7280', border: '#e5e7eb', accent: '#3b82f6', hover: 'rgba(0, 0, 0, 0.05)' },
  navy: { name: 'Navy', bgMain: '#0a192f', bgSidebar: '#112240', textMain: '#ccd6f6', textMuted: '#8892b0', border: '#233554', accent: '#64ffda', hover: 'rgba(100, 255, 218, 0.1)' },
  dracula: { name: 'Dracula', bgMain: '#282a36', bgSidebar: '#21222c', textMain: '#f8f8f2', textMuted: '#6272a4', border: '#44475a', accent: '#ff79c6', hover: 'rgba(255, 255, 255, 0.1)' }
};

export default function App() {
  const [nodes, setNodes] = useState<FileNode[]>(() => {
    const saved = localStorage.getItem('mathsci-fs');
    return saved ? JSON.parse(saved) : initialNodes;
  });
  const [activeFileId, setActiveFileId] = useState<string | null>('file-intro');
  const [expandedFolders, setExpandedFolders] = useState<Set<string>>(new Set(['folder-welcome', 'folder-docs']));
  const [showSettings, setShowSettings] = useState(false);
  const [isSidebarOpen, setIsSidebarOpen] = useState(true);
  const [editorView, setEditorView] = useState<'split' | 'editor' | 'preview'>('split');
  const [currentTheme, setCurrentTheme] = useState<AppTheme>(() => {
    const saved = localStorage.getItem('mathsci-theme');
    return saved ? JSON.parse(saved) : themes.dark;
  });

  useEffect(() => {
    const root = document.documentElement;
    root.style.setProperty('--bg-main', currentTheme.bgMain);
    root.style.setProperty('--bg-sidebar', currentTheme.bgSidebar);
    root.style.setProperty('--bg-toolbar', currentTheme.bgSidebar);
    root.style.setProperty('--text-main', currentTheme.textMain);
    root.style.setProperty('--text-muted', currentTheme.textMuted);
    root.style.setProperty('--border-color', currentTheme.border);
    root.style.setProperty('--accent-color', currentTheme.accent);
    root.style.setProperty('--hover-bg', currentTheme.hover);
    localStorage.setItem('mathsci-theme', JSON.stringify(currentTheme));
  }, [currentTheme]);

  useEffect(() => {
    // Throttled persistence for 1000+ files
    const handler = setTimeout(() => {
      localStorage.setItem('mathsci-fs', JSON.stringify(nodes));
    }, 1000);
    return () => clearTimeout(handler);
  }, [nodes]);

  const deleteRecursive = useCallback((targetId: string, currentNodes: FileNode[]): string[] => {
    const idsToDelete: string[] = [targetId];
    const queue = [targetId];
    while (queue.length > 0) {
      const parentId = queue.shift();
      const children = currentNodes.filter(n => n.parentId === parentId);
      children.forEach(child => {
        idsToDelete.push(child.id);
        queue.push(child.id);
      });
    }
    return idsToDelete;
  }, []);

  const handleExportWorkspace = (format: 'json' | 'md') => {
    let content = '';
    let mimeType = '';
    let fileName = '';

    if (format === 'json') {
      content = JSON.stringify({ version: 1, nodes }, null, 2);
      mimeType = 'application/json';
      fileName = `workspace_backup_${new Date().toISOString().split('T')[0]}.json`;
    } else {
      // Optimized Bundled Markdown Export for 1000+ files
      const nodeMap = new Map<string | null, FileNode[]>();
      nodes.forEach(n => {
        const pId = n.parentId;
        if (!nodeMap.has(pId)) nodeMap.set(pId, []);
        nodeMap.get(pId)!.push(n);
      });

      const buildMarkdown = (parentId: string | null, depth: number): string => {
        let md = '';
        const items = nodeMap.get(parentId) || [];
        // Folders first, then alphabetically
        items.sort((a, b) => {
          if (a.type !== b.type) return a.type === NodeType.FOLDER ? -1 : 1;
          return a.name.localeCompare(b.name);
        });

        items.forEach(item => {
          const indent = '#'.repeat(Math.min(depth + 1, 6));
          if (item.type === NodeType.FOLDER) {
            md += `${indent} Folder: ${item.name}\n\n`;
            md += buildMarkdown(item.id, depth + 1);
          } else {
            md += `${indent} File: ${item.name}\n\n${item.content}\n\n---\n\n`;
          }
        });
        return md;
      };

      content = `# Workspace Export - ${new Date().toLocaleString()}\n\n${buildMarkdown(null, 0)}`;
      mimeType = 'text/markdown';
      fileName = `workspace_bundle_${nodes.length}_files.md`;
    }

    const blob = new Blob([content], { type: mimeType });
    const url = URL.createObjectURL(blob);
    const link = document.createElement('a');
    link.href = url;
    link.download = fileName;
    link.click();
    URL.revokeObjectURL(url);
  };

  const handleImportWorkspace = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;
    const reader = new FileReader();
    reader.onload = (event) => {
      try {
        const data = JSON.parse(event.target?.result as string);
        if (data.nodes && Array.isArray(data.nodes)) {
          setNodes(data.nodes);
          if (data.nodes.length > 0) {
            const firstFile = data.nodes.find((n: FileNode) => n.type === NodeType.FILE);
            setActiveFileId(firstFile ? firstFile.id : data.nodes[0].id);
          }
        }
      } catch (err) {
        alert("Failed to parse import file. Ensure it is a valid Workspace JSON.");
      }
    };
    reader.readAsText(file);
  };

  const activeFile = useMemo(() => nodes.find(n => n.id === activeFileId), [nodes, activeFileId]);

  return (
    <div className="app-container" style={{ background: 'var(--bg-main)' }}>
      <div className="sidebar-wrapper" style={{ width: isSidebarOpen ? '280px' : '0' }}>
         <Sidebar 
            nodes={nodes}
            activeFileId={activeFileId}
            expandedFolders={expandedFolders}
            onFileSelect={setActiveFileId}
            onToggleFolder={(id) => setExpandedFolders(prev => {
                const next = new Set(prev);
                if (next.has(id)) next.delete(id); else next.add(id);
                return next;
            })}
            onAddFile={(parentId) => {
                const id = uuidv4();
                const newNode: FileNode = { id, parentId, name: 'New File.md', type: NodeType.FILE, content: '', createdAt: Date.now() };
                setNodes(prev => [...prev, newNode]);
                setActiveFileId(id);
                if (parentId) setExpandedFolders(prev => new Set(prev).add(parentId));
            }}
            onAddFolder={(parentId) => {
                const id = uuidv4();
                setNodes(prev => [...prev, { id, parentId, name: 'New Folder', type: NodeType.FOLDER, content: '', createdAt: Date.now() }]);
                if (parentId) setExpandedFolders(prev => new Set(prev).add(parentId));
            }}
            onDeleteNode={(id) => {
                const idsToRemove = deleteRecursive(id, nodes);
                setNodes(prev => prev.filter(n => !idsToRemove.includes(n.id)));
                if (activeFileId && idsToRemove.includes(activeFileId)) setActiveFileId(null);
            }}
            onRenameNode={(id, name) => setNodes(prev => prev.map(n => n.id === id ? { ...n, name } : n))}
            onMoveNode={(id, parentId) => setNodes(prev => prev.map(n => n.id === id ? { ...n, parentId } : n))}
         />
      </div>

      <div className="main-content" style={{ flex: 1, display: 'flex', flexDirection: 'column', overflow: 'hidden' }}>
        <div className="toolbar">
            <div style={{ display: 'flex', alignItems: 'center', gap: '0.75rem' }}>
                <button onClick={() => setIsSidebarOpen(!isSidebarOpen)} className="btn-icon" title="Toggle Sidebar"><PanelLeft size={18} /></button>
                <h1 className="app-title" style={{ fontSize: '1rem' }}>MathSci <span style={{ opacity: 0.4, fontWeight: 'normal', fontSize: '0.75rem' }}>v2.0</span></h1>
            </div>
            <div style={{ display: 'flex', alignItems: 'center', gap: '0.5rem' }}>
                <button onClick={() => handleExportWorkspace('md')} className="btn" title="Bundle all files into one Markdown"><FileText size={14} /> Export Bundle</button>
                <button onClick={() => handleExportWorkspace('json')} className="btn" title="Backup Workspace JSON"><Download size={14} /> Backup</button>
                <label className="btn" style={{ cursor: 'pointer' }}>
                  <Upload size={14} /> Restore
                  <input type="file" onChange={handleImportWorkspace} style={{ display: 'none' }} accept=".json" />
                </label>
                <div className="divider"></div>
                <button onClick={() => setShowSettings(true)} className="btn"><Palette size={14} /> Theme</button>
                <div style={{ display: 'flex', background: 'var(--bg-main)', border: '1px solid var(--border-color)', borderRadius: '6px', padding: '2px', gap: '2px' }}>
                   <button onClick={() => setEditorView('editor')} className="btn-icon" style={{ color: editorView === 'editor' ? 'var(--accent-color)' : 'var(--text-muted)' }}><Edit3 size={16} /></button>
                   <button onClick={() => setEditorView('split')} className="btn-icon" style={{ color: editorView === 'split' ? 'var(--accent-color)' : 'var(--text-muted)' }}><Columns size={16} /></button>
                   <button onClick={() => setEditorView('preview')} className="btn-icon" style={{ color: editorView === 'preview' ? 'var(--accent-color)' : 'var(--text-muted)' }}><Eye size={16} /></button>
                </div>
            </div>
        </div>

        <div style={{ flex: 1, overflow: 'hidden' }}>
            {activeFile ? (
                // Fixed: Removed 'allNodes' prop as it is not defined in EditorProps
                <Editor 
                  content={activeFile.content} 
                  fileName={activeFile.name}
                  viewMode={editorView}
                  onChange={(content) => setNodes(prev => prev.map(n => n.id === activeFileId ? { ...n, content } : n))} 
                />
            ) : (
              <div style={{ height: '100%', display: 'flex', alignItems: 'center', justifyContent: 'center', color: 'var(--text-muted)', flexDirection: 'column', gap: '1.5rem', textAlign: 'center' }}>
                  <div style={{ position: 'relative' }}>
                    <FileText size={64} style={{ opacity: 0.1 }} />
                    <Plus size={24} style={{ position: 'absolute', bottom: -5, right: -5, opacity: 0.3 }} />
                  </div>
                  <div>
                    <p style={{ fontSize: '1.1rem', marginBottom: '0.5rem' }}>Workspace ready</p>
                    <p style={{ fontSize: '0.85rem', opacity: 0.6 }}>{nodes.length} items in file system. Select a file to edit.</p>
                  </div>
                  <button onClick={() => {
                     const id = uuidv4();
                     setNodes(prev => [...prev, { id, parentId: null, name: 'Untitled.md', type: NodeType.FILE, content: '', createdAt: Date.now() }]);
                     setActiveFileId(id);
                  }} className="btn btn-primary" style={{ padding: '0.5rem 1.5rem' }}>Create New File</button>
              </div>
            )}
        </div>
      </div>

      {showSettings && (
          <div className="modal-overlay" onClick={() => setShowSettings(false)}>
              <div className="modal" onClick={e => e.stopPropagation()} style={{ maxWidth: '420px', background: '#0a0f1d', color: '#f8fafc', border: '1px solid #1e293b', padding: '1.5rem' }}>
                  <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: '2rem' }}>
                      <div style={{ display: 'flex', alignItems: 'center', gap: '0.75rem' }}>
                        <Palette size={20} color="#3b82f6" />
                        <span style={{ fontSize: '1.125rem', fontWeight: 600 }}>Theme Settings</span>
                      </div>
                      <button onClick={() => setShowSettings(false)} className="btn-icon"><X size={20}/></button>
                  </div>
                  <div style={{ marginBottom: '2rem' }}>
                    <label style={{ fontSize: '0.85rem', color: '#94a3b8', marginBottom: '1rem', display: 'block' }}>Select Look & Feel</label>
                    <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: '0.75rem' }}>
                        {Object.entries(themes).map(([k, t]) => (
                            <button key={k} onClick={() => setCurrentTheme(t)} style={{ padding: '0.75rem', borderRadius: '8px', background: t.bgMain, color: t.textMain, border: `1px solid ${currentTheme.name === t.name ? 'var(--accent-color)' : '#1e293b'}`, cursor: 'pointer', display: 'flex', alignItems: 'center', gap: '0.5rem', fontSize: '0.9rem', transition: 'all 0.2s' }}>
                                <div style={{ width: 12, height: 12, borderRadius: '50%', background: t.accent }} />
                                {t.name}
                            </button>
                        ))}
                    </div>
                  </div>
                  <button onClick={() => setShowSettings(false)} className="btn-primary" style={{ width: '100%', padding: '0.75rem', borderRadius: '8px', border: 'none', fontWeight: 600, cursor: 'pointer' }}>Apply Changes</button>
              </div>
          </div>
      )}
    </div>
  );
}

import React, { useState, useEffect, useRef } from 'react';
import Editor from '@monaco-editor/react';
import { 
  Play, Maximize2, Minimize2, FileCode, Globe, Palette, 
  ExternalLink, RefreshCcw, Layout
} from 'lucide-react';

interface CodeEditorEngineProps {
  config: {
    js?: string;
    html?: string;
    css?: string;
    internal_block_id: string;
  };
  onUpdate: (newConfig: string) => void;
}

type Tab = 'js' | 'html' | 'css' | 'result';

export const CodeEditorEngine: React.FC<CodeEditorEngineProps> = ({ config, onUpdate }) => {
  const [activeTab, setActiveTab] = useState<Tab>('js');
  const [isFullscreen, setIsFullscreen] = useState(false);
  const [showPreview, setShowPreview] = useState(true);

  // Local state for the code to avoid unnecessary parent re-renders while typing
  const [jsCode, setJsCode] = useState(config.js || '');
  const [htmlCode, setHtmlCode] = useState(config.html || '');
  const [cssCode, setCssCode] = useState(config.css || '');

  const iframeRef = useRef<HTMLIFrameElement>(null);

  // Sync with prop changes (when switching files)
  useEffect(() => {
    setJsCode(config.js || '');
    setHtmlCode(config.html || '');
    setCssCode(config.css || '');
  }, [config.internal_block_id]);

  const runCode = () => {
    if (!iframeRef.current) return;

    const combinedHtml = `
      <!DOCTYPE html>
      <html>
        <head>
          <meta charset="utf-8">
          <style>${cssCode}</style>
        </head>
        <body>
          ${htmlCode}
          <script>
            (function() {
              const originalLog = console.log;
              console.log = function(...args) {
                originalLog.apply(console, args);
                window.parent.postMessage({ type: 'console', payload: args.join(' ') }, '*');
              };
              try {
                ${jsCode}
              } catch (err) {
                console.error(err);
              }
            })();
          </script>
        </body>
      </html>
    `;

    const blob = new Blob([combinedHtml], { type: 'text/html' });
    const url = URL.createObjectURL(blob);
    iframeRef.current.src = url;

    // Persist changes to parent
    const updatedConfig = JSON.stringify({
      js: jsCode,
      html: htmlCode,
      css: cssCode,
      internal_block_id: config.internal_block_id
    }, null, 2);
    onUpdate(updatedConfig);
  };

  useEffect(() => {
    if (activeTab === 'result' || showPreview) {
      const timer = setTimeout(runCode, 500);
      return () => clearTimeout(timer);
    }
  }, [activeTab, showPreview]);

  const TabButton = ({ id, label, icon: Icon }: { id: Tab, label: string, icon: any }) => (
    <button
      onClick={() => setActiveTab(id)}
      style={{
        padding: '0.4rem 0.75rem',
        fontSize: '0.75rem',
        fontWeight: 600,
        display: 'flex',
        alignItems: 'center',
        gap: '0.4rem',
        border: 'none',
        background: activeTab === id ? 'var(--bg-main)' : 'transparent',
        color: activeTab === id ? 'var(--accent-color)' : 'var(--text-muted)',
        borderBottom: activeTab === id ? '2px solid var(--accent-color)' : '2px solid transparent',
        cursor: 'pointer',
        transition: 'all 0.2s'
      }}
    >
      <Icon size={14} />
      {label}
    </button>
  );

  const containerStyle: React.CSSProperties = isFullscreen ? {
    position: 'fixed',
    top: 0,
    left: 0,
    width: '100vw',
    height: '100vh',
    zIndex: 9999,
    backgroundColor: 'var(--bg-main)',
    display: 'flex',
    flexDirection: 'column'
  } : {
    width: '100%',
    height: '500px',
    border: '1px solid var(--border-color)',
    borderRadius: '8px',
    overflow: 'hidden',
    display: 'flex',
    flexDirection: 'column',
    margin: '1rem 0',
    backgroundColor: 'var(--bg-sidebar)'
  };

  /**
   * Helper to get the current code based on activeTab.
   * Only called when activeTab is 'js' | 'html' | 'css'
   */
  const getCurrentCode = () => {
    if (activeTab === 'js') return jsCode;
    if (activeTab === 'html') return htmlCode;
    if (activeTab === 'css') return cssCode;
    return '';
  };

  return (
    <div style={containerStyle}>
      {/* Header Toolbar */}
      <div style={{ 
        height: '40px', 
        backgroundColor: '#1f2937', 
        display: 'flex', 
        alignItems: 'center', 
        justifyContent: 'space-between',
        padding: '0 0.5rem',
        borderBottom: '1px solid var(--border-color)'
      }}>
        <div style={{ display: 'flex', gap: '2px', height: '100%', alignItems: 'flex-end' }}>
          <TabButton id="js" label="JS" icon={FileCode} />
          <TabButton id="html" label="HTML" icon={Globe} />
          <TabButton id="css" label="CSS" icon={Palette} />
          <TabButton id="result" label="Result" icon={Layout} />
        </div>

        <div style={{ display: 'flex', alignItems: 'center', gap: '0.5rem' }}>
          <button 
            onClick={runCode}
            style={{
              padding: '0.3rem 0.8rem',
              borderRadius: '4px',
              backgroundColor: '#374151',
              color: '#fff',
              border: 'none',
              fontSize: '0.7rem',
              fontWeight: 'bold',
              display: 'flex',
              alignItems: 'center',
              gap: '0.4rem',
              cursor: 'pointer'
            }}
          >
            <Play size={12} fill="white" /> RUN
          </button>
          <button 
            onClick={() => setIsFullscreen(!isFullscreen)}
            style={{ background: 'transparent', border: 'none', color: '#9ca3af', cursor: 'pointer' }}
          >
            {isFullscreen ? <Minimize2 size={16} /> : <Maximize2 size={16} />}
          </button>
        </div>
      </div>

      {/* Editor/Result Area */}
      <div style={{ flex: 1, display: 'flex', overflow: 'hidden' }}>
        {/* Monaco Editor Pane - Rendered for js, html, and css tabs */}
        {/* Fix: Widened comparison type check to avoid "no overlap" error while keeping logic for code tabs */}
        {(activeTab as string) !== 'result' && (
          <div style={{ flex: 1, height: '100%' }}>
            <Editor
              height="100%"
              theme="vs-dark"
              language={activeTab === 'js' ? 'javascript' : (activeTab as string)}
              value={getCurrentCode()}
              onChange={(val) => {
                if (activeTab === 'js') setJsCode(val || '');
                else if (activeTab === 'html') setHtmlCode(val || '');
                else if (activeTab === 'css') setCssCode(val || '');
              }}
              options={{
                minimap: { enabled: false },
                fontSize: 13,
                scrollBeyondLastLine: false,
                automaticLayout: true,
                padding: { top: 10 }
              }}
            />
          </div>
        )}

        {/* Result/Preview Pane */}
        {(activeTab === 'result' || (showPreview && activeTab !== 'result')) && (
          <div style={{ 
            flex: activeTab === 'result' ? 1 : 0.8, 
            height: '100%', 
            backgroundColor: '#fff',
            borderLeft: '1px solid var(--border-color)',
            display: 'flex',
            flexDirection: 'column'
          }}>
            <iframe
              ref={iframeRef}
              title="Preview"
              style={{ width: '100%', height: '100%', border: 'none' }}
              sandbox="allow-scripts"
            />
          </div>
        )}
      </div>
    </div>
  );
};

import React, { useState, useEffect, useCallback, useMemo } from 'react';
import { v4 as uuidv4 } from 'uuid';
import { 
  Download, Upload, FileJson, Palette, PanelLeft, Edit3, Columns, Eye, X, FileText, Save, Plus
} from 'lucide-react';
import { Sidebar } from './components/Sidebar';
import { Editor } from './components/Editor';
import { FileNode, NodeType, AppTheme } from './types';
import { initialNodes } from './initialData';

const themes: Record<string, AppTheme> = {
  dark: { name: 'Dark', bgMain: '#030712', bgSidebar: '#111827', textMain: '#f3f4f6', textMuted: '#9ca3af', border: '#1f2937', accent: '#3b82f6', hover: 'rgba(255, 255, 255, 0.05)' },
  light: { name: 'Light', bgMain: '#ffffff', bgSidebar: '#f3f4f6', textMain: '#111827', textMuted: '#6b7280', border: '#e5e7eb', accent: '#3b82f6', hover: 'rgba(0, 0, 0, 0.05)' },
  navy: { name: 'Navy', bgMain: '#0a192f', bgSidebar: '#112240', textMain: '#ccd6f6', textMuted: '#8892b0', border: '#233554', accent: '#64ffda', hover: 'rgba(100, 255, 218, 0.1)' },
  dracula: { name: 'Dracula', bgMain: '#282a36', bgSidebar: '#21222c', textMain: '#f8f8f2', textMuted: '#6272a4', border: '#44475a', accent: '#ff79c6', hover: 'rgba(255, 255, 255, 0.1)' }
};

export default function App() {
  const [nodes, setNodes] = useState<FileNode[]>(() => {
    const saved = localStorage.getItem('mathsci-fs');
    return saved ? JSON.parse(saved) : initialNodes;
  });
  const [activeFileId, setActiveFileId] = useState<string | null>('file-intro');
  const [expandedFolders, setExpandedFolders] = useState<Set<string>>(new Set(['folder-welcome', 'folder-docs']));
  const [showSettings, setShowSettings] = useState(false);
  const [isSidebarOpen, setIsSidebarOpen] = useState(true);
  const [editorView, setEditorView] = useState<'split' | 'editor' | 'preview'>('split');
  const [currentTheme, setCurrentTheme] = useState<AppTheme>(() => {
    const saved = localStorage.getItem('mathsci-theme');
    return saved ? JSON.parse(saved) : themes.dark;
  });

  useEffect(() => {
    const root = document.documentElement;
    root.style.setProperty('--bg-main', currentTheme.bgMain);
    root.style.setProperty('--bg-sidebar', currentTheme.bgSidebar);
    root.style.setProperty('--bg-toolbar', currentTheme.bgSidebar);
    root.style.setProperty('--text-main', currentTheme.textMain);
    root.style.setProperty('--text-muted', currentTheme.textMuted);
    root.style.setProperty('--border-color', currentTheme.border);
    root.style.setProperty('--accent-color', currentTheme.accent);
    root.style.setProperty('--hover-bg', currentTheme.hover);
    localStorage.setItem('mathsci-theme', JSON.stringify(currentTheme));
  }, [currentTheme]);

  useEffect(() => {
    const handler = setTimeout(() => {
      localStorage.setItem('mathsci-fs', JSON.stringify(nodes));
    }, 1000);
    return () => clearTimeout(handler);
  }, [nodes]);

  const deleteRecursive = useCallback((targetId: string, currentNodes: FileNode[]): string[] => {
    const idsToDelete: string[] = [targetId];
    const queue = [targetId];
    while (queue.length > 0) {
      const parentId = queue.shift();
      const children = currentNodes.filter(n => n.parentId === parentId);
      children.forEach(child => {
        idsToDelete.push(child.id);
        queue.push(child.id);
      });
    }
    return idsToDelete;
  }, []);

  const handleExportWorkspace = (format: 'json' | 'md') => {
    let content = '';
    let mimeType = '';
    let fileName = '';

    if (format === 'json') {
      content = JSON.stringify({ version: 1, nodes }, null, 2);
      mimeType = 'application/json';
      fileName = `workspace_backup_${new Date().toISOString().split('T')[0]}.json`;
    } else {
      const nodeMap = new Map<string | null, FileNode[]>();
      nodes.forEach(n => {
        const pId = n.parentId;
        if (!nodeMap.has(pId)) nodeMap.set(pId, []);
        nodeMap.get(pId)!.push(n);
      });

      const buildMarkdown = (parentId: string | null, depth: number): string => {
        let md = '';
        const items = nodeMap.get(parentId) || [];
        items.sort((a, b) => {
          if (a.type !== b.type) return a.type === NodeType.FOLDER ? -1 : 1;
          return a.name.localeCompare(b.name);
        });

        items.forEach(item => {
          const indent = '#'.repeat(Math.min(depth + 1, 6));
          if (item.type === NodeType.FOLDER) {
            md += `${indent} Folder: ${item.name}\n\n`;
            md += buildMarkdown(item.id, depth + 1);
          } else {
            md += `${indent} File: ${item.name}\n\n${item.content}\n\n---\n\n`;
          }
        });
        return md;
      };

      content = `# Workspace Export - ${new Date().toLocaleString()}\n\n${buildMarkdown(null, 0)}`;
      mimeType = 'text/markdown';
      fileName = `workspace_bundle_${nodes.length}_files.md`;
    }

    const blob = new Blob([content], { type: mimeType });
    const url = URL.createObjectURL(blob);
    const link = document.createElement('a');
    link.href = url;
    link.download = fileName;
    link.click();
    URL.revokeObjectURL(url);
  };

  const handleImportWorkspace = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;
    const reader = new FileReader();
    reader.onload = (event) => {
      try {
        const data = JSON.parse(event.target?.result as string);
        if (data.nodes && Array.isArray(data.nodes)) {
          setNodes(data.nodes);
          if (data.nodes.length > 0) {
            const firstFile = data.nodes.find((n: FileNode) => n.type === NodeType.FILE);
            setActiveFileId(firstFile ? firstFile.id : data.nodes[0].id);
          }
        }
      } catch (err) {
        alert("Failed to parse import file.");
      }
    };
    reader.readAsText(file);
  };

  const activeFile = useMemo(() => nodes.find(n => n.id === activeFileId), [nodes, activeFileId]);

  const updateCustomColor = (key: keyof AppTheme, value: string) => {
    setCurrentTheme(prev => ({
      ...prev,
      name: 'Custom',
      [key]: value
    }));
  };

  const CustomColorRow = ({ label, value, themeKey }: { label: string, value: string, themeKey: keyof AppTheme }) => (
    <div style={{ display: 'flex', alignItems: 'center', justifyContent: 'space-between', marginBottom: '1.25rem' }}>
      <span style={{ fontSize: '0.9rem', color: '#f3f4f6', fontWeight: 500 }}>{label}</span>
      <div style={{ display: 'flex', alignItems: 'center', gap: '0.75rem' }}>
        <span style={{ fontFamily: 'monospace', fontSize: '0.75rem', color: '#94a3b8' }}>{value.toUpperCase()}</span>
        <div style={{ position: 'relative', width: '32px', height: '24px', borderRadius: '4px', background: value, border: '1px solid rgba(255,255,255,0.1)', cursor: 'pointer' }}>
          <input 
            type="color" 
            value={value} 
            onChange={(e) => updateCustomColor(themeKey, e.target.value)}
            style={{ position: 'absolute', inset: 0, opacity: 0, width: '100%', height: '100%', cursor: 'pointer' }}
          />
        </div>
      </div>
    </div>
  );

  return (
    <div className="app-container" style={{ background: 'var(--bg-main)' }}>
      <div className="sidebar-wrapper" style={{ width: isSidebarOpen ? '280px' : '0' }}>
         <Sidebar 
            nodes={nodes}
            activeFileId={activeFileId}
            expandedFolders={expandedFolders}
            onFileSelect={setActiveFileId}
            onToggleFolder={(id) => setExpandedFolders(prev => {
                const next = new Set(prev);
                if (next.has(id)) next.delete(id); else next.add(id);
                return next;
            })}
            onAddFile={(parentId) => {
                const id = uuidv4();
                const newNode: FileNode = { id, parentId, name: 'New File.md', type: NodeType.FILE, content: '', createdAt: Date.now() };
                setNodes(prev => [...prev, newNode]);
                setActiveFileId(id);
                if (parentId) setExpandedFolders(prev => new Set(prev).add(parentId));
            }}
            onAddFolder={(parentId) => {
                const id = uuidv4();
                setNodes(prev => [...prev, { id, parentId, name: 'New Folder', type: NodeType.FOLDER, content: '', createdAt: Date.now() }]);
                if (parentId) setExpandedFolders(prev => new Set(prev).add(parentId));
            }}
            onDeleteNode={(id) => {
                const idsToRemove = deleteRecursive(id, nodes);
                setNodes(prev => prev.filter(n => !idsToRemove.includes(n.id)));
                if (activeFileId && idsToRemove.includes(activeFileId)) setActiveFileId(null);
            }}
            onRenameNode={(id, name) => setNodes(prev => prev.map(n => n.id === id ? { ...n, name } : n))}
            onMoveNode={(id, parentId) => setNodes(prev => prev.map(n => n.id === id ? { ...n, parentId } : n))}
         />
      </div>

      <div className="main-content" style={{ flex: 1, display: 'flex', flexDirection: 'column', overflow: 'hidden' }}>
        <div className="toolbar">
            <div style={{ display: 'flex', alignItems: 'center', gap: '0.75rem' }}>
                <button onClick={() => setIsSidebarOpen(!isSidebarOpen)} className="btn-icon" title="Toggle Sidebar"><PanelLeft size={18} /></button>
                <h1 className="app-title" style={{ fontSize: '1rem' }}>MathSci <span style={{ opacity: 0.4, fontWeight: 'normal', fontSize: '0.75rem' }}>v2.0</span></h1>
            </div>
            <div style={{ display: 'flex', alignItems: 'center', gap: '0.5rem' }}>
                <button onClick={() => handleExportWorkspace('md')} className="btn" title="Bundle all files into one Markdown"><FileText size={14} /> Export Bundle</button>
                <button onClick={() => handleExportWorkspace('json')} className="btn" title="Backup Workspace JSON"><Download size={14} /> Backup</button>
                <label className="btn" style={{ cursor: 'pointer' }}>
                  <Upload size={14} /> Restore
                  <input type="file" onChange={handleImportWorkspace} style={{ display: 'none' }} accept=".json" />
                </label>
                <div className="divider"></div>
                <button onClick={() => setShowSettings(true)} className="btn"><Palette size={14} /> Theme</button>
                <div style={{ display: 'flex', background: 'var(--bg-main)', border: '1px solid var(--border-color)', borderRadius: '6px', padding: '2px', gap: '2px' }}>
                   <button onClick={() => setEditorView('editor')} className="btn-icon" style={{ color: editorView === 'editor' ? 'var(--accent-color)' : 'var(--text-muted)' }}><Edit3 size={16} /></button>
                   <button onClick={() => setEditorView('split')} className="btn-icon" style={{ color: editorView === 'split' ? 'var(--accent-color)' : 'var(--text-muted)' }}><Columns size={16} /></button>
                   <button onClick={() => setEditorView('preview')} className="btn-icon" style={{ color: editorView === 'preview' ? 'var(--accent-color)' : 'var(--text-muted)' }}><Eye size={16} /></button>
                </div>
            </div>
        </div>

        <div style={{ flex: 1, overflow: 'hidden' }}>
            {activeFile ? (
                <Editor 
                  content={activeFile.content} 
                  fileName={activeFile.name}
                  viewMode={editorView}
                  onChange={(content) => setNodes(prev => prev.map(n => n.id === activeFileId ? { ...n, content } : n))} 
                />
            ) : (
              <div style={{ height: '100%', display: 'flex', alignItems: 'center', justifyContent: 'center', color: 'var(--text-muted)', flexDirection: 'column', gap: '1.5rem', textAlign: 'center' }}>
                  <div style={{ position: 'relative' }}>
                    <FileText size={64} style={{ opacity: 0.1 }} />
                    <Plus size={24} style={{ position: 'absolute', bottom: -5, right: -5, opacity: 0.3 }} />
                  </div>
                  <div>
                    <p style={{ fontSize: '1.1rem', marginBottom: '0.5rem' }}>Workspace ready</p>
                    <p style={{ fontSize: '0.85rem', opacity: 0.6 }}>{nodes.length} items in file system. Select a file to edit.</p>
                  </div>
                  <button onClick={() => {
                     const id = uuidv4();
                     setNodes(prev => [...prev, { id, parentId: null, name: 'Untitled.md', type: NodeType.FILE, content: '', createdAt: Date.now() }]);
                     setActiveFileId(id);
                  }} className="btn btn-primary" style={{ padding: '0.5rem 1.5rem' }}>Create New File</button>
              </div>
            )}
        </div>
      </div>

      {showSettings && (
          <div className="modal-overlay" onClick={() => setShowSettings(false)}>
              <div className="modal" onClick={e => e.stopPropagation()} style={{ width: '400px', background: '#0a0f1d', color: '#f8fafc', border: '1px solid #1e293b', padding: '1.25rem', borderRadius: '12px', boxShadow: '0 20px 25px -5px rgba(0,0,0,0.5)' }}>
                  {/* Modal Header */}
                  <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: '1.5rem' }}>
                      <div style={{ display: 'flex', alignItems: 'center', gap: '0.75rem' }}>
                        <Palette size={20} color="#3b82f6" />
                        <span style={{ fontSize: '1rem', fontWeight: 600 }}>Theme Settings</span>
                      </div>
                      <button onClick={() => setShowSettings(false)} className="btn-icon" style={{ opacity: 0.7 }}><X size={20}/></button>
                  </div>

                  {/* Presets Section */}
                  <div style={{ marginBottom: '1.5rem' }}>
                    <label style={{ fontSize: '0.75rem', color: '#94a3b8', marginBottom: '0.75rem', display: 'block', textTransform: 'none' }}>Presets</label>
                    <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: '0.75rem' }}>
                        {Object.entries(themes).map(([k, t]) => (
                            <button 
                              key={k} 
                              onClick={() => setCurrentTheme(t)} 
                              style={{ 
                                padding: '0.75rem', 
                                borderRadius: '8px', 
                                background: t.bgMain === '#ffffff' ? '#ffffff' : '#111827', 
                                color: t.bgMain === '#ffffff' ? '#111827' : '#f3f4f6', 
                                border: `1px solid ${currentTheme.name === t.name ? '#3b82f6' : 'rgba(255,255,255,0.05)'}`, 
                                cursor: 'pointer', 
                                display: 'flex', 
                                alignItems: 'center', 
                                gap: '0.75rem', 
                                fontSize: '0.85rem', 
                                transition: 'all 0.2s' 
                              }}
                            >
                                <div style={{ width: 10, height: 10, borderRadius: '50%', background: t.accent }} />
                                {t.name}
                            </button>
                        ))}
                    </div>
                  </div>

                  {/* Custom Colors Section */}
                  <div style={{ marginBottom: '1.5rem' }}>
                    <label style={{ fontSize: '0.75rem', color: '#94a3b8', marginBottom: '1rem', display: 'block' }}>Custom Colors</label>
                    <CustomColorRow label="Main Background" value={currentTheme.bgMain} themeKey="bgMain" />
                    <CustomColorRow label="Sidebar Background" value={currentTheme.bgSidebar} themeKey="bgSidebar" />
                    <CustomColorRow label="Text Color" value={currentTheme.textMain} themeKey="textMain" />
                    <CustomColorRow label="Accent Color" value={currentTheme.accent} themeKey="accent" />
                  </div>

                  {/* Divider */}
                  <div style={{ height: '1px', background: 'rgba(255,255,255,0.05)', margin: '1.25rem 0' }} />

                  {/* Action Button */}
                  <button 
                    onClick={() => setShowSettings(false)} 
                    className="btn-primary" 
                    style={{ 
                      width: '100%', 
                      padding: '0.65rem', 
                      borderRadius: '8px', 
                      border: 'none', 
                      fontWeight: 600, 
                      cursor: 'pointer',
                      fontSize: '0.875rem',
                      display: 'flex',
                      justifyContent: 'center'
                    }}
                  >
                    Done
                  </button>
              </div>
          </div>
      )}
    </div>
  );
}

import React, { useState, useEffect, useCallback, useMemo } from 'react';
import { v4 as uuidv4 } from 'uuid';
import { 
  Download, Upload, FileJson, Palette, PanelLeft, Edit3, Columns, Eye, X, FileText, Save, Plus
} from 'lucide-react';
import { Sidebar } from './components/Sidebar';
import { Editor } from './components/Editor';
import { FileNode, NodeType, AppTheme } from './types';
import { initialNodes } from './initialData';

const themes: Record<string, AppTheme> = {
  dark: { name: 'Dark', bgMain: '#030712', bgSidebar: '#111827', textMain: '#f3f4f6', textMuted: '#9ca3af', border: '#1f2937', accent: '#3b82f6', hover: 'rgba(255, 255, 255, 0.05)' },
  light: { name: 'Light', bgMain: '#ffffff', bgSidebar: '#f3f4f6', textMain: '#111827', textMuted: '#6b7280', border: '#e5e7eb', accent: '#3b82f6', hover: 'rgba(0, 0, 0, 0.05)' },
  navy: { name: 'Navy', bgMain: '#0a192f', bgSidebar: '#112240', textMain: '#ccd6f6', textMuted: '#8892b0', border: '#233554', accent: '#64ffda', hover: 'rgba(100, 255, 218, 0.1)' },
  dracula: { name: 'Dracula', bgMain: '#282a36', bgSidebar: '#21222c', textMain: '#f8f8f2', textMuted: '#6272a4', border: '#44475a', accent: '#ff79c6', hover: 'rgba(255, 255, 255, 0.1)' }
};

export default function App() {
  const [nodes, setNodes] = useState<FileNode[]>(() => {
    const saved = localStorage.getItem('mathsci-fs');
    return saved ? JSON.parse(saved) : initialNodes;
  });
  const [activeFileId, setActiveFileId] = useState<string | null>('file-intro');
  const [expandedFolders, setExpandedFolders] = useState<Set<string>>(new Set(['folder-welcome', 'folder-docs']));
  const [showSettings, setShowSettings] = useState(false);
  const [isSidebarOpen, setIsSidebarOpen] = useState(true);
  const [editorView, setEditorView] = useState<'split' | 'editor' | 'preview'>('split');
  const [currentTheme, setCurrentTheme] = useState<AppTheme>(() => {
    const saved = localStorage.getItem('mathsci-theme');
    return saved ? JSON.parse(saved) : themes.dark;
  });

  useEffect(() => {
    const root = document.documentElement;
    root.style.setProperty('--bg-main', currentTheme.bgMain);
    root.style.setProperty('--bg-sidebar', currentTheme.bgSidebar);
    root.style.setProperty('--bg-toolbar', currentTheme.bgSidebar);
    root.style.setProperty('--text-main', currentTheme.textMain);
    root.style.setProperty('--text-muted', currentTheme.textMuted);
    root.style.setProperty('--border-color', currentTheme.border);
    root.style.setProperty('--accent-color', currentTheme.accent);
    root.style.setProperty('--hover-bg', currentTheme.hover);
    localStorage.setItem('mathsci-theme', JSON.stringify(currentTheme));
  }, [currentTheme]);

  useEffect(() => {
    const handler = setTimeout(() => {
      localStorage.setItem('mathsci-fs', JSON.stringify(nodes));
    }, 1000);
    return () => clearTimeout(handler);
  }, [nodes]);

  const deleteRecursive = useCallback((targetId: string, currentNodes: FileNode[]): string[] => {
    const idsToDelete: string[] = [targetId];
    const queue = [targetId];
    while (queue.length > 0) {
      const parentId = queue.shift();
      const children = currentNodes.filter(n => n.parentId === parentId);
      children.forEach(child => {
        idsToDelete.push(child.id);
        queue.push(child.id);
      });
    }
    return idsToDelete;
  }, []);

  const handleExportWorkspace = (format: 'json' | 'md') => {
    let content = '';
    let mimeType = '';
    let fileName = '';

    if (format === 'json') {
      content = JSON.stringify({ version: 1, nodes }, null, 2);
      mimeType = 'application/json';
      fileName = `workspace_backup_${new Date().toISOString().split('T')[0]}.json`;
    } else {
      const nodeMap = new Map<string | null, FileNode[]>();
      nodes.forEach(n => {
        const pId = n.parentId;
        if (!nodeMap.has(pId)) nodeMap.set(pId, []);
        nodeMap.get(pId)!.push(n);
      });

      const buildMarkdown = (parentId: string | null, depth: number): string => {
        let md = '';
        const items = nodeMap.get(parentId) || [];
        items.sort((a, b) => {
          if (a.type !== b.type) return a.type === NodeType.FOLDER ? -1 : 1;
          return a.name.localeCompare(b.name);
        });

        items.forEach(item => {
          const indent = '#'.repeat(Math.min(depth + 1, 6));
          if (item.type === NodeType.FOLDER) {
            md += `${indent} Folder: ${item.name}\n\n`;
            md += buildMarkdown(item.id, depth + 1);
          } else {
            md += `${indent} File: ${item.name}\n\n${item.content}\n\n---\n\n`;
          }
        });
        return md;
      };

      content = `# Workspace Export - ${new Date().toLocaleString()}\n\n${buildMarkdown(null, 0)}`;
      mimeType = 'text/markdown';
      fileName = `workspace_bundle_${nodes.length}_files.md`;
    }

    const blob = new Blob([content], { type: mimeType });
    const url = URL.createObjectURL(blob);
    const link = document.createElement('a');
    link.href = url;
    link.download = fileName;
    link.click();
    URL.revokeObjectURL(url);
  };

  const handleImportWorkspace = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;
    const reader = new FileReader();
    reader.onload = (event) => {
      try {
        const data = JSON.parse(event.target?.result as string);
        if (data.nodes && Array.isArray(data.nodes)) {
          setNodes(data.nodes);
          if (data.nodes.length > 0) {
            const firstFile = data.nodes.find((n: FileNode) => n.type === NodeType.FILE);
            setActiveFileId(firstFile ? firstFile.id : data.nodes[0].id);
          }
        }
      } catch (err) {
        alert("Failed to parse import file.");
      }
    };
    reader.readAsText(file);
  };

  const activeFile = useMemo(() => nodes.find(n => n.id === activeFileId), [nodes, activeFileId]);

  const updateCustomColor = (key: keyof AppTheme, value: string) => {
    setCurrentTheme(prev => ({
      ...prev,
      name: 'Custom',
      [key]: value
    }));
  };

  const CustomColorRow = ({ label, value, themeKey }: { label: string, value: string, themeKey: keyof AppTheme }) => (
    <div style={{ display: 'flex', alignItems: 'center', justifyContent: 'space-between', marginBottom: '1.25rem' }}>
      <span style={{ fontSize: '0.9rem', color: '#f3f4f6', fontWeight: 500 }}>{label}</span>
      <div style={{ display: 'flex', alignItems: 'center', gap: '0.75rem' }}>
        <span style={{ fontFamily: 'monospace', fontSize: '0.75rem', color: '#94a3b8' }}>{value.toUpperCase()}</span>
        <div style={{ position: 'relative', width: '32px', height: '24px', borderRadius: '4px', background: value, border: '1px solid rgba(255,255,255,0.1)', cursor: 'pointer' }}>
          <input 
            type="color" 
            value={value} 
            onChange={(e) => updateCustomColor(themeKey, e.target.value)}
            style={{ position: 'absolute', inset: 0, opacity: 0, width: '100%', height: '100%', cursor: 'pointer' }}
          />
        </div>
      </div>
    </div>
  );

  return (
    <div className="app-container" style={{ background: 'var(--bg-main)' }}>
      <div className="sidebar-wrapper" style={{ width: isSidebarOpen ? '280px' : '0' }}>
         <Sidebar 
            nodes={nodes}
            activeFileId={activeFileId}
            expandedFolders={expandedFolders}
            onFileSelect={setActiveFileId}
            onToggleFolder={(id) => setExpandedFolders(prev => {
                const next = new Set(prev);
                if (next.has(id)) next.delete(id); else next.add(id);
                return next;
            })}
            onAddFile={(parentId) => {
                const id = uuidv4();
                const newNode: FileNode = { id, parentId, name: 'New File.md', type: NodeType.FILE, content: '', createdAt: Date.now() };
                setNodes(prev => [...prev, newNode]);
                setActiveFileId(id);
                if (parentId) setExpandedFolders(prev => new Set(prev).add(parentId));
            }}
            onAddFolder={(parentId) => {
                const id = uuidv4();
                setNodes(prev => [...prev, { id, parentId, name: 'New Folder', type: NodeType.FOLDER, content: '', createdAt: Date.now() }]);
                if (parentId) setExpandedFolders(prev => new Set(prev).add(parentId));
            }}
            onDeleteNode={(id) => {
                const idsToRemove = deleteRecursive(id, nodes);
