import React, { useState, useEffect, useRef } from 'react';
import Editor from '@monaco-editor/react';
import { 
  Play, Maximize2, Minimize2, FileCode, Globe, Palette, 
  ExternalLink, RefreshCcw, Layout
} from 'lucide-react';

interface CodeEditorEngineProps {
  config: {
    js?: string;
    html?: string;
    css?: string;
    internal_block_id: string;
  };
  onUpdate: (newConfig: string) => void;
}

type Tab = 'js' | 'html' | 'css' | 'result';

export const CodeEditorEngine: React.FC<CodeEditorEngineProps> = ({ config, onUpdate }) => {
  const [activeTab, setActiveTab] = useState<Tab>('js');
  const [isFullscreen, setIsFullscreen] = useState(false);
  const [showPreview, setShowPreview] = useState(true);

  // Local state for the code to avoid unnecessary parent re-renders while typing
  const [jsCode, setJsCode] = useState(config.js || '');
  const [htmlCode, setHtmlCode] = useState(config.html || '');
  const [cssCode, setCssCode] = useState(config.css || '');

  const iframeRef = useRef<HTMLIFrameElement>(null);

  // Sync with prop changes (when switching files)
  useEffect(() => {
    setJsCode(config.js || '');
    setHtmlCode(config.html || '');
    setCssCode(config.css || '');
  }, [config.internal_block_id]);

  const runCode = () => {
    if (!iframeRef.current) return;

    const combinedHtml = `
      <!DOCTYPE html>
      <html>
        <head>
          <meta charset="utf-8">
          <style>${cssCode}</style>
        </head>
        <body>
          ${htmlCode}
          <script>
            (function() {
              const originalLog = console.log;
              console.log = function(...args) {
                originalLog.apply(console, args);
                window.parent.postMessage({ type: 'console', payload: args.join(' ') }, '*');
              };
              try {
                ${jsCode}
              } catch (err) {
                console.error(err);
              }
            })();
          </script>
        </body>
      </html>
    `;

    const blob = new Blob([combinedHtml], { type: 'text/html' });
    const url = URL.createObjectURL(blob);
    iframeRef.current.src = url;

    // Persist changes to parent
    const updatedConfig = JSON.stringify({
      js: jsCode,
      html: htmlCode,
      css: cssCode,
      internal_block_id: config.internal_block_id
    }, null, 2);
    onUpdate(updatedConfig);
  };

  useEffect(() => {
    if (activeTab === 'result' || showPreview) {
      const timer = setTimeout(runCode, 500);
      return () => clearTimeout(timer);
    }
  }, [activeTab, showPreview]);

  const TabButton = ({ id, label, icon: Icon }: { id: Tab, label: string, icon: any }) => (
    <button
      onClick={() => setActiveTab(id)}
      style={{
        padding: '0.4rem 0.75rem',
        fontSize: '0.75rem',
        fontWeight: 600,
        display: 'flex',
        alignItems: 'center',
        gap: '0.4rem',
        border: 'none',
        background: activeTab === id ? 'var(--bg-main)' : 'transparent',
        color: activeTab === id ? 'var(--accent-color)' : 'var(--text-muted)',
        borderBottom: activeTab === id ? '2px solid var(--accent-color)' : '2px solid transparent',
        cursor: 'pointer',
        transition: 'all 0.2s'
      }}
    >
      <Icon size={14} />
      {label}
    </button>
  );

  const containerStyle: React.CSSProperties = isFullscreen ? {
    position: 'fixed',
    top: 0,
    left: 0,
    width: '100vw',
    height: '100vh',
    zIndex: 9999,
    backgroundColor: 'var(--bg-main)',
    display: 'flex',
    flexDirection: 'column'
  } : {
    width: '100%',
    height: '500px',
    border: '1px solid var(--border-color)',
    borderRadius: '8px',
    overflow: 'hidden',
    display: 'flex',
    flexDirection: 'column',
    margin: '1rem 0',
    backgroundColor: 'var(--bg-sidebar)'
  };

  return (
    <div style={containerStyle}>
      {/* Header Toolbar */}
      <div style={{ 
        height: '40px', 
        backgroundColor: '#1f2937', 
        display: 'flex', 
        alignItems: 'center', 
        justifyContent: 'space-between',
        padding: '0 0.5rem',
        borderBottom: '1px solid var(--border-color)'
      }}>
        <div style={{ display: 'flex', gap: '2px', height: '100%', alignItems: 'flex-end' }}>
          <TabButton id="js" label="JS" icon={FileCode} />
          <TabButton id="html" label="HTML" icon={Globe} />
          <TabButton id="css" label="CSS" icon={Palette} />
          <TabButton id="result" label="Result" icon={Layout} />
        </div>

        <div style={{ display: 'flex', alignItems: 'center', gap: '0.5rem' }}>
          <button 
            onClick={runCode}
            style={{
              padding: '0.3rem 0.8rem',
              borderRadius: '4px',
              backgroundColor: '#374151',
              color: '#fff',
              border: 'none',
              fontSize: '0.7rem',
              fontWeight: 'bold',
              display: 'flex',
              alignItems: 'center',
              gap: '0.4rem',
              cursor: 'pointer'
            }}
          >
            <Play size={12} fill="white" /> RUN
          </button>
          <button 
            onClick={() => setIsFullscreen(!isFullscreen)}
            style={{ background: 'transparent', border: 'none', color: '#9ca3af', cursor: 'pointer' }}
          >
            {isFullscreen ? <Minimize2 size={16} /> : <Maximize2 size={16} />}
          </button>
        </div>
      </div>

      {/* Editor/Result Area */}
      <div style={{ flex: 1, display: 'flex', overflow: 'hidden' }}>
        {/* Monaco Editor Pane */}
        {/* Fix: Simplified conditional check using string cast to avoid non-overlapping types error */}
        {(activeTab as string) !== 'result' && (
          <div style={{ flex: 1, height: '100%' }}>
            <Editor
              height="100%"
              theme="vs-dark"
              language={activeTab === 'js' ? 'javascript' : activeTab === 'html' ? 'html' : 'css'}
              value={activeTab === 'js' ? jsCode : (activeTab === 'html' ? htmlCode : (activeTab === 'css' ? cssCode : ''))}
              onChange={(val) => {
                if (activeTab === 'js') setJsCode(val || '');
                else if (activeTab === 'html') setHtmlCode(val || '');
                else if (activeTab === 'css') setCssCode(val || '');
              }}
              options={{
                minimap: { enabled: false },
                fontSize: 13,
                scrollBeyondLastLine: false,
                automaticLayout: true,
                padding: { top: 10 }
              }}
            />
          </div>
        )}

        {/* Result/Preview Pane */}
        {(activeTab === 'result' || (showPreview && (activeTab as string) !== 'result')) && (
          <div style={{ 
            flex: activeTab === 'result' ? 1 : 0.8, 
            height: '100%', 
            backgroundColor: '#fff',
            borderLeft: '1px solid var(--border-color)',
            display: 'flex',
            flexDirection: 'column'
          }}>
            <iframe
              ref={iframeRef}
              title="Preview"
              style={{ width: '100%', height: '100%', border: 'none' }}
              sandbox="allow-scripts"
            />
          </div>
        )}
      </div>
    </div>
  );
};

import React, { useState, useRef, useMemo, useCallback, useEffect } from 'react';
import ReactMarkdown from 'react-markdown';
import remarkGfm from 'remark-gfm';
import remarkMath from 'remark-math';
import rehypeKatex from 'rehype-katex';
import rehypeRaw from 'rehype-raw';
import rehypeHighlight from 'rehype-highlight';
import { MermaidDiagram } from './engines/MermaidDiagram';
import { SmilesDiagram } from './engines/SmilesDiagram';
import { InteractivePlot } from './engines/InteractivePlot';
import { PhysicsSimulation } from './engines/PhysicsSimulation';
import { CodeEditorEngine } from './engines/CodeEditorEngine';
import { EditorToolbar } from './editor/EditorToolbar';
import { FileNode } from '../types';

interface EditorProps {
  content: string;
  fileName: string;
  allNodes: FileNode[];
  onChange: (content: string) => void;
  readOnly?: boolean;
  viewMode?: 'split' | 'editor' | 'preview';
}

const safeJsonParse = (str: string) => {
  try {
    return JSON.parse(str);
  } catch (e) {
    try {
      const cleaned = str
        .replace(/\\n/g, "\\n")
        .replace(/\\'/g, "\\'")
        .replace(/\\"/g, '\\"')
        .replace(/\\&/g, "\\&")
        .replace(/\\r/g, "\\r")
        .replace(/\\t/g, "\\t")
        .replace(/\\b/g, "\\b")
        .replace(/\\f/g, "\\f");
      return JSON.parse(cleaned);
    } catch (e2) {
      throw e2;
    }
  }
};

export const Editor: React.FC<EditorProps> = ({ content, fileName, allNodes, onChange, readOnly = false, viewMode = 'split' }) => {
  const textareaRef = useRef<HTMLTextAreaElement>(null);
  const previewRef = useRef<HTMLDivElement>(null);
  const contentRef = useRef(content);
  const [localContent, setLocalContent] = useState(content);

  // Registry to keep track of live updates from IDE blocks
  const ideRegistry = useRef<Record<string, string>>({});
  const persistTimer = useRef<number | null>(null);
  const isSyncingScroll = useRef(false);

  useEffect(() => {
    if (content !== contentRef.current) {
      contentRef.current = content;
      setLocalContent(content);
      ideRegistry.current = {};
    }
  }, [content, fileName]);

  // Scroll Sync Logic
  const handleEditorScroll = () => {
    if (isSyncingScroll.current || viewMode !== 'split' || !textareaRef.current || !previewRef.current) return;
    isSyncingScroll.current = true;
    const { scrollTop, scrollHeight, clientHeight } = textareaRef.current;
    const scrollPercent = scrollTop / (scrollHeight - clientHeight);
    const preview = previewRef.current;
    preview.scrollTop = scrollPercent * (preview.scrollHeight - preview.clientHeight);
    setTimeout(() => { isSyncingScroll.current = false; }, 50);
  };

  const handlePreviewScroll = () => {
    if (isSyncingScroll.current || viewMode !== 'split' || !textareaRef.current || !previewRef.current) return;
    isSyncingScroll.current = true;
    const { scrollTop, scrollHeight, clientHeight } = previewRef.current;
    const scrollPercent = scrollTop / (scrollHeight - clientHeight);
    const textarea = textareaRef.current;
    textarea.scrollTop = scrollPercent * (textarea.scrollHeight - textarea.clientHeight);
    setTimeout(() => { isSyncingScroll.current = false; }, 50);
  };

  const persistToMarkdown = useCallback(() => {
    const currentDoc = contentRef.current;
    const registry = ideRegistry.current;

    const newDoc = currentDoc.replace(/```ide\s*([\s\S]*?)\s*```/g, (match, inner) => {
      try {
        const parsed = safeJsonParse(inner.trim());
        const id = parsed.internal_block_id;
        if (id && registry[id]) {
          return `\`\`\`ide\n${registry[id]}\n\`\`\``;
        }
        return match;
      } catch (e) {
        return match;
      }
    });

    if (newDoc !== currentDoc) {
      contentRef.current = newDoc;
      setLocalContent(newDoc);
      onChange(newDoc);
    }
  }, [onChange]);

  const handleTextareaChange = (val: string) => { 
    setLocalContent(val);
    contentRef.current = val;
    if (persistTimer.current) window.clearTimeout(persistTimer.current);
    persistTimer.current = window.setTimeout(persistToMarkdown, 1000);
  };

  const insertFormat = (prefix: string, suffix: string = '', block: boolean = false) => {
    if (!textareaRef.current) return;
    const { selectionStart: start, selectionEnd: end, value } = textareaRef.current;
    const selectedText = value.substring(start, end);
    let insertion = prefix + selectedText + suffix;
    if (block && value[start - 1] !== '\n' && start !== 0) insertion = '\n' + insertion;
    const newVal = value.substring(0, start) + insertion + value.substring(end);
    handleTextareaChange(newVal);
  };

  const handleIDEUpdate = useCallback((targetId: string, newConfigStr: string) => {
    ideRegistry.current[targetId] = newConfigStr;
    const currentDoc = contentRef.current;
    const updatedDoc = currentDoc.replace(/```ide\s*([\s\S]*?)\s*```/g, (match, inner) => {
      try {
        const parsed = safeJsonParse(inner.trim());
        if (parsed.internal_block_id === targetId) {
          return `\`\`\`ide\n${newConfigStr}\n\`\`\``;
        }
        return match;
      } catch (e) {
        return match;
      }
    });

    if (updatedDoc !== currentDoc) {
      contentRef.current = updatedDoc;
      setLocalContent(updatedDoc);
      if (persistTimer.current) window.clearTimeout(persistTimer.current);
      persistTimer.current = window.setTimeout(() => {
        onChange(updatedDoc);
      }, 500);
    }
  }, [onChange]);

  const markdownComponents = useMemo(() => ({
    code({node, inline, className, children, ...props}: any) {
        const match = /language-([\w-]+)/.exec(className || '');
        const rawCodeContent = String(children).replace(/\n$/, '');
        if (!inline && match?.[1] === 'ide') {
          try { 
            const parsed = safeJsonParse(rawCodeContent.trim());
            const blockId = parsed.internal_block_id;
            if (!blockId) return <pre>{rawCodeContent}</pre>;

            return (
              <CodeEditorEngine 
                key={blockId}
                config={parsed}
                onUpdate={(newStr) => handleIDEUpdate(blockId, newStr)}
              />
            );
          } catch(e: any) { 
            return <pre style={{color: 'red'}}>IDE Syntax Error: {e.message}</pre>;
          }
        }
        if (!inline) {
          switch (match?.[1]) {
            case 'mermaid': return <MermaidDiagram chart={rawCodeContent} />;
            case 'smiles': return <SmilesDiagram smiles={rawCodeContent} />;
            case 'plot': return <InteractivePlot configStr={rawCodeContent} />;
            case 'physics': return <PhysicsSimulation configStr={rawCodeContent} />;
          }
        }
        return <code className={className} {...props}>{children}</code>;
    }
  }), [handleIDEUpdate]);

  return (
    <div className="editor-container bg-[var(--bg-main)] text-[var(--text-main)]">
      <div className="editor-header bg-[var(--bg-toolbar)] border-[var(--border-color)]">
        {(viewMode !== 'preview' && !readOnly) && <EditorToolbar insertFormat={insertFormat} readOnly={readOnly} />}
      </div>
      <div className="split-container">
        {(viewMode === 'split' || viewMode === 'editor') && (
            <div className={`pane ${viewMode === 'split' ? 'half border-r' : 'full'}`}>
                <textarea 
                  ref={textareaRef} 
                  className="textarea" 
                  value={localContent} 
                  onChange={e => handleTextareaChange(e.target.value)} 
                  onBlur={persistToMarkdown}
                  onScroll={handleEditorScroll}
                  placeholder="# Start typing..." 
                  spellCheck={false} 
                  disabled={readOnly} 
                />
            </div>
        )}
        {(viewMode === 'split' || viewMode === 'preview') && (
            <div 
              ref={previewRef}
              onScroll={handlePreviewScroll}
              id="markdown-preview" 
              className={`pane ${viewMode === 'split' ? 'half' : 'full'} preview-area no-scrollbar`}
            >
                <div className="markdown-body">
                    <ReactMarkdown 
                        key={fileName} 
                        remarkPlugins={[remarkGfm, remarkMath]} 
                        rehypePlugins={[
                          rehypeRaw, 
                          [rehypeKatex, { trust: true, strict: false }], 
                          rehypeHighlight
                        ]}
                        components={markdownComponents}
                    >
                      {localContent}
                    </ReactMarkdown>
                </div>
            </div>
        )}
      </div>
    </div>
  );
};

