                          rehypeRaw, 
                          [rehypeKatex, { 
                            trust: true, 
                            strict: false,
                            throwOnError: false
                          }], 
                          rehypeHighlight
                        ]}
                        components={markdownComponents}
                    >
                      {localContent}
                    </ReactMarkdown>
                </div>
            </div>
        )}
      </div>
    </div>
  );
};

