      <div className="editor-header bg-[var(--bg-toolbar)] border-[var(--border-color)]">
        {(viewMode !== 'preview' && !readOnly) && <EditorToolbar insertFormat={insertFormat} readOnly={readOnly} />}
      </div>
      <div className="split-container">
        {(viewMode === 'split' || viewMode === 'editor') && (
            <div className={`pane ${viewMode === 'split' ? 'half border-r' : 'full'}`}>
                <textarea 
                  ref={textareaRef} 
                  className="textarea" 
                  value={localContent} 
                  onChange={e => handleTextareaChange(e.target.value)} 
                  onBlur={persistToMarkdown}
                  onScroll={handleEditorScroll}
                  placeholder="# Start typing..." 
                  spellCheck={false} 
                  disabled={readOnly} 
                />
            </div>
        )}
        {(viewMode === 'split' || viewMode === 'preview') && (
            <div 
              ref={previewRef}
              onScroll={handlePreviewScroll}
              id="markdown-preview" 
              className={`pane ${viewMode === 'split' ? 'half' : 'full'} preview-area no-scrollbar`}
            >
                <div className="markdown-body">
                    <ReactMarkdown 
                        key={fileName} 
                        remarkPlugins={[remarkGfm, remarkMath]} 
                        rehypePlugins={[
                          rehypeRaw, 
                          [rehypeKatex, { 
                            trust: true, 
                            strict: false,
                            throwOnError: false,
                            katex: window.katex // Connect to the global instance that has mhchem extension
                          }], 
                          rehypeHighlight
                        ]}
                        components={markdownComponents} 
                    >
                      {localContent}
                    </ReactMarkdown>
                </div>
            </div>
        )}
      </div>
    </div>
  );
};

import React, { useState, useEffect, useRef } from 'react';
import Editor, { OnMount } from '@monaco-editor/react';
import { 
  Play, Maximize2, Minimize2, FileCode, Globe, Palette, 
  Layout
} from 'lucide-react';

interface CodeEditorEngineProps {
  config: {
    js?: string;
    html?: string;
    css?: string;
    internal_block_id: string;
  };
  onUpdate: (newConfig: string) => void;
}

type Tab = 'js' | 'html' | 'css' | 'result';

export const CodeEditorEngine: React.FC<CodeEditorEngineProps> = ({ config, onUpdate }) => {
  const [activeTab, setActiveTab] = useState<Tab>('js');
  const [isFullscreen, setIsFullscreen] = useState(false);
  const editorRef = useRef<any>(null);

  const [jsCode, setJsCode] = useState(config.js || '');
  const [htmlCode, setHtmlCode] = useState(config.html || '');
  const [cssCode, setCssCode] = useState(config.css || '');

  const iframeRef = useRef<HTMLIFrameElement>(null);

  useEffect(() => {
    setJsCode(config.js || '');
    setHtmlCode(config.html || '');
    setCssCode(config.css || '');
  }, [config.internal_block_id]);

  const handleEditorDidMount: OnMount = (editor, monaco) => {
    editorRef.current = editor;

    // --- CLIPBOARD BRIDGE START ---

    // 1. Handle Paste (Ctrl/Cmd + V)
    editor.addCommand(monaco.KeyMod.CtrlCmd | monaco.KeyCode.KeyV, async () => {
      try {
        const text = await navigator.clipboard.readText();
        const selection = editor.getSelection();
        if (selection) {
          editor.executeEdits('clipboard-paste', [
            {
              range: selection,
              text: text,
              forceMoveMarkers: true,
            },
          ]);
        }
      } catch (err) {
        console.error('Manual paste failed:', err);
      }
    });

    // 2. Handle Copy (Ctrl/Cmd + C)
    editor.addCommand(monaco.KeyMod.CtrlCmd | monaco.KeyCode.KeyC, async () => {
      const selection = editor.getSelection();
      const model = editor.getModel();
      if (selection && model) {
        const text = model.getValueInRange(selection);
        if (text) {
          try {
            await navigator.clipboard.writeText(text);
          } catch (err) {
            console.error('Manual copy failed:', err);
          }
        }
      }
    });

    // 3. Handle Cut (Ctrl/Cmd + X)
    editor.addCommand(monaco.KeyMod.CtrlCmd | monaco.KeyCode.KeyX, async () => {
      const selection = editor.getSelection();
      const model = editor.getModel();
      if (selection && model) {
        const text = model.getValueInRange(selection);
        if (text) {
          try {
            await navigator.clipboard.writeText(text);
            editor.executeEdits('clipboard-cut', [
              {
                range: selection,
                text: '',
                forceMoveMarkers: true,
              },
            ]);
          } catch (err) {
            console.error('Manual cut failed:', err);
          }
        }
      }
    });

    // --- CLIPBOARD BRIDGE END ---

    editor.onDidFocusEditorWidget(() => {
      // Focus reinforcement
    });
  };

  useEffect(() => {
    if (editorRef.current && activeTab !== 'result') {
      editorRef.current.focus();
    }
  }, [activeTab]);

  const runCode = () => {
    if (!iframeRef.current) return;

    const combinedHtml = `
      <!DOCTYPE html>
      <html>
        <head>
          <meta charset="utf-8">
          <style>${cssCode}</style>
        </head>
        <body>
          ${htmlCode}
          <script>
            (function() {
              const originalLog = console.log;
              console.log = function(...args) {
                originalLog.apply(console, args);
                window.parent.postMessage({ type: 'console', payload: args.join(' ') }, '*');
              };
              try {
                ${jsCode}
              } catch (err) {
                console.error(err);
              }
            })();
          </script>
        </body>
      </html>
    `;

    const blob = new Blob([combinedHtml], { type: 'text/html' });
    const url = URL.createObjectURL(blob);
    iframeRef.current.src = url;

    const updatedConfig = JSON.stringify({
      js: jsCode,
      html: htmlCode,
      css: cssCode,
      internal_block_id: config.internal_block_id
    }, null, 2);
    onUpdate(updatedConfig);
  };

  const TabButton = ({ id, label, icon: Icon }: { id: Tab, label: string, icon: any }) => (
    <button
      onClick={() => setActiveTab(id)}
      style={{
        padding: '0.4rem 0.75rem',
        fontSize: '0.75rem',
        fontWeight: 600,
        display: 'flex',
        alignItems: 'center',
        gap: '0.4rem',
        border: 'none',
        background: activeTab === id ? 'var(--bg-main)' : 'transparent',
        color: activeTab === id ? 'var(--accent-color)' : 'var(--text-muted)',
        borderBottom: activeTab === id ? '2px solid var(--accent-color)' : '2px solid transparent',
        cursor: 'pointer',
        transition: 'all 0.2s'
      }}
    >
      <Icon size={14} />
      {label}
    </button>
  );

  const containerStyle: React.CSSProperties = isFullscreen ? {
    position: 'fixed',
    top: 0,
    left: 0,
    width: '100vw',
    height: '100vh',
    zIndex: 9999,
    backgroundColor: 'var(--bg-main)',
    display: 'flex',
    flexDirection: 'column'
  } : {
    width: '100%',
    height: '500px',
    border: '1px solid var(--border-color)',
    borderRadius: '8px',
    overflow: 'hidden',
    display: 'flex',
    flexDirection: 'column',
    margin: '1rem 0',
    backgroundColor: 'var(--bg-sidebar)'
  };

  return (
    <div style={containerStyle}>
      <div style={{ 
        height: '40px', 
        backgroundColor: '#1f2937', 
        display: 'flex', 
        alignItems: 'center', 
        justifyContent: 'space-between',
        padding: '0 0.5rem',
        borderBottom: '1px solid var(--border-color)'
      }}>
        <div style={{ display: 'flex', gap: '2px', height: '100%', alignItems: 'flex-end' }}>
          <TabButton id="js" label="JS" icon={FileCode} />
          <TabButton id="html" label="HTML" icon={Globe} />
          <TabButton id="css" label="CSS" icon={Palette} />
          <TabButton id="result" label="Result" icon={Layout} />
        </div>

        <div style={{ display: 'flex', alignItems: 'center', gap: '0.5rem' }}>
          <button 
            onClick={runCode}
            style={{
              padding: '0.3rem 0.8rem',
              borderRadius: '4px',
              backgroundColor: '#374151',
              color: '#fff',
              border: 'none',
              fontSize: '0.7rem',
              fontWeight: 'bold',
              display: 'flex',
              alignItems: 'center',
              gap: '0.4rem',
              cursor: 'pointer'
            }}
          >
            <Play size={12} fill="white" /> RUN
          </button>
          <button 
            onClick={() => setIsFullscreen(!isFullscreen)}
            style={{ background: 'transparent', border: 'none', color: '#9ca3af', cursor: 'pointer' }}
          >
            {isFullscreen ? <Minimize2 size={16} /> : <Maximize2 size={16} />}
          </button>
        </div>
      </div>

      <div style={{ flex: 1, display: 'flex', overflow: 'hidden' }}>
        {(activeTab as string) !== 'result' && (
          <div style={{ flex: 1, height: '100%' }}>
            <Editor
              height="100%"
              theme="vs-dark"
              language={activeTab === 'js' ? 'javascript' : activeTab === 'html' ? 'html' : 'css'}
              value={activeTab === 'js' ? jsCode : (activeTab === 'html' ? htmlCode : (activeTab === 'css' ? cssCode : ''))}
              onMount={handleEditorDidMount}
              onChange={(val) => {
                if (activeTab === 'js') setJsCode(val || '');
                else if (activeTab === 'html') setHtmlCode(val || '');
                else if (activeTab === 'css') setCssCode(val || '');
              }}
              options={{
                minimap: { enabled: false },
                fontSize: 13,
                scrollBeyondLastLine: false,
                automaticLayout: true,
                padding: { top: 10 },
                fixedOverflowWidgets: true,
                contextmenu: true,
                readOnly: false
              }}
            />
          </div>
        )}

        {activeTab === 'result' && (
          <div style={{ 
            flex: 1, 
            height: '100%', 
            backgroundColor: '#fff',
            display: 'flex',
            flexDirection: 'column'
          }}>
            <iframe
              ref={iframeRef}
              title="Preview"
              style={{ width: '100%', height: '100%', border: 'none' }}
              sandbox="allow-scripts"
            />
          </div>
        )}
      </div>
    </div>
  );
};

import React, { useState, useEffect, useCallback, useMemo, useRef } from 'react';
import { v4 as uuidv4 } from 'uuid';
import { 
  Download, Upload, Palette, PanelLeft, Edit3, Columns, Eye, X, FileText, Plus, FileDown, ExternalLink
} from 'lucide-react';
import { Sidebar } from './components/Sidebar';
import { Editor } from './components/Editor';
import { FileNode, NodeType, AppTheme } from './types';
import { initialNodes } from './initialData';

const themes: Record<string, AppTheme> = {
  dark: { name: 'Dark', bgMain: '#030712', bgSidebar: '#111827', textMain: '#f3f4f6', textMuted: '#9ca3af', border: '#1f2937', accent: '#3b82f6', hover: 'rgba(255, 255, 255, 0.05)' },
  light: { name: 'Light', bgMain: '#ffffff', bgSidebar: '#f3f4f6', textMain: '#111827', textMuted: '#6b7280', border: '#e5e7eb', accent: '#3b82f6', hover: 'rgba(0, 0, 0, 0.05)' },
  navy: { name: 'Navy', bgMain: '#0a192f', bgSidebar: '#112240', textMain: '#ccd6f6', textMuted: '#8892b0', border: '#233554', accent: '#64ffda', hover: 'rgba(100, 255, 218, 0.1)' },
  dracula: { name: 'Dracula', bgMain: '#282a36', bgSidebar: '#21222c', textMain: '#f8f8f2', textMuted: '#6272a4', border: '#44475a', accent: '#ff79c6', hover: 'rgba(255, 255, 255, 0.1)' }
};

export default function App() {
  const [nodes, setNodes] = useState<FileNode[]>(() => {
    const saved = localStorage.getItem('mathsci-fs');
    return saved ? JSON.parse(saved) : initialNodes;
  });
  const [activeFileId, setActiveFileId] = useState<string | null>('file-intro');
  const [expandedFolders, setExpandedFolders] = useState<Set<string>>(new Set(['folder-welcome', 'folder-docs']));
  const [showSettings, setShowSettings] = useState(false);
  const [isSidebarOpen, setIsSidebarOpen] = useState(true);
  const [editorView, setEditorView] = useState<'split' | 'editor' | 'preview'>('split');
  const [currentTheme, setCurrentTheme] = useState<AppTheme>(() => {
    const saved = localStorage.getItem('mathsci-theme');
    return saved ? JSON.parse(saved) : themes.dark;
  });

  const nodesRef = useRef(nodes);
  nodesRef.current = nodes;

  useEffect(() => {
    const root = document.documentElement;
    root.style.setProperty('--bg-main', currentTheme.bgMain);
    root.style.setProperty('--bg-sidebar', currentTheme.bgSidebar);
    root.style.setProperty('--bg-toolbar', currentTheme.bgSidebar);
    root.style.setProperty('--text-main', currentTheme.textMain);
    root.style.setProperty('--text-muted', currentTheme.textMuted);
    root.style.setProperty('--border-color', currentTheme.border);
    root.style.setProperty('--accent-color', currentTheme.accent);
    root.style.setProperty('--hover-bg', currentTheme.hover);
    localStorage.setItem('mathsci-theme', JSON.stringify(currentTheme));
  }, [currentTheme]);

  useEffect(() => {
    localStorage.setItem('mathsci-fs', JSON.stringify(nodes));
  }, [nodes]);

  const handleUpdateContent = useCallback((content: string) => {
    if (!activeFileId) return;
    setNodes(prev => prev.map(n => n.id === activeFileId ? { ...n, content } : n));
  }, [activeFileId]);

  const activeFile = useMemo(() => nodes.find(n => n.id === activeFileId), [nodes, activeFileId]);

  const handleExportPDF = () => {
    const element = document.getElementById('markdown-preview');
    if (!element) return alert("Switch to Preview or Split view to export.");
    const filename = (activeFile?.name || 'document') + '.pdf';
    window.html2pdf().set({
      margin: 1, filename, image: { type: 'jpeg', quality: 0.98 },
      html2canvas: { scale: 2, useCORS: true, backgroundColor: currentTheme.bgMain },
      jsPDF: { unit: 'in', format: 'letter', orientation: 'portrait' }
    }).from(element).save();
  };

  return (
    <div className="app-container" style={{ background: 'var(--bg-main)' }}>
      <div className="sidebar-wrapper" style={{ width: isSidebarOpen ? '280px' : '0' }}>
         <Sidebar 
            nodes={nodes}
            activeFileId={activeFileId}
            expandedFolders={expandedFolders}
            onFileSelect={setActiveFileId}
            onToggleFolder={(id) => setExpandedFolders(prev => {
                const next = new Set(prev);
                if (next.has(id)) next.delete(id); else next.add(id);
                return next;
            })}
            onAddFile={(parentId) => {
                const id = uuidv4();
                const newNode: FileNode = { id, parentId, name: 'Untitled', type: NodeType.FILE, content: '', createdAt: Date.now() };
                setNodes(prev => [...prev, newNode]);
                setActiveFileId(id);
            }}
            onAddFolder={(parentId) => {
                const id = uuidv4();
                setNodes(prev => [...prev, { id, parentId, name: 'New Folder', type: NodeType.FOLDER, content: '', createdAt: Date.now() }]);
            }}
            onDeleteNode={(id) => {
                setNodes(prev => prev.filter(n => n.id !== id && n.parentId !== id));
                if (activeFileId === id) setActiveFileId(null);
            }}
            onRenameNode={(id, name) => setNodes(prev => prev.map(n => n.id === id ? { ...n, name } : n))}
            onMoveNode={(id, parentId) => setNodes(prev => prev.map(n => n.id === id ? { ...n, parentId } : n))}
         />
      </div>

      <div className="main-content" style={{ flex: 1, display: 'flex', flexDirection: 'column', overflow: 'hidden' }}>
        <div className="toolbar">
            <div style={{ display: 'flex', alignItems: 'center', gap: '0.75rem' }}>
                <button onClick={() => setIsSidebarOpen(!isSidebarOpen)} className="btn-icon"><PanelLeft size={18} /></button>
                <h1 className="app-title">MathSci</h1>
            </div>
            <div style={{ display: 'flex', alignItems: 'center', gap: '0.5rem' }}>
                <button onClick={handleExportPDF} className="btn"><FileDown size={14} /> PDF</button>
                <button onClick={() => setShowSettings(true)} className="btn"><Palette size={14} /> Theme</button>
                <div style={{ display: 'flex', background: 'var(--bg-main)', border: '1px solid var(--border-color)', borderRadius: '6px', padding: '2px', gap: '2px' }}>
                   <button onClick={() => setEditorView('editor')} className="btn-icon" style={{ color: editorView === 'editor' ? 'var(--accent-color)' : 'var(--text-muted)' }}><Edit3 size={16} /></button>
                   <button onClick={() => setEditorView('split')} className="btn-icon" style={{ color: editorView === 'split' ? 'var(--accent-color)' : 'var(--text-muted)' }}><Columns size={16} /></button>
                   <button onClick={() => setEditorView('preview')} className="btn-icon" style={{ color: editorView === 'preview' ? 'var(--accent-color)' : 'var(--text-muted)' }}><Eye size={16} /></button>
                </div>
            </div>
        </div>

        <div style={{ flex: 1, overflow: 'hidden' }}>
            {activeFile ? (
                <Editor 
                  key={activeFileId}
                  content={activeFile.content} 
                  fileName={activeFile.name}
                  allNodes={nodes}
                  viewMode={editorView}
                  onChange={handleUpdateContent} 
                />
            ) : (
              <div style={{ height: '100%', display: 'flex', alignItems: 'center', justifyContent: 'center', color: 'var(--text-muted)', textAlign: 'center' }}>
                  <p>Select a file to edit or create a new one.</p>
              </div>
            )}
        </div>
      </div>

      {showSettings && (
          <div className="modal-overlay" onClick={() => setShowSettings(false)}>
              <div className="modal" onClick={e => e.stopPropagation()} style={{ background: '#0a0f1d', padding: '1.5rem', borderRadius: '12px' }}>
                  <h3 style={{ marginTop: 0 }}>Themes</h3>
                  <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: '1rem' }}>
                    {Object.entries(themes).map(([k, t]) => (
                        <button key={k} onClick={() => setCurrentTheme(t)} className="btn" style={{ background: t.bgSidebar, color: t.textMain }}>{t.name}</button>
                    ))}
                  </div>
              </div>
          </div>
      )}
    </div>
  );
}

import React, { useState, useRef, useMemo, useCallback, useEffect } from 'react';
import ReactMarkdown from 'react-markdown';
import remarkGfm from 'remark-gfm';
import remarkMath from 'remark-math';
import rehypeKatex from 'rehype-katex';
import rehypeRaw from 'rehype-raw';
import rehypeHighlight from 'rehype-highlight';
import { MermaidDiagram } from './engines/MermaidDiagram';
import { SmilesDiagram } from './engines/SmilesDiagram';
import { InteractivePlot } from './engines/InteractivePlot';
import { PhysicsSimulation } from './engines/PhysicsSimulation';
import { CodeEditorEngine } from './engines/CodeEditorEngine';
import { EditorToolbar } from './editor/EditorToolbar';
import { FileNode } from '../types';

interface EditorProps {
  content: string;
  fileName: string;
  allNodes: FileNode[];
  onChange: (content: string) => void;
  readOnly?: boolean;
  viewMode?: 'split' | 'editor' | 'preview';
}

const safeJsonParse = (str: string) => {
  try { return JSON.parse(str); } catch (e) { return null; }
};

export const Editor: React.FC<EditorProps> = ({ content, fileName, allNodes, onChange, readOnly = false, viewMode = 'split' }) => {
  const textareaRef = useRef<HTMLTextAreaElement>(null);
  const previewRef = useRef<HTMLDivElement>(null);
  const [localContent, setLocalContent] = useState(content);

  // Update local state when file changes
  useEffect(() => {
    setLocalContent(content);
  }, [content]);

  const handleTextareaChange = (e: React.ChangeEvent<HTMLTextAreaElement>) => {
    const val = e.target.value;
    setLocalContent(val);
    onChange(val); // Real-time sync to parent state
  };

  const insertFormat = (prefix: string, suffix: string = '', block: boolean = false) => {
    if (!textareaRef.current) return;
    const { selectionStart: start, selectionEnd: end, value } = textareaRef.current;
    const selectedText = value.substring(start, end);
    let insertion = prefix + selectedText + suffix;
    if (block && start !== 0 && value[start - 1] !== '\n') insertion = '\n' + insertion;
    const newVal = value.substring(0, start) + insertion + value.substring(end);
    setLocalContent(newVal);
    onChange(newVal);
  };

  const handleIDEUpdate = useCallback((targetId: string, newConfigStr: string) => {
    setLocalContent(prev => {
      const updated = prev.replace(/```ide\s*([\s\S]*?)\s*```/g, (match, inner) => {
        const parsed = safeJsonParse(inner.trim());
        if (parsed?.internal_block_id === targetId) {
          return `\`\`\`ide\n${newConfigStr}\n\`\`\``;
        }
        return match;
      });
      onChange(updated);
      return updated;
    });
  }, [onChange]);

  const markdownComponents = useMemo(() => ({
    code({node, inline, className, children, ...props}: any) {
        const match = /language-([\w-]+)/.exec(className || '');
        const rawCodeContent = String(children).replace(/\n$/, '');
        if (!inline && match?.[1] === 'ide') {
            const parsed = safeJsonParse(rawCodeContent.trim());
            if (!parsed?.internal_block_id) return <pre>{rawCodeContent}</pre>;
            return (
              <CodeEditorEngine 
                key={parsed.internal_block_id}
                config={parsed}
                onUpdate={(newStr) => handleIDEUpdate(parsed.internal_block_id, newStr)}
              />
            );
        }
        if (!inline) {
          switch (match?.[1]) {
            case 'mermaid': return <MermaidDiagram chart={rawCodeContent} />;
            case 'smiles': return <SmilesDiagram smiles={rawCodeContent} />;
            case 'plot': return <InteractivePlot configStr={rawCodeContent} />;
            case 'physics': return <PhysicsSimulation configStr={rawCodeContent} />;
          }
        }
        return <code className={className} {...props}>{children}</code>;
    }
  }), [handleIDEUpdate]);

  return (
    <div className="editor-container h-full w-full flex flex-col">
      <div className="editor-header">
        {(viewMode !== 'preview' && !readOnly) && <EditorToolbar insertFormat={insertFormat} readOnly={readOnly} />}
      </div>
      <div className="split-container flex-1">
        {(viewMode === 'split' || viewMode === 'editor') && (
            <div className={`pane ${viewMode === 'split' ? 'half border-r' : 'full'}`}>
                <textarea 
                  ref={textareaRef} 
                  className="textarea" 
                  value={localContent} 
                  onChange={handleTextareaChange}
                  placeholder="# Type here..." 
                  spellCheck={false} 
                  disabled={readOnly} 
                />
            </div>
        )}
        {(viewMode === 'split' || viewMode === 'preview') && (
            <div ref={previewRef} id="markdown-preview" className={`pane ${viewMode === 'split' ? 'half' : 'full'} preview-area no-scrollbar`}>
                <div className="markdown-body">
                    <ReactMarkdown 
                        remarkPlugins={[remarkGfm, remarkMath]} 
                        rehypePlugins={[rehypeRaw, [rehypeKatex, { trust: true, strict: false }], rehypeHighlight]}
                        components={markdownComponents} 
                    >
                      {localContent}
                    </ReactMarkdown>
                </div>
            </div>
        )}
      </div>
    </div>
  );
};

'use client';
import React, { useRef, useState } from 'react';
import { 
  Bold, Italic, Strikethrough, 
  Heading1, Heading2, Heading3, 
  List, ListOrdered, CheckSquare, 
