import React, { useState, useEffect, useRef } from 'react';
import Editor, { OnMount } from '@monaco-editor/react';
import { 
  Play, Maximize2, Minimize2, FileCode, Globe, Palette, 
  Layout
} from 'lucide-react';

interface CodeEditorEngineProps {
  config: {
    js?: string;
    html?: string;
    css?: string;
    internal_block_id: string;
  };
  onUpdate: (newConfig: string) => void;
}

type Tab = 'js' | 'html' | 'css' | 'result';

export const CodeEditorEngine: React.FC<CodeEditorEngineProps> = ({ config, onUpdate }) => {
  const [activeTab, setActiveTab] = useState<Tab>('js');
  const [isFullscreen, setIsFullscreen] = useState(false);
  const editorRef = useRef<any>(null);

  const [jsCode, setJsCode] = useState(config.js || '');
  const [htmlCode, setHtmlCode] = useState(config.html || '');
  const [cssCode, setCssCode] = useState(config.css || '');

  const iframeRef = useRef<HTMLIFrameElement>(null);
  const hasRunOnce = useRef(false);

  useEffect(() => {
    setJsCode(config.js || '');
    setHtmlCode(config.html || '');
    setCssCode(config.css || '');
  }, [config.internal_block_id]);

  const handleEditorDidMount: OnMount = (editor, monaco) => {
    editorRef.current = editor;

    // Setup basic clipboard commands
    editor.addCommand(monaco.KeyMod.CtrlCmd | monaco.KeyCode.KeyV, async () => {
      const text = await navigator.clipboard.readText();
      const selection = editor.getSelection();
      if (selection) editor.executeEdits('paste', [{ range: selection, text, forceMoveMarkers: true }]);
    });
  };

  useEffect(() => {
    if (editorRef.current && activeTab !== 'result') {
      editorRef.current.focus();
    }
    // If user switches to result and hasn't run it yet, do an initial run
    if (activeTab === 'result' && !hasRunOnce.current) {
      runCode();
    }
  }, [activeTab]);

  const runCode = () => {
    if (!iframeRef.current) return;
    hasRunOnce.current = true;

    const combinedHtml = `
      <!DOCTYPE html>
      <html>
        <head>
          <meta charset="utf-8">
          <style>
            body { background-color: white; color: black; margin: 0; padding: 10px; font-family: sans-serif; }
            ${cssCode}
          </style>
        </head>
        <body>
          ${htmlCode}
          <script>
            (function() {
              try {
                ${jsCode}
              } catch (err) {
                console.error(err);
                document.body.innerHTML += '<div style="color:red; margin-top:20px; border-top:1px solid #ddd; padding-top:10px;"><b>Error:</b> ' + err.message + '</div>';
              }
            })();
          </script>
        </body>
      </html>
    `;

    const blob = new Blob([combinedHtml], { type: 'text/html' });
    const url = URL.createObjectURL(blob);
    iframeRef.current.src = url;

    const updatedConfig = JSON.stringify({
      js: jsCode,
      html: htmlCode,
      css: cssCode,
      internal_block_id: config.internal_block_id
    }, null, 2);
    onUpdate(updatedConfig);
  };

  const TabButton = ({ id, label, icon: Icon }: { id: Tab, label: string, icon: any }) => (
    <button
      onClick={() => setActiveTab(id)}
      style={{
        padding: '0.4rem 0.75rem',
        fontSize: '0.75rem',
        fontWeight: 600,
        display: 'flex',
        alignItems: 'center',
        gap: '0.4rem',
        border: 'none',
        background: activeTab === id ? 'var(--bg-main)' : 'transparent',
        color: activeTab === id ? 'var(--accent-color)' : 'var(--text-muted)',
        borderBottom: activeTab === id ? '2px solid var(--accent-color)' : '2px solid transparent',
        cursor: 'pointer',
        transition: 'all 0.2s',
        height: '100%'
      }}
    >
      <Icon size={14} />
      {label}
    </button>
  );

  const containerStyle: React.CSSProperties = isFullscreen ? {
    position: 'fixed', top: 0, left: 0, width: '100vw', height: '100vh',
    zIndex: 9999, backgroundColor: 'var(--bg-main)', display: 'flex', flexDirection: 'column'
  } : {
    width: '100%', height: '500px', border: '1px solid var(--border-color)',
    borderRadius: '8px', overflow: 'hidden', display: 'flex', flexDirection: 'column',
    margin: '1rem 0', backgroundColor: 'var(--bg-sidebar)'
  };

  return (
    <div style={containerStyle}>
      <div style={{ 
        height: '40px', backgroundColor: '#1f2937', display: 'flex', 
        alignItems: 'center', justifyContent: 'space-between',
        padding: '0 0.5rem', borderBottom: '1px solid var(--border-color)'
      }}>
        <div style={{ display: 'flex', gap: '2px', height: '100%', alignItems: 'center' }}>
          <TabButton id="js" label="JS" icon={FileCode} />
          <TabButton id="html" label="HTML" icon={Globe} />
          <TabButton id="css" label="CSS" icon={Palette} />
          <TabButton id="result" label="Result" icon={Layout} />
        </div>

        <div style={{ display: 'flex', alignItems: 'center', gap: '0.5rem' }}>
          <button 
            onClick={runCode}
            style={{
              padding: '0.3rem 0.8rem', borderRadius: '4px',
              backgroundColor: 'var(--accent-color)', color: '#fff',
              border: 'none', fontSize: '0.7rem', fontWeight: 'bold',
              display: 'flex', alignItems: 'center', gap: '0.4rem', cursor: 'pointer'
            }}
          >
            <Play size={12} fill="white" /> RUN
          </button>
          <button 
            onClick={() => setIsFullscreen(!isFullscreen)}
            style={{ background: 'transparent', border: 'none', color: '#9ca3af', cursor: 'pointer' }}
          >
            {isFullscreen ? <Minimize2 size={16} /> : <Maximize2 size={16} />}
          </button>
        </div>
      </div>

      <div style={{ flex: 1, display: 'flex', overflow: 'hidden', position: 'relative' }}>
        {/* Editor Area */}
        <div style={{ 
          display: activeTab === 'result' ? 'none' : 'block', 
          flex: 1, height: '100%' 
        }}>
          <Editor
            height="100%"
            theme="vs-dark"
            language={activeTab === 'js' ? 'javascript' : activeTab === 'html' ? 'html' : 'css'}
            value={activeTab === 'js' ? jsCode : (activeTab === 'html' ? htmlCode : (activeTab === 'css' ? cssCode : ''))}
            onMount={handleEditorDidMount}
            onChange={(val) => {
              if (activeTab === 'js') setJsCode(val || '');
              else if (activeTab === 'html') setHtmlCode(val || '');
              else if (activeTab === 'css') setCssCode(val || '');
            }}
            options={{
              minimap: { enabled: false }, fontSize: 13, scrollBeyondLastLine: false,
              automaticLayout: true, padding: { top: 10 }, fixedOverflowWidgets: true
            }}
          />
        </div>

        {/* Result Area - Always present in DOM but hidden via CSS */}
        <div style={{ 
          display: activeTab === 'result' ? 'flex' : 'none', 
          flex: 1, height: '100%', backgroundColor: '#fff', flexDirection: 'column'
        }}>
          <iframe
            ref={iframeRef}
            title="Preview"
            style={{ width: '100%', height: '100%', border: 'none' }}
            sandbox="allow-scripts"
          />
        </div>
      </div>
    </div>
  );
};

