                if (window.confirm("Are you sure you want to delete this?")) {
                  setNodes(prev => prev.filter(n => n.id !== id && n.parentId !== id));
                  if (activeFileId === id) setActiveFileId(null);
                }
            }}
            onRenameNode={(id, name) => setNodes(prev => prev.map(n => n.id === id ? { ...n, name } : n))}
            onMoveNode={(id, parentId) => setNodes(prev => prev.map(n => n.id === id ? { ...n, parentId } : n))}
         />
      </div>

      <div className="main-content" style={{ flex: 1, display: 'flex', flexDirection: 'column', overflow: 'hidden' }}>
        <div className="toolbar">
            <div style={{ display: 'flex', alignItems: 'center', gap: '0.75rem' }}>
                <button onClick={() => setIsSidebarOpen(!isSidebarOpen)} className="btn-icon"><PanelLeft size={18} /></button>
                <h1 className="app-title">MathSci</h1>
            </div>
            <div style={{ display: 'flex', alignItems: 'center', gap: '0.5rem' }}>
                <button onClick={handleExportPDF} className="btn"><FileDown size={14} /> PDF</button>
                <button onClick={() => setShowSettings(true)} className="btn"><Palette size={14} /> Theme</button>
                <div style={{ display: 'flex', background: 'var(--bg-main)', border: '1px solid var(--border-color)', borderRadius: '6px', padding: '2px', gap: '2px' }}>
                   <button onClick={() => setEditorView('editor')} className="btn-icon" style={{ color: editorView === 'editor' ? 'var(--accent-color)' : 'var(--text-muted)' }} title="Editor only"><Edit3 size={16} /></button>
                   <button onClick={() => setEditorView('split')} className="btn-icon" style={{ color: editorView === 'split' ? 'var(--accent-color)' : 'var(--text-muted)' }} title="Split view"><Columns size={16} /></button>
                   <button onClick={() => setEditorView('preview')} className="btn-icon" style={{ color: editorView === 'preview' ? 'var(--accent-color)' : 'var(--text-muted)' }} title="Preview only"><Eye size={16} /></button>
                </div>
            </div>
        </div>

        <div style={{ flex: 1, overflow: 'hidden' }}>
            {activeFile ? (
                <Editor 
                  key={activeFileId}
                  content={activeFile.content} 
                  fileName={activeFile.name}
                  allNodes={nodes}
                  viewMode={editorView}
                  onChange={handleUpdateContent} 
                />
            ) : (
              <div style={{ height: '100%', display: 'flex', alignItems: 'center', justifyContent: 'center', color: 'var(--text-muted)', textAlign: 'center' }}>
                  <div style={{ padding: '2rem' }}>
                    <FileText size={48} style={{ marginBottom: '1rem', opacity: 0.2 }} />
                    <p>Select a file from the sidebar or create a new one to begin.</p>
                  </div>
              </div>
            )}
        </div>
      </div>

      {showSettings && (
          <div className="modal-overlay" onClick={() => setShowSettings(false)}>
              <div className="modal" onClick={e => e.stopPropagation()} style={{ background: '#0a0f1d', padding: '1.5rem', borderRadius: '16px', boxShadow: '0 25px 50px -12px rgba(0, 0, 0, 0.5)', border: '1px solid #1f2937', color: '#fff', width: '420px' }}>
                  <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: '1.5rem' }}>
                    <div style={{ display: 'flex', alignItems: 'center', gap: '0.75rem' }}>
                      <Palette size={20} color="#3b82f6" />
                      <h3 style={{ margin: 0, fontSize: '1.1rem', fontWeight: 600 }}>Theme & Workspace</h3>
                    </div>
                    <button onClick={() => setShowSettings(false)} style={{ background: 'none', border: 'none', color: '#9ca3af', cursor: 'pointer' }}><X size={20}/></button>
                  </div>

                  <div style={{ marginBottom: '1.5rem' }}>
                    <label style={{ fontSize: '0.75rem', color: '#9ca3af', display: 'block', marginBottom: '0.75rem' }}>Presets</label>
                    <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: '0.75rem' }}>
                      {Object.entries(themes).map(([k, t]) => (
                          <button 
                            key={k} 
                            onClick={() => setCurrentTheme(t)} 
                            style={{ 
                              background: currentTheme.name === t.name ? '#fff' : '#111827', 
                              color: currentTheme.name === t.name ? '#000' : '#f3f4f6',
                              border: currentTheme.name === t.name ? '1px solid #3b82f6' : '1px solid #1f2937',
                              padding: '0.75rem',
                              borderRadius: '8px',
                              display: 'flex',
                              alignItems: 'center',
                              gap: '0.75rem',
                              cursor: 'pointer',
                              transition: 'all 0.2s',
                              textAlign: 'left'
                            }}
                          >
                            <div style={{ width: '10px', height: '10px', borderRadius: '50%', backgroundColor: '#3b82f6' }}></div>
                            <span style={{ fontSize: '0.875rem', fontWeight: 600 }}>{t.name}</span>
                          </button>
                      ))}
                    </div>
                  </div>

                  <div style={{ marginBottom: '1.5rem' }}>
                    <label style={{ fontSize: '0.75rem', color: '#9ca3af', display: 'block', marginBottom: '1rem' }}>Custom Colors</label>
                    <div style={{ display: 'flex', flexDirection: 'column', gap: '1rem' }}>
                      {[
                        { label: 'Main Background', key: 'bgMain' },
                        { label: 'Sidebar Background', key: 'bgSidebar' },
                        { label: 'Text Color', key: 'textMain' },
                        { label: 'Accent Color', key: 'accent' }
                      ].map((item) => (
                        <div key={item.key} style={{ display: 'flex', alignItems: 'center', justifyContent: 'space-between' }}>
                          <span style={{ fontSize: '0.875rem', fontWeight: 500 }}>{item.label}</span>
                          <div style={{ display: 'flex', alignItems: 'center', gap: '0.75rem' }}>
                            <span style={{ fontSize: '0.75rem', fontFamily: 'monospace', color: '#6b7280' }}>{currentTheme[item.key as keyof AppTheme]?.toUpperCase()}</span>
                            <div style={{ position: 'relative', width: '32px', height: '32px', borderRadius: '4px', border: '1px solid #1f2937', background: currentTheme[item.key as keyof AppTheme] }}>
                              <input 
                                type="color" 
                                value={currentTheme[item.key as keyof AppTheme]} 
                                onChange={(e) => updateThemeColor(item.key as keyof AppTheme, e.target.value)}
                                style={{ position: 'absolute', inset: 0, width: '100%', height: '100%', cursor: 'pointer', opacity: 0 }}
                              />
                            </div>
                          </div>
                        </div>
                      ))}
                    </div>
                  </div>

                  <div style={{ borderTop: '1px solid #1f2937', paddingTop: '1.5rem', marginBottom: '1.5rem' }}>
                    <label style={{ fontSize: '0.75rem', color: '#9ca3af', display: 'block', marginBottom: '0.75rem' }}>Workspace Backup (.json)</label>
                    <div style={{ display: 'flex', gap: '0.5rem' }}>
                      <button 
                        onClick={exportWorkspaceJSON} 
                        className="btn" 
                        style={{ flex: 1, justifyContent: 'center', background: '#111827' }}
