                  <button 
                    onClick={() => setShowSettings(false)} 
                    style={{ 
                      width: '100%', 
                      padding: '0.875rem', 
                      background: '#3b82f6', 
                      color: 'white', 
                      border: 'none', 
                      borderRadius: '8px', 
                      fontWeight: 600, 
                      fontSize: '0.875rem',
