import React, { useState, useEffect, useCallback, useMemo } from 'react';
import { v4 as uuidv4 } from 'uuid';
import { 
  Download, Upload, Palette, PanelLeft, Edit3, Columns, Eye, X, FileText, Plus, FileDown, Trash2
} from 'lucide-react';
import { Sidebar } from './components/Sidebar';
import { Editor } from './components/Editor';
import { FileNode, NodeType, AppTheme, ImportData } from './types';
import { initialNodes } from './initialData';

const themes: Record<string, AppTheme> = {
  dark: { name: 'Dark', bgMain: '#030712', bgSidebar: '#111827', textMain: '#f3f4f6', textMuted: '#9ca3af', border: '#1f2937', accent: '#3b82f6', hover: 'rgba(255, 255, 255, 0.05)' },
  light: { name: 'Light', bgMain: '#ffffff', bgSidebar: '#f3f4f6', textMain: '#111827', textMuted: '#6b7280', border: '#e5e7eb', accent: '#3b82f6', hover: 'rgba(0, 0, 0, 0.05)' },
  navy: { name: 'Navy', bgMain: '#0a192f', bgSidebar: '#112240', textMain: '#ccd6f6', textMuted: '#8892b0', border: '#233554', accent: '#64ffda', hover: 'rgba(100, 255, 218, 0.1)' },
  dracula: { name: 'Dracula', bgMain: '#282a36', bgSidebar: '#21222c', textMain: '#f8f8f2', textMuted: '#6272a4', border: '#44475a', accent: '#ff79c6', hover: 'rgba(255, 255, 255, 0.1)' }
};

export default function App() {
  const [nodes, setNodes] = useState<FileNode[]>(() => {
    const saved = localStorage.getItem('mathsci-fs');
    return saved ? JSON.parse(saved) : initialNodes;
  });
  const [activeFileId, setActiveFileId] = useState<string | null>('file-intro');
  const [expandedFolders, setExpandedFolders] = useState<Set<string>>(new Set(['folder-welcome', 'folder-docs']));
  const [showSettings, setShowSettings] = useState(false);
  const [isSidebarOpen, setIsSidebarOpen] = useState(true);
  const [editorView, setEditorView] = useState<'split' | 'editor' | 'preview'>('split');
  const [currentTheme, setCurrentTheme] = useState<AppTheme>(() => {
    const saved = localStorage.getItem('mathsci-theme');
    return saved ? JSON.parse(saved) : themes.dark;
  });

  useEffect(() => {
    const root = document.documentElement;
    root.style.setProperty('--bg-main', currentTheme.bgMain);
    root.style.setProperty('--bg-sidebar', currentTheme.bgSidebar);
    root.style.setProperty('--bg-toolbar', currentTheme.bgSidebar);
    root.style.setProperty('--text-main', currentTheme.textMain);
    root.style.setProperty('--text-muted', currentTheme.textMuted);
    root.style.setProperty('--border-color', currentTheme.border);
    root.style.setProperty('--accent-color', currentTheme.accent);
    root.style.setProperty('--hover-bg', currentTheme.hover);
    localStorage.setItem('mathsci-theme', JSON.stringify(currentTheme));
  }, [currentTheme]);

  useEffect(() => {
    localStorage.setItem('mathsci-fs', JSON.stringify(nodes));
  }, [nodes]);

  const handleUpdateContent = useCallback((content: string) => {
    if (!activeFileId) return;
    setNodes(prev => prev.map(n => n.id === activeFileId ? { ...n, content } : n));
  }, [activeFileId]);

  const activeFile = useMemo(() => nodes.find(n => n.id === activeFileId), [nodes, activeFileId]);

  const handleExportPDF = () => {
    const element = document.getElementById('markdown-preview');
    if (!element) return alert("Switch to Preview or Split view to export.");
    const filename = (activeFile?.name || 'document') + '.pdf';
    window.html2pdf().set({
      margin: 1, filename, image: { type: 'jpeg', quality: 0.98 },
      html2canvas: { scale: 2, useCORS: true, backgroundColor: currentTheme.bgMain },
      jsPDF: { unit: 'in', format: 'letter', orientation: 'portrait' }
    }).from(element).save();
  };

  const exportWorkspaceJSON = () => {
    const data: ImportData = { version: 1, nodes };
    const blob = new Blob([JSON.stringify(data, null, 2)], { type: 'application/json' });
    const url = URL.createObjectURL(blob);
    const a = document.createElement('a');
    a.href = url;
    a.download = `mathsci-workspace-${new Date().toISOString().split('T')[0]}.json`;
    a.click();
    URL.revokeObjectURL(url);
  };

  const importWorkspaceJSON = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;
    const reader = new FileReader();
    reader.onload = (event) => {
      try {
        const data = JSON.parse(event.target?.result as string) as ImportData;
        if (data.nodes && Array.isArray(data.nodes)) {
          setNodes(data.nodes);
          alert(`Successfully imported ${data.nodes.length} files/folders.`);
        }
      } catch (err) {
        alert("Error parsing workspace file. Please ensure it is a valid JSON export.");
      }
    };
    reader.readAsText(file);
  };

  const updateThemeColor = (key: keyof AppTheme, color: string) => {
    setCurrentTheme(prev => ({ ...prev, [key]: color }));
  };

  // Helper to delete a node and all its descendants
  const deleteNodeAndDescendants = (nodeId: string, currentNodes: FileNode[]): FileNode[] => {
    const children = currentNodes.filter(n => n.parentId === nodeId);
    let updatedNodes = currentNodes.filter(n => n.id !== nodeId);
    children.forEach(child => {
      updatedNodes = deleteNodeAndDescendants(child.id, updatedNodes);
    });
    return updatedNodes;
  };

  const handleDeleteNode = (id: string) => {
    const nodeToDelete = nodes.find(n => n.id === id);
    if (!nodeToDelete) return;

    if (window.confirm(`Are you sure you want to delete "${nodeToDelete.name}"?${nodeToDelete.type === NodeType.FOLDER ? ' All contents will be lost.' : ''}`)) {
      setNodes(prev => {
        const next = deleteNodeAndDescendants(id, prev);
        return next;
      });
      if (activeFileId === id || nodes.find(n => n.id === activeFileId)?.parentId === id) {
        setActiveFileId(null);
      }
    }
  };

  return (
    <div className="app-container" style={{ background: 'var(--bg-main)' }}>
      <div className="sidebar-wrapper" style={{ width: isSidebarOpen ? '280px' : '0' }}>
         <Sidebar 
            nodes={nodes}
            activeFileId={activeFileId}
            expandedFolders={expandedFolders}
            onFileSelect={setActiveFileId}
            onToggleFolder={(id) => setExpandedFolders(prev => {
                const next = new Set(prev);
                if (next.has(id)) next.delete(id); else next.add(id);
                return next;
            })}
            onAddFile={(parentId) => {
                const id = uuidv4();
                // Removed .md requirement
                const newNode: FileNode = { id, parentId, name: 'Untitled', type: NodeType.FILE, content: '', createdAt: Date.now() };
                setNodes(prev => [...prev, newNode]);
                setActiveFileId(id);
            }}
            onAddFolder={(parentId) => {
                const id = uuidv4();
                setNodes(prev => [...prev, { id, parentId, name: 'New Folder', type: NodeType.FOLDER, content: '', createdAt: Date.now() }]);
            }}
            onDeleteNode={handleDeleteNode}
            onRenameNode={(id, name) => setNodes(prev => prev.map(n => n.id === id ? { ...n, name } : n))}
            onMoveNode={(id, parentId) => setNodes(prev => prev.map(n => n.id === id ? { ...n, parentId } : n))}
         />
      </div>

      <div className="main-content" style={{ flex: 1, display: 'flex', flexDirection: 'column', overflow: 'hidden' }}>
        <div className="toolbar">
            <div style={{ display: 'flex', alignItems: 'center', gap: '0.75rem' }}>
                <button onClick={() => setIsSidebarOpen(!isSidebarOpen)} className="btn-icon"><PanelLeft size={18} /></button>
                <h1 className="app-title">MathSci</h1>
            </div>
            <div style={{ display: 'flex', alignItems: 'center', gap: '0.5rem' }}>
                <button onClick={handleExportPDF} className="btn"><FileDown size={14} /> PDF</button>
                <button onClick={() => setShowSettings(true)} className="btn"><Palette size={14} /> Theme</button>
                <div style={{ display: 'flex', background: 'var(--bg-main)', border: '1px solid var(--border-color)', borderRadius: '6px', padding: '2px', gap: '2px' }}>
                   <button onClick={() => setEditorView('editor')} className="btn-icon" style={{ color: editorView === 'editor' ? 'var(--accent-color)' : 'var(--text-muted)' }} title="Editor only"><Edit3 size={16} /></button>
                   <button onClick={() => setEditorView('split')} className="btn-icon" style={{ color: editorView === 'split' ? 'var(--accent-color)' : 'var(--text-muted)' }} title="Split view"><Columns size={16} /></button>
                   <button onClick={() => setEditorView('preview')} className="btn-icon" style={{ color: editorView === 'preview' ? 'var(--accent-color)' : 'var(--text-muted)' }} title="Preview only"><Eye size={16} /></button>
                </div>
            </div>
        </div>

        <div style={{ flex: 1, overflow: 'hidden' }}>
            {activeFile ? (
                <Editor 
                  key={activeFileId}
                  content={activeFile.content} 
                  fileName={activeFile.name}
                  allNodes={nodes}
                  viewMode={editorView}
                  onChange={handleUpdateContent} 
                />
            ) : (
              <div style={{ height: '100%', display: 'flex', alignItems: 'center', justifyContent: 'center', color: 'var(--text-muted)', textAlign: 'center' }}>
                  <div style={{ padding: '2rem' }}>
                    <FileText size={48} style={{ marginBottom: '1rem', opacity: 0.2 }} />
                    <p>Select a file from the sidebar or create a new one to begin.</p>
                  </div>
              </div>
            )}
        </div>
      </div>

      {showSettings && (
          <div className="modal-overlay" onClick={() => setShowSettings(false)}>
              <div className="modal" onClick={e => e.stopPropagation()} style={{ background: '#0a0f1d', padding: '1.5rem', borderRadius: '16px', boxShadow: '0 25px 50px -12px rgba(0, 0, 0, 0.5)', border: '1px solid #1f2937', color: '#fff', width: '420px' }}>
                  <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: '1.5rem' }}>
                    <div style={{ display: 'flex', alignItems: 'center', gap: '0.75rem' }}>
                      <Palette size={20} color="#3b82f6" />
                      <h3 style={{ margin: 0, fontSize: '1.1rem', fontWeight: 600 }}>Theme & Workspace</h3>
                    </div>
                    <button onClick={() => setShowSettings(false)} style={{ background: 'none', border: 'none', color: '#9ca3af', cursor: 'pointer' }}><X size={20}/></button>
                  </div>

                  <div style={{ marginBottom: '1.5rem' }}>
                    <label style={{ fontSize: '0.75rem', color: '#9ca3af', display: 'block', marginBottom: '0.75rem' }}>Presets</label>
                    <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: '0.75rem' }}>
                      {Object.entries(themes).map(([k, t]) => (
                          <button 
                            key={k} 
                            onClick={() => setCurrentTheme(t)} 
                            style={{ 
                              background: currentTheme.name === t.name ? '#fff' : '#111827', 
                              color: currentTheme.name === t.name ? '#000' : '#f3f4f6',
                              border: currentTheme.name === t.name ? '1px solid #3b82f6' : '1px solid #1f2937',
                              padding: '0.75rem',
                              borderRadius: '8px',
                              display: 'flex',
                              alignItems: 'center',
                              gap: '0.75rem',
                              cursor: 'pointer',
                              transition: 'all 0.2s',
                              textAlign: 'left'
                            }}
                          >
                            <div style={{ width: '10px', height: '10px', borderRadius: '50%', backgroundColor: '#3b82f6' }}></div>
                            <span style={{ fontSize: '0.875rem', fontWeight: 600 }}>{t.name}</span>
                          </button>
                      ))}
                    </div>
                  </div>

                  <div style={{ marginBottom: '1.5rem' }}>
                    <label style={{ fontSize: '0.75rem', color: '#9ca3af', display: 'block', marginBottom: '1rem' }}>Custom Colors</label>
                    <div style={{ display: 'flex', flexDirection: 'column', gap: '1rem' }}>
                      {[
                        { label: 'Main Background', key: 'bgMain' },
                        { label: 'Sidebar Background', key: 'bgSidebar' },
                        { label: 'Text Color', key: 'textMain' },
                        { label: 'Accent Color', key: 'accent' }
                      ].map((item) => (
                        <div key={item.key} style={{ display: 'flex', alignItems: 'center', justifyContent: 'space-between' }}>
                          <span style={{ fontSize: '0.875rem', fontWeight: 500 }}>{item.label}</span>
                          <div style={{ display: 'flex', alignItems: 'center', gap: '0.75rem' }}>
                            <span style={{ fontSize: '0.75rem', fontFamily: 'monospace', color: '#6b7280' }}>{currentTheme[item.key as keyof AppTheme]?.toUpperCase()}</span>
                            <div style={{ position: 'relative', width: '32px', height: '32px', borderRadius: '4px', border: '1px solid #1f2937', background: currentTheme[item.key as keyof AppTheme] }}>
                              <input 
                                type="color" 
                                value={currentTheme[item.key as keyof AppTheme]} 
                                onChange={(e) => updateThemeColor(item.key as keyof AppTheme, e.target.value)}
                                style={{ position: 'absolute', inset: 0, width: '100%', height: '100%', cursor: 'pointer', opacity: 0 }}
                              />
                            </div>
                          </div>
                        </div>
                      ))}
                    </div>
                  </div>

                  <div style={{ borderTop: '1px solid #1f2937', paddingTop: '1.5rem', marginBottom: '1.5rem' }}>
                    <label style={{ fontSize: '0.75rem', color: '#9ca3af', display: 'block', marginBottom: '0.75rem' }}>Workspace Backup (.json)</label>
                    <div style={{ display: 'flex', gap: '0.5rem' }}>
                      <button 
                        onClick={exportWorkspaceJSON} 
                        className="btn" 
                        style={{ flex: 1, justifyContent: 'center', background: '#111827' }}
                        title="Download all files as JSON"
                      >
                        <Download size={14} /> Export JSON
                      </button>
                      <label className="btn" style={{ flex: 1, justifyContent: 'center', cursor: 'pointer', background: '#111827' }} title="Upload a workspace JSON file">
                        <Upload size={14} /> Import JSON
                        <input type="file" accept=".json" onChange={importWorkspaceJSON} style={{ display: 'none' }} />
                      </label>
                    </div>
                    <p style={{ fontSize: '0.65rem', color: '#6b7280', marginTop: '0.5rem', textAlign: 'center' }}>
                      Exports current structure including all 1000+ files.
                    </p>
                  </div>

                  <button 
                    onClick={() => setShowSettings(false)} 
                    style={{ 
                      width: '100%', 
                      padding: '0.875rem', 
                      background: '#3b82f6', 
                      color: 'white', 
                      border: 'none', 
                      borderRadius: '8px', 
                      fontWeight: 600, 
                      fontSize: '0.875rem',
                      cursor: 'pointer'
                    }}
                  >
                    Done
                  </button>
              </div>
          </div>
      )}
    </div>
  );
}

import React, { useMemo, useState, useRef, useEffect } from 'react';
import { 
  Folder, 
  FolderOpen, 
  FileText, 
  ChevronRight, 
  ChevronDown, 
  Plus, 
  FolderPlus, 
  Trash2, 
  Edit2,
  Check
} from 'lucide-react';
import { FileNode, NodeType } from '../types';

interface SidebarProps {
  nodes: FileNode[];
  activeFileId: string | null;
  expandedFolders: Set<string>;
  onFileSelect: (id: string) => void;
  onToggleFolder: (id: string) => void;
  onAddFile: (parentId: string | null) => void;
  onAddFolder: (parentId: string | null) => void;
  onDeleteNode: (id: string) => void;
  onRenameNode: (id: string, newName: string) => void;
  onMoveNode: (nodeId: string, newParentId: string | null) => void;
}

// Map structure for O(1) children lookup
type NodeMap = Map<string | null, FileNode[]>;

interface NodeItemProps extends Omit<SidebarProps, 'nodes'> {
  node: FileNode;
  level: number;
  nodeMap: NodeMap;
  editingId: string | null;
  onEditStart: (id: string) => void;
  onEditCancel: () => void;
  onContextMenu: (e: React.MouseEvent, node: FileNode) => void;
}

const NodeItem: React.FC<NodeItemProps> = ({ 
  node, 
  level, 
  nodeMap, 
  activeFileId, 
  expandedFolders, 
  editingId,
  onFileSelect, 
  onToggleFolder,
  onAddFile,
  onAddFolder,
  onDeleteNode,
  onRenameNode,
  onMoveNode,
  onEditStart,
  onEditCancel,
  onContextMenu
}) => {
  const isEditing = editingId === node.id;
  const [editName, setEditName] = useState(node.name);
  const [isDragOver, setIsDragOver] = useState(false);
  const inputRef = useRef<HTMLInputElement>(null);

  const isFolder = node.type === NodeType.FOLDER;
  const isExpanded = expandedFolders.has(node.id);
  const isActive = node.id === activeFileId;

  const children = nodeMap.get(node.id) || [];

  useEffect(() => {
    if (isEditing) {
      setEditName(node.name);
    }
  }, [isEditing, node.name]);

  useEffect(() => {
    if (isEditing && inputRef.current) {
      inputRef.current.focus();
      inputRef.current.select();
    }
  }, [isEditing]);

  const handleRenameSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    e.stopPropagation();
    if (editName.trim() && editName.trim() !== node.name) {
      onRenameNode(node.id, editName.trim());
    }
    onEditCancel();
  };

  const handleKeyDown = (e: React.KeyboardEvent) => {
    if (e.key === 'Escape') {
      onEditCancel();
    } else if (e.key === 'Enter') {
      handleRenameSubmit(e);
    }
  };

  const handleDeleteClick = (e: React.MouseEvent) => {
    e.stopPropagation();
    // Consistent with the context menu deletion
    onDeleteNode(node.id);
  };

  // Drag and Drop
  const handleDragStart = (e: React.DragEvent) => {
    e.dataTransfer.setData('nodeId', node.id);
    e.dataTransfer.effectAllowed = 'move';
  };

  const handleDragOver = (e: React.DragEvent) => {
    e.preventDefault();
    e.stopPropagation();
    if (isFolder) {
        setIsDragOver(true);
        e.dataTransfer.dropEffect = 'move';
    }
  };

  const handleDragLeave = (e: React.DragEvent) => {
    e.preventDefault();
    e.stopPropagation();
    setIsDragOver(false);
  };

  const handleDrop = (e: React.DragEvent) => {
    e.preventDefault();
    e.stopPropagation();
    setIsDragOver(false);

    if (!isFolder) return;

    const draggedNodeId = e.dataTransfer.getData('nodeId');
    if (draggedNodeId && draggedNodeId !== node.id) {
        onMoveNode(draggedNodeId, node.id);
        if (!isExpanded) {
            onToggleFolder(node.id);
        }
    }
  };

  return (
    <div style={{ userSelect: 'none' }}>
      <div 
        draggable={!isEditing}
        onDragStart={handleDragStart}
        onDragOver={handleDragOver}
        onDragLeave={handleDragLeave}
        onDrop={handleDrop}
        className={`sidebar-item ${isActive ? 'active' : ''}`}
        style={{ 
          paddingLeft: `${level * 12 + 8}px`,
          backgroundColor: isActive ? 'var(--accent-color)' : (isDragOver ? 'var(--hover-bg)' : undefined),
          outline: isDragOver ? '2px solid var(--accent-color)' : 'none',
          outlineOffset: '-2px'
        }}
        onClick={() => isFolder ? onToggleFolder(node.id) : onFileSelect(node.id)}
        onContextMenu={(e) => onContextMenu(e, node)}
      >
        <span style={{ marginRight: '4px', opacity: 0.7, display: 'flex' }}>
          {isFolder && (
            isExpanded ? <ChevronDown size={14} /> : <ChevronRight size={14} />
          )}
          {!isFolder && <span style={{ width: '14px', display: 'inline-block' }} />}
        </span>

        <span style={{ marginRight: '8px', color: isActive ? '#fff' : (isFolder ? '#eab308' : 'var(--accent-color)') }}>
          {isFolder ? (isExpanded ? <FolderOpen size={16} /> : <Folder size={16} />) : <FileText size={16} />}
        </span>

        {isEditing ? (
          <form onSubmit={handleRenameSubmit} onClick={e => e.stopPropagation()} style={{ flex: 1, display: 'flex', alignItems: 'center' }}>
            <input
              ref={inputRef}
              type="text"
              value={editName}
              onChange={(e) => setEditName(e.target.value)}
              onKeyDown={handleKeyDown}
              className="input-text"
              style={{ padding: '0 4px', height: '1.25rem', fontSize: '0.75rem' }}
              onBlur={handleRenameSubmit}
            />
            <button type="submit" style={{ marginLeft: '4px', color: '#4ade80', background: 'none', border: 'none', cursor: 'pointer' }}><Check size={12} /></button>
          </form>
        ) : (
          <span style={{ flex: 1, whiteSpace: 'nowrap', overflow: 'hidden', textOverflow: 'ellipsis' }}>{node.name}</span>
        )}

        {/* Quick Actions */}
        {!isEditing && (
          <div className="sidebar-actions">
             <button 
               onClick={(e) => { e.stopPropagation(); onEditStart(node.id); }}
               className="btn-icon"
               style={{ padding: '2px' }}
               title="Rename"
             >
               <Edit2 size={12} />
             </button>

             {isFolder && (
               <>
                 <button 
                  onClick={(e) => { e.stopPropagation(); onAddFile(node.id); }}
                  className="btn-icon"
                  style={{ padding: '2px' }}
                  title="New File"
                 >
                   <Plus size={12} />
                 </button>
                 <button 
                  onClick={(e) => { e.stopPropagation(); onAddFolder(node.id); }}
                  className="btn-icon"
                  style={{ padding: '2px' }}
                  title="New Folder"
                 >
                   <FolderPlus size={12} />
                 </button>
               </>
             )}

             <button 
                onClick={handleDeleteClick}
                className="btn-icon"
                style={{ padding: '2px', color: '#f87171' }}
                title="Delete"
             >
               <Trash2 size={12} />
             </button>
          </div>
        )}
      </div>

      {isFolder && isExpanded && (
        <div>
          {children.map(child => (
            <NodeItem 
              key={child.id} 
              node={child} 
              level={level + 1}
              nodeMap={nodeMap}
              editingId={editingId}
              onEditStart={onEditStart}
              onEditCancel={onEditCancel}
              onContextMenu={onContextMenu}
              {...{activeFileId, expandedFolders, onFileSelect, onToggleFolder, onAddFile, onAddFolder, onDeleteNode, onRenameNode, onMoveNode}}
            />
          ))}
          {children.length === 0 && (
            <div 
              style={{ paddingLeft: `${(level + 1) * 12 + 28}px`, color: 'var(--text-muted)', fontSize: '0.75rem', paddingTop: '0.25rem', paddingBottom: '0.25rem', fontStyle: 'italic' }}
            >
              Empty folder
            </div>
          )}
        </div>
      )}
    </div>
  );
};

export const Sidebar: React.FC<SidebarProps> = (props) => {
  const [editingId, setEditingId] = useState<string | null>(null);
  const [contextMenu, setContextMenu] = useState<{x: number, y: number, node: FileNode} | null>(null);
  const [isRootDragOver, setIsRootDragOver] = useState(false);

  const nodeMap = useMemo(() => {
    const map = new Map<string | null, FileNode[]>();
    props.nodes.forEach(node => {
      const parentId = node.parentId;
      if (!map.has(parentId)) map.set(parentId, []);
      map.get(parentId)!.push(node);
    });
    map.forEach(list => {
      list.sort((a, b) => {
        if (a.type !== b.type) return a.type === NodeType.FOLDER ? -1 : 1;
        return a.name.localeCompare(b.name);
      });
    });
    return map;
  }, [props.nodes]);

  const rootNodes = nodeMap.get(null) || [];

  const handleContextMenu = (e: React.MouseEvent, node: FileNode) => {
      e.preventDefault();
      e.stopPropagation();
      setContextMenu({ x: e.clientX, y: e.clientY, node });
  };

  const handleAction = (action: () => void) => {
      action();
      setContextMenu(null);
  };

  const handleRootDragOver = (e: React.DragEvent) => {
      e.preventDefault();
      if (e.target === e.currentTarget) setIsRootDragOver(true);
  };

  const handleRootDragLeave = (e: React.DragEvent) => {
      e.preventDefault();
      if (e.target === e.currentTarget) setIsRootDragOver(false);
  };

  const handleRootDrop = (e: React.DragEvent) => {
      e.preventDefault();
      setIsRootDragOver(false);
      if (e.target === e.currentTarget) {
          const draggedNodeId = e.dataTransfer.getData('nodeId');
          if (draggedNodeId) props.onMoveNode(draggedNodeId, null);
      }
  };

  return (
    <div 
      style={{ height: '100%', display: 'flex', flexDirection: 'column', position: 'relative', outline: isRootDragOver ? '2px solid var(--accent-color)' : 'none', outlineOffset: '-2px' }}
      onContextMenu={(e) => e.preventDefault()}
      onDragOver={handleRootDragOver}
      onDragLeave={handleRootDragLeave}
      onDrop={handleRootDrop}
      onClick={() => setEditingId(null)}
    >
      {/* Context Menu */}
      {contextMenu && (
          <div 
            style={{ position: 'fixed', inset: 0, zIndex: 50 }}
            onClick={() => setContextMenu(null)}
            onContextMenu={(e) => { e.preventDefault(); setContextMenu(null); }}
          >
              <div 
                className="context-menu"
                style={{ 
                    top: Math.min(contextMenu.y, window.innerHeight - 200), 
                    left: Math.min(contextMenu.x, window.innerWidth - 170),
                }}
              >
                  <div style={{ padding: '0.5rem 1rem', fontSize: '0.75rem', fontWeight: 'bold', opacity: 0.5, borderBottom: '1px solid var(--border-color)', marginBottom: '0.25rem' }}>
                      {contextMenu.node.name}
                  </div>
                  <button onClick={() => handleAction(() => setEditingId(contextMenu.node.id))} className="context-item">
                      <Edit2 size={14} /> Rename
                  </button>
                  {contextMenu.node.type === NodeType.FOLDER && (
                      <>
                        <button onClick={() => handleAction(() => props.onAddFile(contextMenu.node.id))} className="context-item">
                            <Plus size={14} /> New File
                        </button>
                        <button onClick={() => handleAction(() => props.onAddFolder(contextMenu.node.id))} className="context-item">
                            <FolderPlus size={14} /> New Folder
                        </button>
                      </>
                  )}
                  <div style={{ height: '1px', backgroundColor: 'var(--border-color)', margin: '0.25rem 0' }}></div>
                  <button 
                    onClick={() => handleAction(() => {
                        props.onDeleteNode(contextMenu.node.id);
                    })}
                    className="context-item"
                    style={{ color: '#f87171' }}
                  >
                      <Trash2 size={14} /> Delete
                  </button>
              </div>
          </div>
      )}

      <div className="sidebar-header">
        <h2 className="sidebar-title">
           <FolderOpen size={18} style={{ color: 'var(--accent-color)' }}/>
           EXPLORER
        </h2>
        <div className="flex gap-1">
          <button onClick={() => props.onAddFile(null)} className="btn-icon" title="New File at Root"><Plus size={16} /></button>
          <button onClick={() => props.onAddFolder(null)} className="btn-icon" title="New Folder at Root"><FolderPlus size={16} /></button>
        </div>
      </div>

      <div className="sidebar-content">
        {rootNodes.map(node => (
          <NodeItem 
            key={node.id} 
            node={node} 
            level={0} 
            nodeMap={nodeMap}
            editingId={editingId}
            onEditStart={setEditingId}
            onEditCancel={() => setEditingId(null)}
            onContextMenu={handleContextMenu}
            {...props} 
          />
        ))}
        {rootNodes.length === 0 && (
          <div style={{ textAlign: 'center', marginTop: '2.5rem', fontSize: '0.875rem', padding: '1rem', color: 'var(--text-muted)' }}>
            No files found.<br/>Right click or use buttons to add.
          </div>
        )}
      </div>
    </div>
  );
};

import React, { useState, useEffect, useCallback, useMemo } from 'react';
import { v4 as uuidv4 } from 'uuid';
import { 
  Download, Upload, Palette, PanelLeft, Edit3, Columns, Eye, X, FileText, Plus, FileDown
} from 'lucide-react';
import { Sidebar } from './components/Sidebar';
import { Editor } from './components/Editor';
import { FileNode, NodeType, AppTheme, ImportData } from './types';
import { initialNodes } from './initialData';

const themes: Record<string, AppTheme> = {
  dark: { name: 'Dark', bgMain: '#030712', bgSidebar: '#111827', textMain: '#f3f4f6', textMuted: '#9ca3af', border: '#1f2937', accent: '#3b82f6', hover: 'rgba(255, 255, 255, 0.05)' },
  light: { name: 'Light', bgMain: '#ffffff', bgSidebar: '#f3f4f6', textMain: '#111827', textMuted: '#6b7280', border: '#e5e7eb', accent: '#3b82f6', hover: 'rgba(0, 0, 0, 0.05)' },
  navy: { name: 'Navy', bgMain: '#0a192f', bgSidebar: '#112240', textMain: '#ccd6f6', textMuted: '#8892b0', border: '#233554', accent: '#64ffda', hover: 'rgba(100, 255, 218, 0.1)' },
  dracula: { name: 'Dracula', bgMain: '#282a36', bgSidebar: '#21222c', textMain: '#f8f8f2', textMuted: '#6272a4', border: '#44475a', accent: '#ff79c6', hover: 'rgba(255, 255, 255, 0.1)' }
};

export default function App() {
  const [nodes, setNodes] = useState<FileNode[]>(() => {
    const saved = localStorage.getItem('mathsci-fs');
    return saved ? JSON.parse(saved) : initialNodes;
  });
  const [activeFileId, setActiveFileId] = useState<string | null>('file-intro');
  const [expandedFolders, setExpandedFolders] = useState<Set<string>>(new Set(['folder-welcome', 'folder-docs']));
  const [showSettings, setShowSettings] = useState(false);
  const [isSidebarOpen, setIsSidebarOpen] = useState(true);
  const [editorView, setEditorView] = useState<'split' | 'editor' | 'preview'>('split');
  const [currentTheme, setCurrentTheme] = useState<AppTheme>(() => {
    const saved = localStorage.getItem('mathsci-theme');
    return saved ? JSON.parse(saved) : themes.dark;
  });

  useEffect(() => {
    const root = document.documentElement;
    root.style.setProperty('--bg-main', currentTheme.bgMain);
    root.style.setProperty('--bg-sidebar', currentTheme.bgSidebar);
    root.style.setProperty('--bg-toolbar', currentTheme.bgSidebar);
    root.style.setProperty('--text-main', currentTheme.textMain);
    root.style.setProperty('--text-muted', currentTheme.textMuted);
    root.style.setProperty('--border-color', currentTheme.border);
    root.style.setProperty('--accent-color', currentTheme.accent);
    root.style.setProperty('--hover-bg', currentTheme.hover);
    localStorage.setItem('mathsci-theme', JSON.stringify(currentTheme));
  }, [currentTheme]);

  useEffect(() => {
    localStorage.setItem('mathsci-fs', JSON.stringify(nodes));
  }, [nodes]);

  const handleUpdateContent = useCallback((content: string) => {
    if (!activeFileId) return;
    setNodes(prev => prev.map(n => n.id === activeFileId ? { ...n, content } : n));
  }, [activeFileId]);

  const activeFile = useMemo(() => nodes.find(n => n.id === activeFileId), [nodes, activeFileId]);

  const handleExportPDF = () => {
    const element = document.getElementById('markdown-preview');
    if (!element) return alert("Switch to Preview or Split view to export.");
    const filename = (activeFile?.name || 'document') + '.pdf';
    window.html2pdf().set({
      margin: 1, filename, image: { type: 'jpeg', quality: 0.98 },
      html2canvas: { scale: 2, useCORS: true, backgroundColor: currentTheme.bgMain },
      jsPDF: { unit: 'in', format: 'letter', orientation: 'portrait' }
    }).from(element).save();
  };

  const exportWorkspaceJSON = () => {
    const data: ImportData = { version: 1, nodes };
    const blob = new Blob([JSON.stringify(data, null, 2)], { type: 'application/json' });
    const url = URL.createObjectURL(blob);
    const a = document.createElement('a');
    a.href = url;
    a.download = `mathsci-workspace-${new Date().toISOString().split('T')[0]}.json`;
    a.click();
    URL.revokeObjectURL(url);
  };

  const importWorkspaceJSON = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;
    const reader = new FileReader();
    reader.onload = (event) => {
      try {
        const data = JSON.parse(event.target?.result as string) as ImportData;
        if (data.nodes && Array.isArray(data.nodes)) {
          setNodes(data.nodes);
          alert(`Successfully imported ${data.nodes.length} items.`);
        }
      } catch (err) {
        alert("Error parsing workspace file.");
      }
    };
    reader.readAsText(file);
  };

  const updateThemeColor = (key: keyof AppTheme, color: string) => {
    setCurrentTheme(prev => ({ ...prev, [key]: color }));
  };

  const handleDeleteNode = (id: string) => {
    const nodeToDelete = nodes.find(n => n.id === id);
    if (!nodeToDelete) return;

    const message = `Are you sure you want to delete "${nodeToDelete.name}"?${nodeToDelete.type === NodeType.FOLDER ? ' All files inside will be deleted.' : ''}`;

    if (window.confirm(message)) {
      setNodes(prev => {
        const idsToDelete = new Set<string>();
        const findChildren = (parentId: string) => {
          idsToDelete.add(parentId);
          prev.filter(n => n.parentId === parentId).forEach(child => findChildren(child.id));
        };
        findChildren(id);

        // If current active file is being deleted, reset it
        if (activeFileId && idsToDelete.has(activeFileId)) {
          setActiveFileId(null);
        }

        return prev.filter(n => !idsToDelete.has(n.id));
      });
    }
  };

  return (
    <div className="app-container" style={{ background: 'var(--bg-main)' }}>
      <div className="sidebar-wrapper" style={{ width: isSidebarOpen ? '280px' : '0' }}>
         <Sidebar 
            nodes={nodes}
            activeFileId={activeFileId}
            expandedFolders={expandedFolders}
            onFileSelect={setActiveFileId}
            onToggleFolder={(id) => setExpandedFolders(prev => {
                const next = new Set(prev);
                if (next.has(id)) next.delete(id); else next.add(id);
                return next;
            })}
            onAddFile={(parentId) => {
                const id = uuidv4();
                const newNode: FileNode = { id, parentId, name: 'Untitled', type: NodeType.FILE, content: '', createdAt: Date.now() };
                setNodes(prev => [...prev, newNode]);
                setActiveFileId(id);
            }}
            onAddFolder={(parentId) => {
                const id = uuidv4();
                setNodes(prev => [...prev, { id, parentId, name: 'New Folder', type: NodeType.FOLDER, content: '', createdAt: Date.now() }]);
            }}
            onDeleteNode={handleDeleteNode}
            onRenameNode={(id, name) => setNodes(prev => prev.map(n => n.id === id ? { ...n, name } : n))}
            onMoveNode={(id, parentId) => setNodes(prev => prev.map(n => n.id === id ? { ...n, parentId } : n))}
         />
      </div>

      <div className="main-content" style={{ flex: 1, display: 'flex', flexDirection: 'column', overflow: 'hidden' }}>
        <div className="toolbar">
            <div style={{ display: 'flex', alignItems: 'center', gap: '0.75rem' }}>
                <button onClick={() => setIsSidebarOpen(!isSidebarOpen)} className="btn-icon"><PanelLeft size={18} /></button>
                <h1 className="app-title">MathSci</h1>
            </div>
            <div style={{ display: 'flex', alignItems: 'center', gap: '0.5rem' }}>
                <button onClick={handleExportPDF} className="btn"><FileDown size={14} /> PDF</button>
                <button onClick={() => setShowSettings(true)} className="btn"><Palette size={14} /> Theme</button>
                <div style={{ display: 'flex', background: 'var(--bg-main)', border: '1px solid var(--border-color)', borderRadius: '6px', padding: '2px', gap: '2px' }}>
                   <button onClick={() => setEditorView('editor')} className="btn-icon" style={{ color: editorView === 'editor' ? 'var(--accent-color)' : 'var(--text-muted)' }} title="Editor only"><Edit3 size={16} /></button>
                   <button onClick={() => setEditorView('split')} className="btn-icon" style={{ color: editorView === 'split' ? 'var(--accent-color)' : 'var(--text-muted)' }} title="Split view"><Columns size={16} /></button>
                   <button onClick={() => setEditorView('preview')} className="btn-icon" style={{ color: editorView === 'preview' ? 'var(--accent-color)' : 'var(--text-muted)' }} title="Preview only"><Eye size={16} /></button>
                </div>
            </div>
        </div>

        <div style={{ flex: 1, overflow: 'hidden' }}>
            {activeFile ? (
                <Editor 
                  key={activeFileId}
                  content={activeFile.content} 
                  fileName={activeFile.name}
                  allNodes={nodes}
                  viewMode={editorView}
                  onChange={handleUpdateContent} 
                />
            ) : (
              <div style={{ height: '100%', display: 'flex', alignItems: 'center', justifyContent: 'center', color: 'var(--text-muted)', textAlign: 'center' }}>
                  <div style={{ padding: '2rem' }}>
                    <FileText size={48} style={{ marginBottom: '1rem', opacity: 0.2 }} />
                    <p>Select a file from the sidebar or create a new one to begin.</p>
                  </div>
              </div>
            )}
        </div>
      </div>

      {showSettings && (
          <div className="modal-overlay" onClick={() => setShowSettings(false)}>
              <div className="modal" onClick={e => e.stopPropagation()} style={{ background: '#0a0f1d', padding: '1.5rem', borderRadius: '16px', boxShadow: '0 25px 50px -12px rgba(0, 0, 0, 0.5)', border: '1px solid #1f2937', color: '#fff', width: '420px' }}>
                  <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: '1.5rem' }}>
                    <div style={{ display: 'flex', alignItems: 'center', gap: '0.75rem' }}>
                      <Palette size={20} color="#3b82f6" />
                      <h3 style={{ margin: 0, fontSize: '1.1rem', fontWeight: 600 }}>Theme & Workspace</h3>
                    </div>
                    <button onClick={() => setShowSettings(false)} style={{ background: 'none', border: 'none', color: '#9ca3af', cursor: 'pointer' }}><X size={20}/></button>
                  </div>

                  <div style={{ marginBottom: '1.5rem' }}>
                    <label style={{ fontSize: '0.75rem', color: '#9ca3af', display: 'block', marginBottom: '0.75rem' }}>Presets</label>
                    <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: '0.75rem' }}>
                      {Object.entries(themes).map(([k, t]) => (
                          <button 
                            key={k} 
                            onClick={() => setCurrentTheme(t)} 
                            style={{ 
                              background: currentTheme.name === t.name ? '#fff' : '#111827', 
                              color: currentTheme.name === t.name ? '#000' : '#f3f4f6',
                              border: currentTheme.name === t.name ? '1px solid #3b82f6' : '1px solid #1f2937',
                              padding: '0.75rem',
                              borderRadius: '8px',
                              display: 'flex',
                              alignItems: 'center',
                              gap: '0.75rem',
                              cursor: 'pointer',
                              transition: 'all 0.2s',
                              textAlign: 'left'
                            }}
                          >
                            <div style={{ width: '10px', height: '10px', borderRadius: '50%', backgroundColor: '#3b82f6' }}></div>
                            <span style={{ fontSize: '0.875rem', fontWeight: 600 }}>{t.name}</span>
                          </button>
                      ))}
                    </div>
                  </div>

                  <div style={{ marginBottom: '1.5rem' }}>
                    <label style={{ fontSize: '0.75rem', color: '#9ca3af', display: 'block', marginBottom: '1rem' }}>Custom Colors</label>
                    <div style={{ display: 'flex', flexDirection: 'column', gap: '1rem' }}>
                      {[
                        { label: 'Main Background', key: 'bgMain' },
                        { label: 'Sidebar Background', key: 'bgSidebar' },
                        { label: 'Text Color', key: 'textMain' },
                        { label: 'Accent Color', key: 'accent' }
                      ].map((item) => (
                        <div key={item.key} style={{ display: 'flex', alignItems: 'center', justifyContent: 'space-between' }}>
                          <span style={{ fontSize: '0.875rem', fontWeight: 500 }}>{item.label}</span>
                          <div style={{ display: 'flex', alignItems: 'center', gap: '0.75rem' }}>
                            <span style={{ fontSize: '0.75rem', fontFamily: 'monospace', color: '#6b7280' }}>{currentTheme[item.key as keyof AppTheme]?.toUpperCase()}</span>
                            <div style={{ position: 'relative', width: '32px', height: '32px', borderRadius: '4px', border: '1px solid #1f2937', background: currentTheme[item.key as keyof AppTheme] }}>
                              <input 
                                type="color" 
                                value={currentTheme[item.key as keyof AppTheme]} 
                                onChange={(e) => updateThemeColor(item.key as keyof AppTheme, e.target.value)}
                                style={{ position: 'absolute', inset: 0, width: '100%', height: '100%', cursor: 'pointer', opacity: 0 }}
                              />
                            </div>
                          </div>
                        </div>
                      ))}
                    </div>
                  </div>

                  <div style={{ borderTop: '1px solid #1f2937', paddingTop: '1.5rem', marginBottom: '1.5rem' }}>
                    <label style={{ fontSize: '0.75rem', color: '#9ca3af', display: 'block', marginBottom: '0.75rem' }}>Workspace Backup (.json)</label>
                    <div style={{ display: 'flex', gap: '0.5rem' }}>
                      <button 
                        onClick={exportWorkspaceJSON} 
                        className="btn" 
                        style={{ flex: 1, justifyContent: 'center', background: '#111827' }}
                        title="Download all files as JSON"
                      >
                        <Download size={14} /> Export JSON
                      </button>
                      <label className="btn" style={{ flex: 1, justifyContent: 'center', cursor: 'pointer', background: '#111827' }} title="Upload a workspace JSON file">
                        <Upload size={14} /> Import JSON
                        <input type="file" accept=".json" onChange={importWorkspaceJSON} style={{ display: 'none' }} />
                      </label>
                    </div>
                  </div>

                  <button 
                    onClick={() => setShowSettings(false)} 
                    style={{ 
                      width: '100%', 
                      padding: '0.875rem', 
                      background: '#3b82f6', 
                      color: 'white', 
                      border: 'none', 
                      borderRadius: '8px', 
                      fontWeight: 600, 
                      fontSize: '0.875rem',
                      cursor: 'pointer'
                    }}
                  >
                    Done
                  </button>
              </div>
          </div>
      )}
    </div>
  );
}

import React, { useState, useEffect, useCallback, useMemo } from 'react';
import { v4 as uuidv4 } from 'uuid';
import { 
  Download, Upload, Palette, PanelLeft, Edit3, Columns, Eye, X, FileText, Plus, FileDown
} from 'lucide-react';
import { Sidebar } from './components/Sidebar';
import { Editor } from './components/Editor';
import { FileNode, NodeType, AppTheme, ImportData } from './types';
import { initialNodes } from './initialData';

const themes: Record<string, AppTheme> = {
  dark: { name: 'Dark', bgMain: '#030712', bgSidebar: '#111827', textMain: '#f3f4f6', textMuted: '#9ca3af', border: '#1f2937', accent: '#3b82f6', hover: 'rgba(255, 255, 255, 0.05)' },
  light: { name: 'Light', bgMain: '#ffffff', bgSidebar: '#f3f4f6', textMain: '#111827', textMuted: '#6b7280', border: '#e5e7eb', accent: '#3b82f6', hover: 'rgba(0, 0, 0, 0.05)' },
  navy: { name: 'Navy', bgMain: '#0a192f', bgSidebar: '#112240', textMain: '#ccd6f6', textMuted: '#8892b0', border: '#233554', accent: '#64ffda', hover: 'rgba(100, 255, 218, 0.1)' },
  dracula: { name: 'Dracula', bgMain: '#282a36', bgSidebar: '#21222c', textMain: '#f8f8f2', textMuted: '#6272a4', border: '#44475a', accent: '#ff79c6', hover: 'rgba(255, 255, 255, 0.1)' }
};

export default function App() {
  const [nodes, setNodes] = useState<FileNode[]>(() => {
    const saved = localStorage.getItem('mathsci-fs');
    // Clean initial nodes to remove .md if they exist
    const baseNodes = saved ? JSON.parse(saved) : initialNodes;
    return baseNodes.map((n: FileNode) => ({...n, name: n.name.replace(/\.md$/, '')}));
  });

  const [activeFileId, setActiveFileId] = useState<string | null>('file-intro');
  const [expandedFolders, setExpandedFolders] = useState<Set<string>>(new Set(['folder-welcome', 'folder-docs']));
  const [showSettings, setShowSettings] = useState(false);
  const [isSidebarOpen, setIsSidebarOpen] = useState(true);
  const [editorView, setEditorView] = useState<'split' | 'editor' | 'preview'>('split');
  const [currentTheme, setCurrentTheme] = useState<AppTheme>(() => {
    const saved = localStorage.getItem('mathsci-theme');
    return saved ? JSON.parse(saved) : themes.dark;
  });

  useEffect(() => {
    const root = document.documentElement;
    root.style.setProperty('--bg-main', currentTheme.bgMain);
    root.style.setProperty('--bg-sidebar', currentTheme.bgSidebar);
    root.style.setProperty('--bg-toolbar', currentTheme.bgSidebar);
    root.style.setProperty('--text-main', currentTheme.textMain);
    root.style.setProperty('--text-muted', currentTheme.textMuted);
    root.style.setProperty('--border-color', currentTheme.border);
    root.style.setProperty('--accent-color', currentTheme.accent);
    root.style.setProperty('--hover-bg', currentTheme.hover);
    localStorage.setItem('mathsci-theme', JSON.stringify(currentTheme));
  }, [currentTheme]);

  useEffect(() => {
    localStorage.setItem('mathsci-fs', JSON.stringify(nodes));
  }, [nodes]);

  const handleUpdateContent = useCallback((content: string) => {
    if (!activeFileId) return;
    setNodes(prev => prev.map(n => n.id === activeFileId ? { ...n, content } : n));
  }, [activeFileId]);

  const activeFile = useMemo(() => nodes.find(n => n.id === activeFileId), [nodes, activeFileId]);

  const handleExportPDF = () => {
    const element = document.getElementById('markdown-preview');
    if (!element) return alert("Switch to Preview or Split view to export.");
    const filename = (activeFile?.name || 'document') + '.pdf';
    window.html2pdf().set({
      margin: 1, filename, image: { type: 'jpeg', quality: 0.98 },
      html2canvas: { scale: 2, useCORS: true, backgroundColor: currentTheme.bgMain },
      jsPDF: { unit: 'in', format: 'letter', orientation: 'portrait' }
    }).from(element).save();
  };

  const exportWorkspaceJSON = () => {
    const data: ImportData = { version: 1, nodes };
    const blob = new Blob([JSON.stringify(data, null, 2)], { type: 'application/json' });
    const url = URL.createObjectURL(blob);
    const a = document.createElement('a');
    a.href = url;
    a.download = `mathsci-workspace.json`;
    a.click();
    URL.revokeObjectURL(url);
  };

  const importWorkspaceJSON = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;
    const reader = new FileReader();
    reader.onload = (event) => {
      try {
        const data = JSON.parse(event.target?.result as string) as ImportData;
        if (data.nodes && Array.isArray(data.nodes)) {
          setNodes(data.nodes);
          alert(`Imported ${data.nodes.length} items.`);
        }
      } catch (err) {
        alert("Error parsing workspace file.");
      }
    };
    reader.readAsText(file);
  };

  const updateThemeColor = (key: keyof AppTheme, color: string) => {
    setCurrentTheme(prev => ({ ...prev, [key]: color }));
  };

  const handleDeleteNode = (id: string) => {
    const nodeToDelete = nodes.find(n => n.id === id);
    if (!nodeToDelete) return;

    if (window.confirm(`Delete "${nodeToDelete.name}"? This cannot be undone.`)) {
      setNodes(prev => {
        const idsToDelete = new Set<string>();
        const collectIds = (parentId: string) => {
          idsToDelete.add(parentId);
          prev.filter(n => n.parentId === parentId).forEach(child => collectIds(child.id));
        };
        collectIds(id);

        if (activeFileId && idsToDelete.has(activeFileId)) {
          setActiveFileId(null);
        }

        return prev.filter(n => !idsToDelete.has(n.id));
      });
    }
  };

  return (
    <div className="app-container" style={{ background: 'var(--bg-main)' }}>
      <div className="sidebar-wrapper" style={{ width: isSidebarOpen ? '280px' : '0' }}>
         <Sidebar 
            nodes={nodes}
            activeFileId={activeFileId}
            expandedFolders={expandedFolders}
            onFileSelect={setActiveFileId}
            onToggleFolder={(id) => setExpandedFolders(prev => {
                const next = new Set(prev);
                if (next.has(id)) next.delete(id); else next.add(id);
                return next;
            })}
            onAddFile={(parentId) => {
                const id = uuidv4();
                const newNode: FileNode = { id, parentId, name: 'Untitled', type: NodeType.FILE, content: '', createdAt: Date.now() };
                setNodes(prev => [...prev, newNode]);
                setActiveFileId(id);
            }}
            onAddFolder={(parentId) => {
                const id = uuidv4();
                setNodes(prev => [...prev, { id, parentId, name: 'New Folder', type: NodeType.FOLDER, content: '', createdAt: Date.now() }]);
            }}
            onDeleteNode={handleDeleteNode}
            onRenameNode={(id, name) => setNodes(prev => prev.map(n => n.id === id ? { ...n, name } : n))}
            onMoveNode={(id, parentId) => setNodes(prev => prev.map(n => n.id === id ? { ...n, parentId } : n))}
         />
      </div>

      <div className="main-content" style={{ flex: 1, display: 'flex', flexDirection: 'column', overflow: 'hidden' }}>
        <div className="toolbar">
            <div style={{ display: 'flex', alignItems: 'center', gap: '0.75rem' }}>
                <button onClick={() => setIsSidebarOpen(!isSidebarOpen)} className="btn-icon"><PanelLeft size={18} /></button>
                <h1 className="app-title">MathSci</h1>
            </div>
            <div style={{ display: 'flex', alignItems: 'center', gap: '0.5rem' }}>
                <button onClick={handleExportPDF} className="btn"><FileDown size={14} /> PDF</button>
                <button onClick={() => setShowSettings(true)} className="btn"><Palette size={14} /> Theme</button>
                <div style={{ display: 'flex', background: 'var(--bg-main)', border: '1px solid var(--border-color)', borderRadius: '6px', padding: '2px', gap: '2px' }}>
                   <button onClick={() => setEditorView('editor')} className="btn-icon" style={{ color: editorView === 'editor' ? 'var(--accent-color)' : 'var(--text-muted)' }} title="Editor only"><Edit3 size={16} /></button>
                   <button onClick={() => setEditorView('split')} className="btn-icon" style={{ color: editorView === 'split' ? 'var(--accent-color)' : 'var(--text-muted)' }} title="Split view"><Columns size={16} /></button>
                   <button onClick={() => setEditorView('preview')} className="btn-icon" style={{ color: editorView === 'preview' ? 'var(--accent-color)' : 'var(--text-muted)' }} title="Preview only"><Eye size={16} /></button>
                </div>
            </div>
        </div>

        <div style={{ flex: 1, overflow: 'hidden' }}>
            {activeFile ? (
                <Editor 
                  key={activeFileId}
                  content={activeFile.content} 
                  fileName={activeFile.name}
                  allNodes={nodes}
                  viewMode={editorView}
                  onChange={handleUpdateContent} 
                />
            ) : (
              <div style={{ height: '100%', display: 'flex', alignItems: 'center', justifyContent: 'center', color: 'var(--text-muted)', textAlign: 'center' }}>
                  <div style={{ padding: '2rem' }}>
                    <FileText size={48} style={{ marginBottom: '1rem', opacity: 0.2 }} />
                    <p>Select a file from the sidebar or create a new one to begin.</p>
                  </div>
              </div>
            )}
        </div>
      </div>

      {showSettings && (
          <div className="modal-overlay" onClick={() => setShowSettings(false)}>
              <div className="modal" onClick={e => e.stopPropagation()} style={{ background: '#0a0f1d', padding: '1.5rem', borderRadius: '16px', border: '1px solid #1f2937', color: '#fff', width: '420px' }}>
                  <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: '1.5rem' }}>
                    <h3 style={{ margin: 0 }}>Workspace Settings</h3>
                    <button onClick={() => setShowSettings(false)} className="btn-icon"><X size={20}/></button>
                  </div>
                  <div style={{ display: 'flex', flexDirection: 'column', gap: '1rem' }}>
                    <button onClick={exportWorkspaceJSON} className="btn"><Download size={14} /> Export Workspace JSON</button>
                    <label className="btn" style={{ cursor: 'pointer' }}>
                      <Upload size={14} /> Import Workspace JSON
                      <input type="file" accept=".json" onChange={importWorkspaceJSON} style={{ display: 'none' }} />
                    </label>
                  </div>
                  <button onClick={() => setShowSettings(false)} className="btn-primary w-full" style={{ marginTop: '1.5rem', padding: '0.75rem' }}>Done</button>
              </div>
          </div>
      )}
    </div>
  );
}

import React, { useMemo, useState, useRef, useEffect } from 'react';
import { 
  Folder, 
  FolderOpen, 
  FileText, 
  ChevronRight, 
  ChevronDown, 
  Plus, 
  FolderPlus, 
  Trash2, 
  Edit2,
  Check
} from 'lucide-react';
import { FileNode, NodeType } from '../types';

interface SidebarProps {
  nodes: FileNode[];
  activeFileId: string | null;
  expandedFolders: Set<string>;
  onFileSelect: (id: string) => void;
  onToggleFolder: (id: string) => void;
  onAddFile: (parentId: string | null) => void;
  onAddFolder: (parentId: string | null) => void;
  onDeleteNode: (id: string) => void;
  onRenameNode: (id: string, newName: string) => void;
  onMoveNode: (nodeId: string, newParentId: string | null) => void;
}

type NodeMap = Map<string | null, FileNode[]>;

interface NodeItemProps extends Omit<SidebarProps, 'nodes'> {
  node: FileNode;
  level: number;
  nodeMap: NodeMap;
  editingId: string | null;
  onEditStart: (id: string) => void;
  onEditCancel: () => void;
  onContextMenu: (e: React.MouseEvent, node: FileNode) => void;
}

const NodeItem: React.FC<NodeItemProps> = ({ 
  node, 
  level, 
  nodeMap, 
  activeFileId, 
  expandedFolders, 
  editingId,
  onFileSelect, 
  onToggleFolder,
  onAddFile,
  onAddFolder,
  onDeleteNode,
  onRenameNode,
  onMoveNode,
  onEditStart,
  onEditCancel,
  onContextMenu
}) => {
  const isEditing = editingId === node.id;
  const [editName, setEditName] = useState(node.name);
  const [isDragOver, setIsDragOver] = useState(false);
  const inputRef = useRef<HTMLInputElement>(null);

  const isFolder = node.type === NodeType.FOLDER;
  const isExpanded = expandedFolders.has(node.id);
  const isActive = node.id === activeFileId;

  const children = nodeMap.get(node.id) || [];

  useEffect(() => {
    if (isEditing) setEditName(node.name);
  }, [isEditing, node.name]);

  useEffect(() => {
    if (isEditing && inputRef.current) {
      inputRef.current.focus();
      inputRef.current.select();
    }
  }, [isEditing]);

  const handleRenameSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    e.stopPropagation();
    if (editName.trim() && editName.trim() !== node.name) {
      onRenameNode(node.id, editName.trim());
    }
    onEditCancel();
  };

  const handleKeyDown = (e: React.KeyboardEvent) => {
    if (e.key === 'Escape') onEditCancel();
    else if (e.key === 'Enter') handleRenameSubmit(e);
  };

  // Drag and Drop Logic
  const handleDragStart = (e: React.DragEvent) => {
    e.dataTransfer.setData('nodeId', node.id);
    e.dataTransfer.effectAllowed = 'move';
  };

  const handleDragOver = (e: React.DragEvent) => {
    e.preventDefault();
    e.stopPropagation();
    if (isFolder) {
      setIsDragOver(true);
      e.dataTransfer.dropEffect = 'move';
    }
  };

  const handleDragLeave = (e: React.DragEvent) => {
    e.preventDefault();
    e.stopPropagation();
    setIsDragOver(false);
  };

  const handleDrop = (e: React.DragEvent) => {
    e.preventDefault();
    e.stopPropagation();
    setIsDragOver(false);
    if (!isFolder) return;
    const draggedNodeId = e.dataTransfer.getData('nodeId');
    if (draggedNodeId && draggedNodeId !== node.id) {
      onMoveNode(draggedNodeId, node.id);
      if (!isExpanded) onToggleFolder(node.id);
    }
  };

  return (
    <div style={{ userSelect: 'none' }}>
      <div 
        draggable={!isEditing}
        onDragStart={handleDragStart}
        onDragOver={handleDragOver}
        onDragLeave={handleDragLeave}
        onDrop={handleDrop}
        className={`sidebar-item ${isActive ? 'active' : ''}`}
        style={{ 
          paddingLeft: `${level * 12 + 8}px`,
          backgroundColor: isActive ? 'var(--accent-color)' : (isDragOver ? 'var(--hover-bg)' : undefined),
          outline: isDragOver ? '2px solid var(--accent-color)' : 'none',
          outlineOffset: '-2px'
        }}
        onClick={() => isFolder ? onToggleFolder(node.id) : onFileSelect(node.id)}
        onContextMenu={(e) => onContextMenu(e, node)}
      >
        <span style={{ marginRight: '4px', opacity: 0.7, display: 'flex' }}>
          {isFolder && (isExpanded ? <ChevronDown size={14} /> : <ChevronRight size={14} />)}
          {!isFolder && <span style={{ width: '14px' }} />}
        </span>

        <span style={{ marginRight: '8px', color: isActive ? '#fff' : (isFolder ? '#eab308' : 'var(--accent-color)') }}>
          {isFolder ? (isExpanded ? <FolderOpen size={16} /> : <Folder size={16} />) : <FileText size={16} />}
        </span>

        {isEditing ? (
          <form onSubmit={handleRenameSubmit} onClick={e => e.stopPropagation()} style={{ flex: 1, display: 'flex', alignItems: 'center' }}>
            <input
              ref={inputRef}
              type="text"
              value={editName}
              onChange={(e) => setEditName(e.target.value)}
              onKeyDown={handleKeyDown}
              className="input-text"
              style={{ padding: '0 4px', height: '1.25rem', fontSize: '0.75rem', width: '100%' }}
              onBlur={handleRenameSubmit}
            />
          </form>
        ) : (
          <span style={{ flex: 1, whiteSpace: 'nowrap', overflow: 'hidden', textOverflow: 'ellipsis' }}>{node.name}</span>
        )}

        {!isEditing && (
          <div className="sidebar-actions">
             <button 
               onClick={(e) => { e.stopPropagation(); onEditStart(node.id); }}
               className="btn-icon" title="Rename"
             >
               <Edit2 size={12} />
             </button>
             {isFolder && (
               <button 
                onClick={(e) => { e.stopPropagation(); onAddFile(node.id); }}
                className="btn-icon" title="New File"
               >
                 <Plus size={12} />
               </button>
             )}
             <button 
                onClick={(e) => { e.stopPropagation(); onDeleteNode(node.id); }}
                className="btn-icon" style={{ color: '#f87171' }} title="Delete"
             >
               <Trash2 size={12} />
             </button>
          </div>
        )}
      </div>

      {isFolder && isExpanded && (
        <div>
          {children.map(child => (
            <NodeItem 
              key={child.id} 
              node={child} 
              level={level + 1}
              nodeMap={nodeMap}
              editingId={editingId}
              onEditStart={onEditStart}
              onEditCancel={onEditCancel}
              onContextMenu={onContextMenu}
              activeFileId={activeFileId}
              expandedFolders={expandedFolders}
              onFileSelect={onFileSelect}
              onToggleFolder={onToggleFolder}
              onAddFile={onAddFile}
              onAddFolder={onAddFolder}
              onDeleteNode={onDeleteNode}
              onRenameNode={onRenameNode}
              onMoveNode={onMoveNode}
            />
          ))}
          {children.length === 0 && (
            <div style={{ paddingLeft: `${(level + 1) * 12 + 28}px`, color: 'var(--text-muted)', fontSize: '0.75rem', paddingBottom: '0.25rem', fontStyle: 'italic' }}>
              Empty
            </div>
          )}
        </div>
      )}
    </div>
  );
};

export const Sidebar: React.FC<SidebarProps> = (props) => {
  const [editingId, setEditingId] = useState<string | null>(null);
  const [contextMenu, setContextMenu] = useState<{x: number, y: number, node: FileNode} | null>(null);
  const [isRootDragOver, setIsRootDragOver] = useState(false);

  const nodeMap = useMemo(() => {
    const map = new Map<string | null, FileNode[]>();
    props.nodes.forEach(node => {
      const parentId = node.parentId;
      if (!map.has(parentId)) map.set(parentId, []);
      map.get(parentId)!.push(node);
    });
    map.forEach(list => list.sort((a, b) => a.type === b.type ? a.name.localeCompare(b.name) : (a.type === NodeType.FOLDER ? -1 : 1)));
    return map;
  }, [props.nodes]);

  const rootNodes = nodeMap.get(null) || [];

  const handleContextMenu = (e: React.MouseEvent, node: FileNode) => {
      e.preventDefault();
      e.stopPropagation();
      setContextMenu({ x: e.clientX, y: e.clientY, node });
  };

  return (
    <div 
      style={{ height: '100%', display: 'flex', flexDirection: 'column', position: 'relative' }}
      onDragOver={(e) => { e.preventDefault(); setIsRootDragOver(true); }}
      onDragLeave={() => setIsRootDragOver(false)}
      onDrop={(e) => {
          e.preventDefault();
          setIsRootDragOver(false);
          const id = e.dataTransfer.getData('nodeId');
          if (id) props.onMoveNode(id, null);
      }}
      onClick={() => setEditingId(null)}
    >
      {contextMenu && (
          <div style={{ position: 'fixed', inset: 0, zIndex: 50 }} onClick={() => setContextMenu(null)}>
              <div className="context-menu" style={{ top: contextMenu.y, left: contextMenu.x }}>
                  <button onClick={() => { setEditingId(contextMenu.node.id); setContextMenu(null); }} className="context-item"><Edit2 size={14} /> Rename</button>
                  <button onClick={() => { props.onDeleteNode(contextMenu.node.id); setContextMenu(null); }} className="context-item" style={{ color: '#f87171' }}><Trash2 size={14} /> Delete</button>
              </div>
          </div>
      )}

      <div className="sidebar-header">
        <h2 className="sidebar-title"><FolderOpen size={18} /> EXPLORER</h2>
        <div className="flex gap-1">
          <button onClick={() => props.onAddFile(null)} className="btn-icon"><Plus size={16} /></button>
          <button onClick={() => props.onAddFolder(null)} className="btn-icon"><FolderPlus size={16} /></button>
        </div>
      </div>

      <div className="sidebar-content">
        {rootNodes.map(node => (
          <NodeItem 
            key={node.id} 
            node={node} 
            level={0} 
            nodeMap={nodeMap}
            editingId={editingId}
            onEditStart={setEditingId}
            onEditCancel={() => setEditingId(null)}
            onContextMenu={handleContextMenu}
            activeFileId={props.activeFileId}
            expandedFolders={props.expandedFolders}
            onFileSelect={props.onFileSelect}
            onToggleFolder={props.onToggleFolder}
            onAddFile={props.onAddFile}
            onAddFolder={props.onAddFolder}
            onDeleteNode={props.onDeleteNode}
            onRenameNode={props.onRenameNode}
            onMoveNode={props.onMoveNode}
          />
        ))}
      </div>
    </div>
  );
};

import React, { useState, useEffect, useCallback, useMemo } from 'react';
import { v4 as uuidv4 } from 'uuid';
import { 
  Download, Upload, Palette, PanelLeft, Edit3, Columns, Eye, X, FileText, Plus, FileDown
} from 'lucide-react';
import { Sidebar } from './components/Sidebar';
import { Editor } from './components/Editor';
import { FileNode, NodeType, AppTheme, ImportData } from './types';
import { initialNodes } from './initialData';

const themes: Record<string, AppTheme> = {
  dark: { name: 'Dark', bgMain: '#030712', bgSidebar: '#111827', textMain: '#f3f4f6', textMuted: '#9ca3af', border: '#1f2937', accent: '#3b82f6', hover: 'rgba(255, 255, 255, 0.05)' },
  light: { name: 'Light', bgMain: '#ffffff', bgSidebar: '#f3f4f6', textMain: '#111827', textMuted: '#6b7280', border: '#e5e7eb', accent: '#3b82f6', hover: 'rgba(0, 0, 0, 0.05)' },
