const themes: Record<string, AppTheme> = {
  dark: { name: 'Dark', bgMain: '#030712', bgSidebar: '#111827', textMain: '#f3f4f6', textMuted: '#9ca3af', border: '#1f2937', accent: '#3b82f6', hover: 'rgba(255, 255, 255, 0.05)' },
  light: { name: 'Light', bgMain: '#ffffff', bgSidebar: '#f3f4f6', textMain: '#111827', textMuted: '#6b7280', border: '#e5e7eb', accent: '#3b82f6', hover: 'rgba(0, 0, 0, 0.05)' },
  navy: { name: 'Navy', bgMain: '#0a192f', bgSidebar: '#112240', textMain: '#ccd6f6', textMuted: '#8892b0', border: '#233554', accent: '#64ffda', hover: 'rgba(100, 255, 218, 0.1)' },
  dracula: { name: 'Dracula', bgMain: '#282a36', bgSidebar: '#21222c', textMain: '#f8f8f2', textMuted: '#6272a4', border: '#44475a', accent: '#ff79c6', hover: 'rgba(255, 255, 255, 0.1)' }
};

export default function App() {
  const [nodes, setNodes] = useState<FileNode[]>(() => {
    const saved = localStorage.getItem('mathsci-fs');
    const baseNodes = saved ? JSON.parse(saved) : initialNodes;
    return baseNodes.map((n: FileNode) => ({...n, name: n.name.replace(/\.md$/, '')}));
  });

  const [activeFileId, setActiveFileId] = useState<string | null>('file-intro');
  const [expandedFolders, setExpandedFolders] = useState<Set<string>>(new Set(['folder-welcome', 'folder-docs']));
  const [showSettings, setShowSettings] = useState(false);
  const [isSidebarOpen, setIsSidebarOpen] = useState(true);
  const [editorView, setEditorView] = useState<'split' | 'editor' | 'preview'>('split');
  const [currentTheme, setCurrentTheme] = useState<AppTheme>(() => {
    const saved = localStorage.getItem('mathsci-theme');
    return saved ? JSON.parse(saved) : themes.dark;
  });

  useEffect(() => {
    const root = document.documentElement;
    // Map theme properties to CSS Variables defined in index.html
    root.style.setProperty('--bg-main', currentTheme.bgMain);
    root.style.setProperty('--bg-sidebar', currentTheme.bgSidebar);
    root.style.setProperty('--bg-toolbar', currentTheme.bgSidebar);
    root.style.setProperty('--text-main', currentTheme.textMain);
    root.style.setProperty('--text-muted', currentTheme.textMuted);
    root.style.setProperty('--border-color', currentTheme.border);
    root.style.setProperty('--accent-color', currentTheme.accent);
    root.style.setProperty('--hover-bg', currentTheme.hover);
    localStorage.setItem('mathsci-theme', JSON.stringify(currentTheme));
  }, [currentTheme]);

  useEffect(() => {
    localStorage.setItem('mathsci-fs', JSON.stringify(nodes));
  }, [nodes]);

  const handleUpdateContent = useCallback((content: string) => {
    if (!activeFileId) return;
    setNodes(prev => prev.map(n => n.id === activeFileId ? { ...n, content } : n));
  }, [activeFileId]);

  const handleDeleteNode = useCallback((id: string) => {
    setNodes(prev => {
      const node = prev.find(n => n.id === id);
      if (!node) return prev;
      if (!window.confirm(`Are you sure you want to delete "${node.name}"?`)) return prev;

      const idsToDelete = new Set<string>();
      const collect = (parentId: string) => {
        idsToDelete.add(parentId);
        prev.filter(n => n.parentId === parentId).forEach(c => collect(c.id));
      };
      collect(id);
      if (activeFileId && idsToDelete.has(activeFileId)) setActiveFileId(null);
      return prev.filter(n => !idsToDelete.has(n.id));
    });
  }, [activeFileId]);

  const activeFile = useMemo(() => nodes.find(n => n.id === activeFileId), [nodes, activeFileId]);

  const updateCustomColor = (key: keyof AppTheme, val: string) => {
    setCurrentTheme(prev => ({ ...prev, [key]: val, name: 'Custom' }));
  };

  return (
    <div className="app-container" style={{ backgroundColor: 'var(--bg-main)' }}>
      <div className="sidebar-wrapper" style={{ width: isSidebarOpen ? '280px' : '0' }}>
         <Sidebar 
            nodes={nodes}
            activeFileId={activeFileId}
            expandedFolders={expandedFolders}
            onFileSelect={setActiveFileId}
            onToggleFolder={(id) => setExpandedFolders(prev => {
                const next = new Set(prev);
                if (next.has(id)) next.delete(id); else next.add(id);
                return next;
            })}
            onAddFile={(parentId) => {
                const id = uuidv4();
                setNodes(prev => [...prev, { id, parentId, name: 'Untitled', type: NodeType.FILE, content: '', createdAt: Date.now() }]);
                setActiveFileId(id);
            }}
            onAddFolder={(parentId) => {
                const id = uuidv4();
                setNodes(prev => [...prev, { id, parentId, name: 'New Folder', type: NodeType.FOLDER, content: '', createdAt: Date.now() }]);
            }}
            onDeleteNode={handleDeleteNode}
            onRenameNode={(id, name) => setNodes(prev => prev.map(n => n.id === id ? { ...n, name } : n))}
            onMoveNode={(id, parentId) => setNodes(prev => prev.map(n => n.id === id ? { ...n, parentId } : n))}
         />
      </div>

      <div className="main-content" style={{ flex: 1, display: 'flex', flexDirection: 'column', overflow: 'hidden' }}>
        <div className="toolbar">
            <div style={{ display: 'flex', alignItems: 'center', gap: '0.75rem' }}>
                <button onClick={() => setIsSidebarOpen(!isSidebarOpen)} className="btn-icon"><PanelLeft size={18} /></button>
                <h1 className="app-title">MathSci</h1>
            </div>
            <div style={{ display: 'flex', alignItems: 'center', gap: '0.5rem' }}>
                <button onClick={() => setShowSettings(true)} className="btn"><Palette size={14} /> Theme</button>
                <div style={{ display: 'flex', background: 'rgba(0,0,0,0.2)', border: '1px solid var(--border-color)', borderRadius: '6px', padding: '2px' }}>
                   <button onClick={() => setEditorView('editor')} className="btn-icon" style={{ color: editorView === 'editor' ? 'var(--accent-color)' : 'var(--text-muted)' }}><Edit3 size={16} /></button>
                   <button onClick={() => setEditorView('split')} className="btn-icon" style={{ color: editorView === 'split' ? 'var(--accent-color)' : 'var(--text-muted)' }}><Columns size={16} /></button>
                   <button onClick={() => setEditorView('preview')} className="btn-icon" style={{ color: editorView === 'preview' ? 'var(--accent-color)' : 'var(--text-muted)' }}><Eye size={16} /></button>
                </div>
            </div>
        </div>

        <div style={{ flex: 1, overflow: 'hidden' }}>
            {activeFile ? (
                <Editor 
                  key={activeFileId}
                  content={activeFile.content} 
                  fileName={activeFile.name}
                  allNodes={nodes}
                  viewMode={editorView}
                  onChange={handleUpdateContent} 
                />
            ) : (
              <div style={{ height: '100%', display: 'flex', alignItems: 'center', justifyContent: 'center', color: 'var(--text-muted)' }}>
                  <div style={{ textAlign: 'center' }}>
                    <FileText size={48} style={{ opacity: 0.2, marginBottom: '1rem' }} />
                    <p>Select or create a file to start editing</p>
                  </div>
              </div>
            )}
        </div>
      </div>

      {showSettings && (
          <div className="modal-overlay" onClick={() => setShowSettings(false)}>
              <div className="modal" onClick={e => e.stopPropagation()} style={{ background: '#0a0f1d', padding: '1.5rem', borderRadius: '16px', border: '1px solid #1f2937', color: '#fff', width: '420px' }}>
                  <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: '1.5rem' }}>
                    <div style={{ display: 'flex', alignItems: 'center', gap: '0.75rem' }}>
                      <Palette size={20} color="#3b82f6" />
                      <h3 style={{ margin: 0, fontSize: '1.1rem', fontWeight: 600 }}>Theme Settings</h3>
                    </div>
                    <button onClick={() => setShowSettings(false)} className="btn-icon" style={{ color: '#9ca3af' }}><X size={20}/></button>
                  </div>

                  <div style={{ marginBottom: '1.5rem' }}>
                    <p style={{ fontSize: '0.75rem', color: '#9ca3af', textTransform: 'uppercase', letterSpacing: '0.05em', marginBottom: '0.75rem' }}>Presets</p>
                    <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: '0.75rem' }}>
                      {Object.entries(themes).map(([k, t]) => (
                        <button 
                          key={k} 
                          onClick={() => setCurrentTheme(t)} 
                          style={{ 
                            padding: '0.75rem',
                            borderRadius: '8px',
                            border: currentTheme.name === t.name ? '1px solid #3b82f6' : '1px solid #1f2937',
                            background: t.bgSidebar,
                            color: t.textMain,
                            display: 'flex',
                            alignItems: 'center',
                            gap: '0.75rem',
                            cursor: 'pointer',
                            fontSize: '0.875rem'
                          }}
                        >
                          <div style={{ width: '10px', height: '10px', borderRadius: '50%', background: t.accent }} />
                          {t.name}
                        </button>
                      ))}
                    </div>
                  </div>

                  <div style={{ marginBottom: '1.5rem' }}>
                    <p style={{ fontSize: '0.75rem', color: '#9ca3af', textTransform: 'uppercase', letterSpacing: '0.05em', marginBottom: '1rem' }}>Custom Colors</p>
                    <div style={{ display: 'flex', flexDirection: 'column', gap: '1rem' }}>
                      {[
                        { label: 'Main Background', key: 'bgMain', color: currentTheme.bgMain },
                        { label: 'Sidebar Background', key: 'bgSidebar', color: currentTheme.bgSidebar },
                        { label: 'Text Color', key: 'textMain', color: currentTheme.textMain },
                        { label: 'Accent Color', key: 'accent', color: currentTheme.accent }
                      ].map((item) => (
                        <div key={item.key} style={{ display: 'flex', alignItems: 'center', justifyContent: 'space-between' }}>
                          <span style={{ fontSize: '0.9rem', fontWeight: 500 }}>{item.label}</span>
                          <div style={{ display: 'flex', alignItems: 'center', gap: '0.75rem' }}>
                            <span style={{ fontSize: '0.75rem', color: '#6b7280', fontFamily: 'monospace' }}>{item.color.toUpperCase()}</span>
                            <div style={{ position: 'relative', width: '32px', height: '20px' }}>
                              <div style={{ position: 'absolute', inset: 0, borderRadius: '4px', background: item.color, border: '1px solid #374151' }} />
                              <input 
                                type="color" 
                                value={item.color} 
                                onChange={(e) => updateCustomColor(item.key as keyof AppTheme, e.target.value)}
                                style={{ position: 'absolute', inset: 0, opacity: 0, cursor: 'pointer', width: '100%', height: '100%' }}
                              />
                            </div>
                          </div>
                        </div>
                      ))}
                    </div>
                  </div>

                  <button 
                    onClick={() => setShowSettings(false)} 
                    className="btn-primary" 
                    style={{ 
                      width: '100%', 
                      padding: '0.85rem', 
                      borderRadius: '10px', 
                      fontSize: '0.9rem', 
                      fontWeight: 600,
                      marginTop: '0.5rem'
                    }}
                  >
                    Done
                  </button>
              </div>
          </div>
      )}
    </div>
  );
}

import React, { useMemo, useState, useRef, useEffect } from 'react';
import { 
  Folder, FolderOpen, FileText, ChevronRight, ChevronDown, 
  Plus, FolderPlus, Trash2, Edit2
} from 'lucide-react';
import { FileNode, NodeType } from '../types';

interface SidebarProps {
  nodes: FileNode[];
  activeFileId: string | null;
  expandedFolders: Set<string>;
  onFileSelect: (id: string) => void;
  onToggleFolder: (id: string) => void;
  onAddFile: (parentId: string | null) => void;
  onAddFolder: (parentId: string | null) => void;
  onDeleteNode: (id: string) => void;
  onRenameNode: (id: string, newName: string) => void;
  onMoveNode: (nodeId: string, newParentId: string | null) => void;
}

const NodeItem: React.FC<{
  node: FileNode;
  level: number;
  nodeMap: Map<string | null, FileNode[]>;
  editingId: string | null;
  onEditStart: (id: string) => void;
  onEditCancel: () => void;
  props: SidebarProps;
}> = ({ node, level, nodeMap, editingId, onEditStart, onEditCancel, props }) => {
  const [isDragOver, setIsDragOver] = useState(false);
  const isEditing = editingId === node.id;
  const [editName, setEditName] = useState(node.name);
  const inputRef = useRef<HTMLInputElement>(null);

  const isFolder = node.type === NodeType.FOLDER;
  const isExpanded = props.expandedFolders.has(node.id);
  const isActive = node.id === props.activeFileId;
  const children = nodeMap.get(node.id) || [];

  useEffect(() => {
    if (isEditing && inputRef.current) {
      inputRef.current.focus();
      inputRef.current.select();
    }
  }, [isEditing]);

  const handleDragStart = (e: React.DragEvent) => {
    e.dataTransfer.setData('nodeId', node.id);
    e.dataTransfer.effectAllowed = 'move';
  };

  const handleDragOver = (e: React.DragEvent) => {
    e.preventDefault();
    if (isFolder && e.dataTransfer.types.includes('nodeId')) {
      setIsDragOver(true);
    }
  };

  const handleDrop = (e: React.DragEvent) => {
    e.preventDefault();
    setIsDragOver(false);
    const draggedId = e.dataTransfer.getData('nodeId');
    if (draggedId && draggedId !== node.id) {
      props.onMoveNode(draggedId, isFolder ? node.id : node.parentId);
    }
  };

  const handleRename = (e: React.FormEvent) => {
    e.preventDefault();
    if (editName.trim()) props.onRenameNode(node.id, editName.trim());
    onEditCancel();
  };

  return (
    <div 
      onDragOver={handleDragOver}
      onDragLeave={() => setIsDragOver(false)}
      onDrop={handleDrop}
      style={{ 
        outline: isDragOver ? '2px solid var(--accent-color)' : 'none',
        backgroundColor: isDragOver ? 'var(--hover-bg)' : 'transparent'
      }}
    >
      <div 
        draggable
        onDragStart={handleDragStart}
        className={`sidebar-item ${isActive ? 'active' : ''}`}
        style={{ paddingLeft: `${level * 12 + 8}px` }}
        onClick={() => isFolder ? props.onToggleFolder(node.id) : props.onFileSelect(node.id)}
      >
        <span style={{ marginRight: '4px', opacity: 0.7, display: 'flex' }}>
          {isFolder && (isExpanded ? <ChevronDown size={14} /> : <ChevronRight size={14} />)}
          {!isFolder && <span style={{ width: '14px' }} />}
        </span>

        <span style={{ marginRight: '8px', color: isActive ? '#fff' : (isFolder ? '#eab308' : 'var(--accent-color)') }}>
          {isFolder ? (isExpanded ? <FolderOpen size={16} /> : <Folder size={16} />) : <FileText size={16} />}
        </span>

        {isEditing ? (
          <form onSubmit={handleRename} style={{ flex: 1 }}>
            <input
              ref={inputRef}
              type="text"
              value={editName}
              onChange={(e) => setEditName(e.target.value)}
              onBlur={handleRename}
              className="textarea"
              style={{ padding: '0 4px', height: '1.25rem', fontSize: '0.75rem', width: '100%', background: 'var(--bg-main)' }}
            />
          </form>
        ) : (
          <span style={{ flex: 1, whiteSpace: 'nowrap', overflow: 'hidden', textOverflow: 'ellipsis' }}>{node.name}</span>
        )}

        {!isEditing && (
          <div className="sidebar-actions">
             <button onClick={(e) => { e.stopPropagation(); onEditStart(node.id); }} className="btn-icon"><Edit2 size={12} /></button>
             {isFolder && <button onClick={(e) => { e.stopPropagation(); props.onAddFile(node.id); }} className="btn-icon"><Plus size={12} /></button>}
             <button onClick={(e) => { e.stopPropagation(); props.onDeleteNode(node.id); }} className="btn-icon" style={{ color: '#f87171' }}><Trash2 size={12} /></button>
          </div>
        )}
      </div>

      {isFolder && isExpanded && (
        <div>
          {children.map(child => (
            <NodeItem 
              key={child.id} 
              node={child} 
              level={level + 1} 
              nodeMap={nodeMap} 
              editingId={editingId} 
              onEditStart={onEditStart} 
              onEditCancel={onEditCancel} 
              props={props} 
            />
          ))}
        </div>
      )}
    </div>
  );
};

export const Sidebar: React.FC<SidebarProps> = (props) => {
  const [editingId, setEditingId] = useState<string | null>(null);
  const [isRootOver, setIsRootOver] = useState(false);

  const nodeMap = useMemo(() => {
    const map = new Map<string | null, FileNode[]>();
    props.nodes.forEach(node => {
      const parentId = node.parentId;
      if (!map.has(parentId)) map.set(parentId, []);
      map.get(parentId)!.push(node);
    });
    // Strict Ascending Sort: Folders First (A-Z), then Files (A-Z)
    map.forEach(list => list.sort((a, b) => {
      if (a.type !== b.type) return a.type === NodeType.FOLDER ? -1 : 1;
      return a.name.toLowerCase().localeCompare(b.name.toLowerCase());
    }));
    return map;
  }, [props.nodes]);

  const rootNodes = nodeMap.get(null) || [];

  return (
    <div style={{ height: '100%', display: 'flex', flexDirection: 'column' }}>
      <div className="sidebar-header">
        <h2 className="sidebar-title"><FolderOpen size={18} /> EXPLORER</h2>
        <div className="flex gap-1">
          <button onClick={() => props.onAddFile(null)} title="New File at Root"><Plus size={16} /></button>
          <button onClick={() => props.onAddFolder(null)} title="New Folder at Root"><FolderPlus size={16} /></button>
        </div>
      </div>

      <div 
        className="sidebar-content"
        onDragOver={(e) => { e.preventDefault(); setIsRootOver(true); }}
        onDragLeave={() => setIsRootOver(false)}
        onDrop={(e) => {
          e.preventDefault();
          setIsRootOver(false);
          const id = e.dataTransfer.getData('nodeId');
          if (id) props.onMoveNode(id, null);
        }}
        style={{ backgroundColor: isRootOver ? 'var(--hover-bg)' : 'transparent' }}
      >
        {rootNodes.map(node => (
          <NodeItem 
            key={node.id} 
            node={node} 
            level={0} 
            nodeMap={nodeMap} 
            editingId={editingId} 
            onEditStart={setEditingId} 
            onEditCancel={() => setEditingId(null)} 
            props={props} 
          />
        ))}
      </div>
    </div>
  );
};

import React, { useState, useEffect, useCallback, useMemo } from 'react';
import { v4 as uuidv4 } from 'uuid';
import { 
  Download, Upload, Palette, PanelLeft, Edit3, Columns, Eye, X, FileText, Plus, FileDown
} from 'lucide-react';
import { Sidebar } from './components/Sidebar';
import { Editor } from './components/Editor';
import { FileNode, NodeType, AppTheme, ImportData } from './types';
import { initialNodes } from './initialData';

const themes: Record<string, AppTheme> = {
  dark: { name: 'Dark', bgMain: '#030712', bgSidebar: '#111827', textMain: '#f3f4f6', textMuted: '#9ca3af', border: '#1f2937', accent: '#3b82f6', hover: 'rgba(255, 255, 255, 0.05)' },
  light: { name: 'Light', bgMain: '#ffffff', bgSidebar: '#f3f4f6', textMain: '#111827', textMuted: '#6b7280', border: '#e5e7eb', accent: '#3b82f6', hover: 'rgba(0, 0, 0, 0.05)' },
  navy: { name: 'Navy', bgMain: '#0a192f', bgSidebar: '#112240', textMain: '#ccd6f6', textMuted: '#8892b0', border: '#233554', accent: '#64ffda', hover: 'rgba(100, 255, 218, 0.1)' },
  dracula: { name: 'Dracula', bgMain: '#282a36', bgSidebar: '#21222c', textMain: '#f8f8f2', textMuted: '#6272a4', border: '#44475a', accent: '#ff79c6', hover: 'rgba(255, 255, 255, 0.1)' }
};

export default function App() {
  const [nodes, setNodes] = useState<FileNode[]>(() => {
    const saved = localStorage.getItem('mathsci-fs');
    const baseNodes = saved ? JSON.parse(saved) : initialNodes;
    return baseNodes;
  });

  const [activeFileId, setActiveFileId] = useState<string | null>('file-intro');
  const [expandedFolders, setExpandedFolders] = useState<Set<string>>(new Set(['folder-welcome', 'folder-docs']));
  const [showSettings, setShowSettings] = useState(false);
  const [isSidebarOpen, setIsSidebarOpen] = useState(true);
  const [editorView, setEditorView] = useState<'split' | 'editor' | 'preview'>('split');
  const [currentTheme, setCurrentTheme] = useState<AppTheme>(() => {
    const saved = localStorage.getItem('mathsci-theme');
    return saved ? JSON.parse(saved) : themes.dark;
  });

  useEffect(() => {
    const root = document.documentElement;
    root.style.setProperty('--bg-main', currentTheme.bgMain);
    root.style.setProperty('--bg-sidebar', currentTheme.bgSidebar);
    root.style.setProperty('--bg-toolbar', currentTheme.bgSidebar);
    root.style.setProperty('--text-main', currentTheme.textMain);
    root.style.setProperty('--text-muted', currentTheme.textMuted);
    root.style.setProperty('--border-color', currentTheme.border);
    root.style.setProperty('--accent-color', currentTheme.accent);
    root.style.setProperty('--hover-bg', currentTheme.hover);
    localStorage.setItem('mathsci-theme', JSON.stringify(currentTheme));
  }, [currentTheme]);

  useEffect(() => {
    localStorage.setItem('mathsci-fs', JSON.stringify(nodes));
  }, [nodes]);

  const handleUpdateContent = useCallback((content: string) => {
    if (!activeFileId) return;
    setNodes(prev => prev.map(n => n.id === activeFileId ? { ...n, content } : n));
  }, [activeFileId]);

  const handleDeleteNode = useCallback((id: string) => {
    setNodes(prev => {
      const node = prev.find(n => n.id === id);
      if (!node) return prev;
      if (!window.confirm(`Delete "${node.name}" and all its contents?`)) return prev;

      const idsToDelete = new Set<string>();
      const collect = (parentId: string) => {
        idsToDelete.add(parentId);
        prev.filter(n => n.parentId === parentId).forEach(c => collect(c.id));
      };
      collect(id);
      if (activeFileId && idsToDelete.has(activeFileId)) setActiveFileId(null);
      return prev.filter(n => !idsToDelete.has(n.id));
    });
  }, [activeFileId]);

  const activeFile = useMemo(() => nodes.find(n => n.id === activeFileId), [nodes, activeFileId]);

  const updateCustomColor = (key: keyof AppTheme, val: string) => {
    setCurrentTheme(prev => ({ ...prev, [key]: val, name: 'Custom' }));
  };

  return (
    <div className="app-container" style={{ backgroundColor: 'var(--bg-main)' }}>
      <div className="sidebar-wrapper" style={{ width: isSidebarOpen ? '280px' : '0' }}>
         <Sidebar 
            nodes={nodes}
            activeFileId={activeFileId}
            expandedFolders={expandedFolders}
            onFileSelect={setActiveFileId}
            onToggleFolder={(id) => setExpandedFolders(prev => {
                const next = new Set(prev);
                if (next.has(id)) next.delete(id); else next.add(id);
                return next;
            })}
            onAddFile={(parentId) => {
                const id = uuidv4();
                setNodes(prev => [...prev, { id, parentId, name: 'Untitled', type: NodeType.FILE, content: '', createdAt: Date.now() }]);
                setActiveFileId(id);
                if (parentId) setExpandedFolders(prev => new Set(prev).add(parentId));
            }}
            onAddFolder={(parentId) => {
                const id = uuidv4();
                setNodes(prev => [...prev, { id, parentId, name: 'New Folder', type: NodeType.FOLDER, content: '', createdAt: Date.now() }]);
                if (parentId) setExpandedFolders(prev => new Set(prev).add(parentId));
            }}
            onDeleteNode={handleDeleteNode}
            onRenameNode={(id, name) => setNodes(prev => prev.map(n => n.id === id ? { ...n, name } : n))}
            onMoveNode={(id, parentId) => setNodes(prev => prev.map(n => n.id === id ? { ...n, parentId } : n))}
